{
  "name": "KIVIA - Collaborative Peer Study",
  "description": "An integrated study platform combining real-time chat, video learning, and AI-powered smart notebooks grounded in group discussions.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Could not find root element");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type UserStatus = 'online' | 'busy' | 'studying' | 'offline';

export interface User {
  id: string;
  name: string;
  avatar: string;
  status: UserStatus;
  currentFocus?: string;
}

export interface Message {
  id: string;
  senderId: string;
  text: string;
  timestamp: Date;
  type: 'text' | 'voice' | 'file' | 'ai';
  metadata?: any;
}

export interface Group {
  id: string;
  name: string;
  members: User[];
  lastMessage?: string;
}

export interface NoteSource {
  type: 'chat' | 'video' | 'document';
  id: string;
  title: string;
  timestamp?: number;
}

export interface SmartNote {
  id: string;
  title: string;
  content: string;
  source: NoteSource;
  tags: string[];
}

export interface VideoSession {
  id: string;
  title: string;
  thumbnail: string;
  duration: string;
  recordedAt: Date;
  url: string;
}

export enum AppTab {
  CHAT = 'chat',
  VIDEO = 'video',
  NOTEBOOK = 'notebook',
  SARA = 'sara'
}

import { GoogleGenAI, Type } from "@google/genai";

const API_KEY = process.env.API_KEY || "";

export const getSaraResponse = async (prompt: string, context: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Context from group study session: ${context}\n\nUser query: ${prompt}`,
      config: {
        systemInstruction: "You are SARA, an encouraging and expert AI Study Assistant for KIVIA. Your goal is to help students learn together. Summarize discussions, explain concepts simply, generate quizzes, and highlight key takeaways. Always refer back to the group's specific discussions or shared materials.",
        temperature: 0.7,
      },
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I'm having a little trouble connecting to my knowledge base right now. Let's try focusing on the last thing we discussed!";
  }
};

export const generateSmartNotes = async (conversation: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze this conversation and generate structured smart notes: ${conversation}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              content: { type: Type.STRING },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } },
              sourceId: { type: Type.STRING }
            },
            required: ["title", "content", "tags"]
          }
        }
      }
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Smart Note Generation Error:", error);
    return [];
  }
};

import React, { useState, useEffect, useRef } from 'react';
