export default Sidebar;

import React, { useState, useRef, useEffect } from 'react';
import { Group, Message } from '../types';

interface ChatViewProps {
  group: Group;
  messages: Message[];
  onSendMessage: (text: string) => void;
}

const ChatView: React.FC<ChatViewProps> = ({ group, messages, onSendMessage }) => {
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    onSendMessage(inputText);
    setInputText('');
  };

  return (
    <div className="flex flex-col h-full">
      {/* Chat Messages */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-6 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] bg-opacity-5"
      >
        {messages.map((msg, idx) => {
          const sender = group.members.find(m => m.id === msg.senderId) || { name: 'You', avatar: 'https://picsum.photos/seed/me/100' };
          const isMe = msg.senderId === 'currentUser';
          const isAI = msg.type === 'ai';

          return (
            <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
              <div className={`flex max-w-[80%] gap-3 ${isMe ? 'flex-row-reverse' : 'flex-row'}`}>
                {!isMe && (
                  <img src={sender.avatar} className="w-8 h-8 rounded-full border border-gray-200 mt-1" alt={sender.name} />
                )}
                <div>
                  {!isMe && <div className="text-[11px] font-bold text-gray-500 mb-1 ml-1">{sender.name}</div>}
                  <div className={`
                    p-3 rounded-2xl shadow-sm text-sm relative
                    ${isMe ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-gray-800 rounded-tl-none'}
                    ${isAI ? 'border-2 border-indigo-200 bg-indigo-50/50' : ''}
                  `}>
                    {isAI && (
                      <div className="flex items-center gap-1.5 text-xs font-bold text-indigo-600 mb-1 uppercase tracking-tighter">
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                        SARA Analysis
                      </div>
                    )}
                    {msg.text}
                    <div className={`text-[10px] mt-1 text-right ${isMe ? 'text-indigo-100' : 'text-gray-400'}`}>
                      {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Input Area */}
      <form onSubmit={handleSubmit} className="p-4 bg-white border-t border-gray-100 flex items-center gap-4">
        <button type="button" className="text-gray-400 hover:text-indigo-600">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
        </button>
        <div className="flex-1 relative">
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Type a message or ask SARA..."
            className="w-full bg-gray-100 border-none rounded-2xl px-5 py-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none pr-12 transition-all"
          />
          <button type="button" className="absolute right-3 top-2.5 text-gray-400 hover:text-indigo-600">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
          </button>
        </div>
        <button 
          type="submit" 
          disabled={!inputText.trim()}
          className="bg-indigo-600 text-white p-3 rounded-full hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-indigo-100 transition-all"
        >
          <svg className="w-5 h-5 transform rotate-90" fill="currentColor" viewBox="0 0 20 20"><path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" /></svg>
        </button>
      </form>
    </div>
  );
};

export default ChatView;

import React, { useState } from 'react';
import { SmartNote } from '../types';

interface NotebookViewProps {
  notes: SmartNote[];
}

const NotebookView: React.FC<NotebookViewProps> = ({ notes }) => {
  const [filter, setFilter] = useState('');

  const filteredNotes = notes.filter(n => 
    n.title.toLowerCase().includes(filter.toLowerCase()) || 
    n.content.toLowerCase().includes(filter.toLowerCase()) ||
    n.tags.some(t => t.toLowerCase().includes(filter.toLowerCase()))
  );

  return (
    <div className="h-full flex flex-col bg-gray-50/50">
      <div className="p-6 border-b border-gray-100 bg-white flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Smart Notebook</h2>
          <p className="text-sm text-gray-500 mt-1">Grounded knowledge automatically compiled from your sessions.</p>
        </div>
        <div className="flex gap-2">
          <div className="relative">
            <input 
              type="text" 
              placeholder="Search notes..." 
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
              className="bg-gray-100 border-none rounded-xl px-4 py-2 text-sm w-64 focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
          <button className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">
            Generate Quiz
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6">
        <div className="columns-1 md:columns-2 lg:columns-3 gap-6 space-y-6">
          {filteredNotes.map(note => (
            <div key={note.id} className="break-inside-avoid p-5 bg-white border border-gray-100 rounded-2xl shadow-sm hover:shadow-md transition-shadow group">
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-bold text-gray-900 group-hover:text-indigo-600 transition-colors">{note.title}</h3>
                <span className="text-[10px] px-2 py-0.5 bg-gray-100 text-gray-500 rounded-full font-bold uppercase tracking-widest">
                  {note.source.type}
                </span>
              </div>
              <p className="text-sm text-gray-600 leading-relaxed mb-4">
                {note.content}
              </p>
              <div className="flex flex-wrap gap-2 mb-4">
                {note.tags.map(tag => (
                  <span key={tag} className="text-[10px] font-bold text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded">
                    #{tag}
                  </span>
                ))}
              </div>
              <div className="pt-4 border-t border-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-2 text-xs text-gray-400 italic">
                  <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.8a3.736 3.736 0 011.014-.006m-.337 4.173a3.91 3.91 0 01.337-4.173" /></svg>
                  Grounded: {note.source.title}
                </div>
                <button className="text-indigo-600 hover:bg-indigo-50 p-1.5 rounded-lg transition-colors">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" /></svg>
                </button>
              </div>
            </div>
          ))}
          {filteredNotes.length === 0 && (
            <div className="flex flex-col items-center justify-center py-20 text-center col-span-full">
              <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                <svg className="w-10 h-10 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
