export default NotebookView;

import React, { useState } from 'react';
import { Message, SmartNote } from '../types';
import { getSaraResponse } from '../services/gemini';

interface SARAPanelProps {
  onClose: () => void;
  messages: Message[];
  notes: SmartNote[];
}

const SARAPanel: React.FC<SARAPanelProps> = ({ onClose, messages, notes }) => {
  const [query, setQuery] = useState('');
  const [history, setHistory] = useState<{ role: 'user' | 'ai', text: string }[]>([
    { role: 'ai', text: "Hello! I'm SARA. I've been monitoring your session. How can I assist your group today?" }
  ]);
  const [loading, setLoading] = useState(false);

  const handleAsk = async () => {
    if (!query.trim() || loading) return;

    const userMsg = query;
    setQuery('');
    setHistory(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const context = `
      Group Messages: ${messages.map(m => m.text).join(' | ')}
      Key Notes: ${notes.map(n => n.content).join(' | ')}
    `;

    const response = await getSaraResponse(userMsg, context);
    setHistory(prev => [...prev, { role: 'ai', text: response || "I'm sorry, I couldn't process that. Try again?" }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-full overflow-hidden">
      <div className="p-4 border-b border-gray-100 flex items-center justify-between bg-white/50 glass">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-full flex items-center justify-center text-white font-bold text-xs">S</div>
          <div>
            <h3 className="text-sm font-bold text-gray-900">SARA Assistant</h3>
            <p className="text-[10px] text-green-500 font-bold uppercase">Ready to Help</p>
          </div>
        </div>
        <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded-lg">
          <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {history.map((h, i) => (
          <div key={i} className={`flex ${h.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`p-3 rounded-xl text-xs max-w-[90%] ${
              h.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-800'
            }`}>
              {h.text}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="p-3 bg-gray-100 rounded-xl flex gap-1">
              <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
              <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-gray-100 bg-white">
        <div className="flex flex-col gap-2">
          <p className="text-[10px] text-gray-400 font-bold px-1">SUGGESTIONS</p>
          <div className="flex flex-wrap gap-2">
            {["Summarize session", "Create 5 quiz Qs", "Next study topic?"].map(s => (
              <button 
                key={s} 
                onClick={() => setQuery(s)}
                className="text-[10px] bg-indigo-50 text-indigo-600 px-2 py-1 rounded-md font-bold hover:bg-indigo-100 transition-colors"
              >
                {s}
              </button>
            ))}
          </div>
        </div>
        <div className="mt-4 flex gap-2">
          <input 
            type="text" 
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleAsk()}
            placeholder="Ask SARA anything..."
            className="flex-1 bg-gray-100 border-none rounded-xl px-4 py-2 text-xs focus:ring-2 focus:ring-indigo-500 outline-none"
          />
          <button 
            onClick={handleAsk}
            className="bg-indigo-600 text-white p-2 rounded-xl hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100"
          >
            <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" /></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

