import React, { useState, useRef, useEffect } from 'react';
import { User, Group } from '../types';

interface VideoCallProps {
  onClose: () => void;
  currentUser: User;
  activeGroup: Group;
}

const VideoCall: React.FC<VideoCallProps> = ({ onClose, currentUser, activeGroup }) => {
  const [isMuted, setIsMuted] = useState(false);
  const [isVideoOff, setIsVideoOff] = useState(false);
  const [isScreenSharing, setIsScreenSharing] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const screenRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    startCamera();
    return () => {
      streamRef.current?.getTracks().forEach(track => track.stop());
    };
  }, []);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Error accessing camera:", err);
    }
  };

  const toggleScreenShare = async () => {
    if (isScreenSharing) {
      const tracks = screenRef.current?.srcObject as MediaStream;
      tracks?.getTracks().forEach(t => t.stop());
      setIsScreenSharing(false);
    } else {
      try {
        const stream = await navigator.mediaDevices.getDisplayMedia({ video: true });
        if (screenRef.current) {
          screenRef.current.srcObject = stream;
        }
        setIsScreenSharing(true);
        stream.getTracks()[0].onended = () => setIsScreenSharing(false);
      } catch (err) {
        console.error("Error screen sharing:", err);
      }
    }
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black/95 flex flex-col p-4 md:p-8 animate-in fade-in duration-300">
      <div className="flex items-center justify-between text-white mb-6">
        <div>
          <h2 className="text-xl font-black tracking-tight">{activeGroup.name} Call</h2>
          <p className="text-xs font-bold text-gray-500 uppercase tracking-widest mt-1">Live Study Session</p>
        </div>
        <div className="flex -space-x-3">
          {[1, 2, 3].map(i => (
            <div key={i} className="w-10 h-10 rounded-full border-2 border-black bg-gray-800 flex items-center justify-center overflow-hidden">
                <img src={`https://picsum.photos/seed/${i + 10}/100`} alt="Member" className="w-full h-full object-cover" />
            </div>
          ))}
          <div className="w-10 h-10 rounded-full border-2 border-black bg-indigo-600 flex items-center justify-center text-xs font-bold">+5</div>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4 min-h-0">
        <div className="relative bg-zinc-900 rounded-[2rem] overflow-hidden border border-white/5 shadow-2xl">
          <video ref={videoRef} autoPlay playsInline muted={isMuted} className={`w-full h-full object-cover ${isVideoOff ? 'hidden' : ''}`} />
          {isVideoOff && (
            <div className="absolute inset-0 flex items-center justify-center bg-zinc-800">
              <div className="w-24 h-24 rounded-full bg-indigo-600 flex items-center justify-center text-3xl font-bold text-white shadow-2xl">
                {currentUser.name[0]}
              </div>
            </div>
          )}
          <div className="absolute bottom-6 left-6 flex items-center gap-2 bg-black/40 backdrop-blur-md px-4 py-2 rounded-full border border-white/10">
            <span className="w-2 h-2 bg-green-500 rounded-full"></span>
            <span className="text-xs font-bold text-white">{currentUser.name} (You)</span>
          </div>
        </div>

        <div className={`relative bg-zinc-900 rounded-[2rem] overflow-hidden border border-white/5 shadow-2xl transition-all ${isScreenSharing ? 'scale-100 opacity-100' : 'scale-95 opacity-50'}`}>
          {isScreenSharing ? (
            <video ref={screenRef} autoPlay playsInline className="w-full h-full object-contain bg-black" />
          ) : (
            <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-500 gap-4">
              <svg className="w-16 h-16 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9.75 17L9 20l-1 1h8l-1-1-.75-3M3 13h18M5 17h14a2 2 0 002-2V5a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>
              <p className="text-sm font-bold tracking-widest uppercase">Screen Share Inactive</p>
            </div>
          )}
          {isScreenSharing && (
            <div className="absolute bottom-6 left-6 bg-red-600 px-4 py-2 rounded-full text-xs font-bold text-white flex items-center gap-2">
              <span className="w-2 h-2 bg-white rounded-full animate-pulse"></span>
              PRESENTING SCREEN
            </div>
          )}
        </div>
      </div>

      <div className="mt-8 flex items-center justify-center gap-4">
        <button 
          onClick={() => setIsMuted(!isMuted)}
          className={`p-4 rounded-2xl transition-all ${isMuted ? 'bg-red-500 text-white' : 'bg-white/10 text-white hover:bg-white/20'}`}
        >
          {isMuted ? (
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M18.364 18.364A9 9 0 005.636 5.636m12.728 12.728A9 9 0 015.636 5.636m12.728 12.728L5.636 5.636" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
          ) : (
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
