        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
        </button>
        <button 
          onClick={toggleScreenShare}
          className={`p-4 rounded-2xl transition-all ${isScreenSharing ? 'bg-indigo-600 text-white' : 'bg-white/10 text-white hover:bg-white/20'}`}
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.75 17L9 20l-1 1h8l-1-1-.75-3M3 13h18M5 17h14a2 2 0 002-2V5a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>
        </button>
        <button 
          onClick={onClose}
          className="p-4 bg-red-600 text-white rounded-[2rem] px-8 font-black uppercase tracking-widest hover:bg-red-700 transition-all shadow-2xl shadow-red-600/20"
        >
          End Call
        </button>
      </div>
    </div>
  );
};

