import React, { useState } from 'react';
import { Message, SmartNote, VideoSession } from '../types';
import { getSaraResponse, generateSmartNotes } from '../services/gemini';

interface SARAPanelProps {
  onClose: () => void;
  messages: Message[];
  notes: SmartNote[];
  videos: VideoSession[];
  onAiResponse: (msg: Message) => void;
  onNewNote: (note: SmartNote) => void;
}

const SARAPanel: React.FC<SARAPanelProps> = ({ onClose, messages, notes, videos, onAiResponse, onNewNote }) => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<{ role: 'user' | 'ai', text: string }[]>([
    { role: 'ai', text: "Ready to study! Ask me to 'Summarize', 'Create Notes', or 'Analyze Video'." }
  ]);

  const handleAsk = async (explicitQuery?: string) => {
    const q = explicitQuery || query;
    if (!q.trim() || loading) return;

    setHistory(prev => [...prev, { role: 'user', text: q }]);
    setQuery('');
    setLoading(true);

    const isVideoAnalysis = q.toLowerCase().includes('analyze video') || q.toLowerCase().includes('session note');

    if (isVideoAnalysis && videos.length > 0) {
      const latestVideo = videos[videos.length - 1];
      const analysisPrompt = `Analyze the content of the video session titled "${latestVideo.title}". Transcript snapshot: ${latestVideo.transcript}. Extract key learning moments and summarized notes.`;
      const response = await getSaraResponse(analysisPrompt, `Group has shared ${videos.length} videos.`);

      onNewNote({
        id: 'vid-note-' + Date.now(),
        title: `Deep Dive: ${latestVideo.title}`,
        content: response,
        tags: ['Video Analysis', 'Session Highlight'],
        source: { type: 'video', id: latestVideo.id, title: latestVideo.title },
        createdAt: new Date().toISOString(),
        groupId: ''
      });

      setHistory(prev => [...prev, { role: 'ai', text: `I've analyzed your latest session "${latestVideo.title}". A new smart note has been added to your notebook with the key takeaways!` }]);
    } else if (q.toLowerCase().includes('create notes') || q.toLowerCase().includes('generate notes')) {
      const chatStr = messages.map(m => `${m.senderName}: ${m.text}`).join('\n');
      const newNotes = await generateSmartNotes(chatStr);
      if (newNotes && newNotes.length > 0) {
        newNotes.forEach((n: any) => {
          onNewNote({
            id: Date.now().toString() + Math.random(),
            title: n.title,
            content: n.content,
            tags: n.tags,
            source: { type: 'chat', id: 'ai-gen', title: 'SARA AI scan' },
            createdAt: new Date().toISOString(),
            groupId: ''
          });
        });
        setHistory(prev => [...prev, { role: 'ai', text: `I've generated ${newNotes.length} new notes for your group notebook! Go check them out.` }]);
      } else {
        setHistory(prev => [...prev, { role: 'ai', text: "I couldn't find enough discussion to generate notes yet. Keep chatting!" }]);
      }
    } else {
      const context = `
        Discussion: ${messages.slice(-10).map(m => m.text).join(' | ')}
        Notes: ${notes.map(n => n.title).join(', ')}
        Videos: ${videos.map(v => v.title).join(', ')}
      `;
      const response = await getSaraResponse(q, context);
      setHistory(prev => [...prev, { role: 'ai', text: response }]);

      if (q.toLowerCase().includes('summarize')) {
        onAiResponse({
            id: 'sara-' + Date.now(),
            senderId: 'sara',
            senderName: 'SARA',
            text: response,
            timestamp: new Date().toISOString(),
            type: 'ai'
        });
      }
    }
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-full overflow-hidden bg-white">
      <div className="p-6 border-b border-gray-100 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-indigo-100">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
          </div>
          <div>
            <h3 className="text-sm font-black text-gray-900 tracking-tight">SARA AI</h3>
            <div className="flex items-center gap-1">
               <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
               <span className="text-[9px] font-black text-green-600 uppercase tracking-widest">Active Intelligence</span>
            </div>
          </div>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
          <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {history.map((h, i) => (
          <div key={i} className={`flex ${h.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`p-4 rounded-2xl text-xs leading-relaxed max-w-[90%] shadow-sm ${
              h.role === 'user' ? 'bg-indigo-600 text-white font-medium' : 'bg-gray-100 text-gray-800 font-bold'
            }`}>
              {h.text}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="p-4 bg-gray-100 rounded-2xl flex gap-1.5">
              <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 border-t border-gray-100 bg-gray-50/30">
        <div className="flex flex-col gap-3">
          <p className="text-[9px] text-gray-400 font-black uppercase tracking-widest px-1">Capabilities</p>
          <div className="flex flex-wrap gap-2">
            {[
              { label: "Summarize Chat", q: "Summarize the latest discussion" },
              { label: "Analyze Video", q: "Analyze the latest video session" },
              { label: "Create Notes", q: "Generate notes from chat" }
            ].map(s => (
              <button 
                key={s.label} 
                onClick={() => handleAsk(s.q)}
                className="text-[10px] bg-white border border-indigo-100 text-indigo-600 px-3 py-1.5 rounded-xl font-bold hover:bg-indigo-600 hover:text-white transition-all shadow-sm"
              >
                {s.label}
              </button>
            ))}
          </div>
        </div>
        <div className="mt-6 flex gap-2">
          <input 
            type="text" 
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleAsk()}
            placeholder="Ask anything..."
            className="flex-1 bg-white border border-gray-100 rounded-2xl px-5 py-3 text-xs font-medium focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm transition-all"
          />
          <button 
            onClick={() => handleAsk()}
            disabled={!query.trim() || loading}
            className="bg-indigo-600 text-white p-3 rounded-2xl hover:bg-indigo-700 disabled:opacity-50 transition-all shadow-lg shadow-indigo-100 active:scale-95"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default SARAPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Group, Message, AppTab, SmartNote, VideoSession } from './types';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VideoView from './components/VideoView';
import NotebookView from './components/NotebookView';
import SARAPanel from './components/SARAPanel';
import Auth from './components/Auth';
import VideoCall from './components/VideoCall';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.CHAT);
  const [groups, setGroups] = useState<Group[]>([]);
  const [activeGroupId, setActiveGroupId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [notes, setNotes] = useState<SmartNote[]>([]);
  const [videos, setVideos] = useState<VideoSession[]>([]);
  const [isSARAOpen, setIsSARAOpen] = useState(false);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCalling, setIsCalling] = useState(false);

  // Load Initial Data
  useEffect(() => {
    const savedUser = localStorage.getItem('kivia_current_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));

    setGroups(JSON.parse(localStorage.getItem('kivia_groups') || '[]'));
    setMessages(JSON.parse(localStorage.getItem('kivia_messages') || '[]'));
    setNotes(JSON.parse(localStorage.getItem('kivia_notes') || '[]'));
    setVideos(JSON.parse(localStorage.getItem('kivia_videos') || '[]'));
    setAllUsers(JSON.parse(localStorage.getItem('kivia_users') || '[]'));
  }, []);

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('kivia_groups', JSON.stringify(groups));
    localStorage.setItem('kivia_messages', JSON.stringify(messages));
    localStorage.setItem('kivia_notes', JSON.stringify(notes));
    localStorage.setItem('kivia_videos', JSON.stringify(videos));
  }, [groups, messages, notes, videos]);

  // Global Search Logic
  const searchResults = useMemo(() => {
    if (!searchQuery.trim()) return null;
    const q = searchQuery.toLowerCase();
    return {
      messages: messages.filter(m => m.text.toLowerCase().includes(q)),
      notes: notes.filter(n => n.title.toLowerCase().includes(q) || n.content.toLowerCase().includes(q)),
      videos: videos.filter(v => v.title.toLowerCase().includes(q))
    };
  }, [searchQuery, messages, notes, videos]);

  if (!currentUser) {
    return <Auth onLogin={(user) => {
      setCurrentUser(user);
      localStorage.setItem('kivia_current_user', JSON.stringify(user));
    }} />;
  }

  const activeGroup = groups.find(g => g.id === activeGroupId) || null;
  const filteredMessages = messages.filter(m => m.metadata?.groupId === activeGroupId);

  const handleCreateGroup = (name: string) => {
    const newGroup: Group = {
      id: Date.now().toString(),
      name,
      memberIds: [currentUser.id],
      createdAt: new Date().toISOString(),
      lastMessage: 'Group created'
    };
    setGroups([...groups, newGroup]);
    setActiveGroupId(newGroup.id);
  };

  const handleSendMessage = (text: string, type: Message['type'] = 'text', metadata: any = {}) => {
    if (!activeGroupId) return;
    const newMessage: Message = {
      id: Date.now().toString(),
      senderId: currentUser.id,
      senderName: currentUser.name,
      text,
      timestamp: new Date().toISOString(),
      type,
      metadata: { ...metadata, groupId: activeGroupId }
    };
    setMessages([...messages, newMessage]);
    setGroups(groups.map(g => g.id === activeGroupId ? { ...g, lastMessage: type === 'text' ? text : `[Sent ${type}]` } : g));
  };

  const handleAddVideo = (title: string, url: string) => {
    if (!activeGroupId) return;
    const newVideo: VideoSession = {
      id: Date.now().toString(),
      groupId: activeGroupId,
      title,
      url,
      thumbnail: `https://picsum.photos/seed/${Date.now()}/400/225`,
      duration: 'Live',
      recordedAt: new Date().toISOString(),
      transcript: "Simulated transcript: In today's physics session, we discussed Gauss's law and its applications in spherical conductors..."
    };
    setVideos([...videos, newVideo]);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('kivia_current_user');
  };

  return (
    <div className="flex h-screen bg-white">
      <div className="hidden md:block w-72 border-r border-gray-100 h-full">
        <Sidebar 
          groups={groups} 
          activeGroupId={activeGroupId} 
          onGroupSelect={setActiveGroupId} 
          currentUser={currentUser}
          onLogout={handleLogout}
          onCreateGroup={handleCreateGroup}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-white relative">
        <header className="flex items-center justify-between px-6 py-4 border-b border-gray-100 glass sticky top-0 z-10 gap-4">
          <div className="flex items-center gap-4 flex-shrink-0">
            <h1 className="text-xl font-bold text-indigo-600">KIVIA</h1>
            {activeGroup && (
              <div className="flex items-center gap-2">
                <span className="text-gray-300">/</span>
                <span className="text-sm font-bold text-gray-700 truncate max-w-[120px]">{activeGroup.name}</span>
                <button 
                  onClick={() => setIsCalling(true)}
                  className="ml-2 p-1.5 bg-green-50 text-green-600 rounded-lg hover:bg-green-600 hover:text-white transition-all shadow-sm"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                </button>
              </div>
            )}
          </div>

          <div className="flex-1 max-w-md relative mx-4">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
              <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
            <input 
              type="text" 
              placeholder="Search everything..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-gray-50 border-none rounded-2xl pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder:text-gray-400"
            />

            {searchQuery && searchResults && (
              <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden z-50 animate-in fade-in slide-in-from-top-2">
                <div className="max-h-[70vh] overflow-y-auto p-4 space-y-6">
                  {searchResults.messages.length > 0 && (
                    <div>
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 px-2">Messages</h4>
                      {searchResults.messages.slice(0, 5).map(m => (
                        <div key={m.id} className="p-2 hover:bg-indigo-50 rounded-xl cursor-pointer transition-colors" onClick={() => { setActiveGroupId(m.metadata?.groupId || null); setSearchQuery(''); }}>
                          <p className="text-xs font-bold text-gray-700">{m.senderName}</p>
                          <p className="text-xs text-gray-500 truncate">{m.text}</p>
                        </div>
                      ))}
                    </div>
                  )}
                  {searchResults.notes.length > 0 && (
                    <div>
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 px-2">Notes</h4>
                      {searchResults.notes.slice(0, 5).map(n => (
                        <div key={n.id} className="p-2 hover:bg-indigo-50 rounded-xl cursor-pointer transition-colors" onClick={() => { setActiveTab(AppTab.NOTEBOOK); setSearchQuery(''); }}>
                          <p className="text-xs font-bold text-gray-700">{n.title}</p>
                          <p className="text-xs text-gray-500 truncate">{n.content}</p>
                        </div>
                      ))}
                    </div>
                  )}
                  {searchResults.videos.length > 0 && (
                    <div>
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 px-2">Videos</h4>
                      {searchResults.videos.slice(0, 5).map(v => (
                        <div key={v.id} className="p-2 hover:bg-indigo-50 rounded-xl cursor-pointer transition-colors" onClick={() => { setActiveTab(AppTab.VIDEO); setSearchQuery(''); }}>
                          <p className="text-xs font-bold text-gray-700">{v.title}</p>
                        </div>
                      ))}
                    </div>
                  )}
                  {/* FIX: Use an explicit type cast (any[]) for the values extracted via Object.values to prevent "Property 'length' does not exist on type 'unknown'" */}
                  {Object.values(searchResults).every((arr: any) => arr.length === 0) && (
                    <div className="text-center py-8">
                      <p className="text-xs text-gray-400 font-bold">No results found for "{searchQuery}"</p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>

          <nav className="flex bg-gray-100/50 p-1 rounded-xl flex-shrink-0">
            {[
              { id: AppTab.CHAT, label: 'Chat', icon: <path d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /> },
              { id: AppTab.VIDEO, label: 'Sessions', icon: <path d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /> },
              { id: AppTab.NOTEBOOK, label: 'Notebook', icon: <path d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /> },
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as AppTab)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  activeTab === tab.id ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">{tab.icon}</svg>
                <span className="hidden lg:inline">{tab.label}</span>
              </button>
            ))}
          </nav>

          <button 
            onClick={() => setIsSARAOpen(!isSARAOpen)}
            className={`flex-shrink-0 p-2 rounded-full transition-colors flex items-center gap-2 ${isSARAOpen ? 'bg-indigo-100 text-indigo-600' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
          >
            <div className="relative flex h-3 w-3">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-3 w-3 bg-indigo-500"></span>
            </div>
            <span className="text-xs font-bold">SARA</span>
          </button>
        </header>

        <div className="flex-1 overflow-hidden">
          {!activeGroupId ? (
            <div className="h-full flex flex-col items-center justify-center p-8 text-center bg-gray-50/30">
              <div className="w-24 h-24 bg-indigo-100 text-indigo-600 rounded-3xl flex items-center justify-center mb-6 shadow-xl shadow-indigo-100">
                <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
              </div>
              <h2 className="text-2xl font-black text-gray-900 mb-2">Welcome to KIVIA</h2>
              <p className="text-gray-500 max-w-sm">Select a study group or create a new one to start collaborating.</p>
              <button 
                onClick={() => {
                   const name = prompt('Group Name:');
                   if (name) handleCreateGroup(name);
                }}
                className="mt-8 bg-indigo-600 text-white px-8 py-3 rounded-2xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-95"
              >
                Create Group
              </button>
            </div>
          ) : (
            <>
              {activeTab === AppTab.CHAT && <ChatView currentUser={currentUser} messages={filteredMessages} onSendMessage={handleSendMessage} allUsers={allUsers} />}
              {activeTab === AppTab.VIDEO && <VideoView videos={videos.filter(v => v.groupId === activeGroupId)} onAddVideo={handleAddVideo} />}
              {activeTab === AppTab.NOTEBOOK && <NotebookView notes={notes.filter(n => n.groupId === activeGroupId)} />}
            </>
          )}
        </div>

        {isSARAOpen && (
          <div className="absolute right-0 top-0 bottom-0 w-80 bg-white border-l border-gray-100 transform transition-transform duration-300 shadow-2xl z-20">
            <SARAPanel 
              onClose={() => setIsSARAOpen(false)} 
              messages={filteredMessages} 
              notes={notes.filter(n => n.groupId === activeGroupId)} 
              videos={videos.filter(v => v.groupId === activeGroupId)}
              onAiResponse={(msg) => setMessages([...messages, { ...msg, metadata: { ...msg.metadata, groupId: activeGroupId || '' } }])}
              onNewNote={(note) => setNotes([...notes, { ...note, groupId: activeGroupId || '' }])}
            />
          </div>
        )}
      </main>

      {isCalling && (
        <VideoCall 
          onClose={() => setIsCalling(false)} 
          currentUser={currentUser} 
          activeGroup={activeGroup!}
        />
      )}
    </div>
  );
};

