import React from 'react';

interface PreviewProps {
  type: 'image' | 'video' | 'website' | 'file';
  url: string;
  title?: string;
  description?: string;
}

const PreviewCard: React.FC<PreviewProps> = ({ type, url, title, description }) => {
  if (type === 'image') {
    return (
      <div className="mt-2 rounded-2xl overflow-hidden border border-gray-100 shadow-sm max-w-sm">
        <img src={url} alt="Shared preview" className="w-full h-auto object-cover max-h-60" />
      </div>
    );
  }

  if (type === 'video') {
    const isYoutube = url.includes('youtube') || url.includes('youtu.be');
    const videoId = isYoutube ? url.split('v=')[1]?.split('&')[0] || url.split('/').pop() : null;

    return (
      <div className="mt-2 rounded-2xl overflow-hidden border border-gray-100 shadow-sm max-w-sm bg-black aspect-video flex items-center justify-center">
        {videoId ? (
          <iframe 
            src={`https://www.youtube.com/embed/${videoId}`}
            className="w-full h-full"
            frameBorder="0"
            allowFullScreen
          />
        ) : (
          <div className="text-white text-xs font-bold">Video Preview Not Available</div>
        )}
      </div>
    );
  }

  if (type === 'website') {
    return (
      <a 
        href={url} 
        target="_blank" 
        rel="noopener noreferrer"
        className="mt-2 block rounded-2xl border border-gray-100 bg-white overflow-hidden shadow-sm hover:shadow-md transition-shadow max-w-sm"
      >
        <div className="h-24 bg-gray-50 flex items-center justify-center overflow-hidden">
          <img 
            src={`https://api.microlink.io?url=${encodeURIComponent(url)}&screenshot=true&embed=screenshot.url`} 
            alt="Site preview" 
            className="w-full h-full object-cover opacity-80"
            onError={(e) => (e.currentTarget.src = 'https://picsum.photos/seed/web/400/200')}
          />
        </div>
        <div className="p-3">
          <p className="text-xs font-bold text-indigo-600 truncate uppercase tracking-widest">{new URL(url).hostname}</p>
          <p className="text-sm font-bold text-gray-800 line-clamp-1 mt-1">{title || 'External Resource'}</p>
          <p className="text-xs text-gray-500 line-clamp-1 mt-0.5">{description || 'Visit website to learn more...'}</p>
        </div>
      </a>
    );
  }

  return (
    <div className="mt-2 flex items-center gap-3 p-3 bg-indigo-50/50 rounded-2xl border border-indigo-100 max-w-sm">
      <div className="bg-white p-2.5 rounded-xl text-indigo-600 shadow-sm">
        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
        </svg>
      </div>
      <div className="min-w-0 flex-1">
        <p className="font-bold text-sm truncate text-indigo-900">{title || 'Document.pdf'}</p>
        <p className="text-[10px] text-indigo-400 font-bold uppercase tracking-tight">Shared Resource</p>
      </div>
    </div>
  );
};

export default PreviewCard;

import React, { useState, useRef, useEffect } from 'react';
import { Message, User } from '../types';
import PreviewCard from './PreviewCard';

interface ChatViewProps {
  currentUser: User;
  messages: Message[];
  onSendMessage: (text: string, type?: Message['type'], metadata?: any) => void;
  allUsers: User[];
}

const ChatView: React.FC<ChatViewProps> = ({ currentUser, messages, onSendMessage, allUsers }) => {
  const [inputText, setInputText] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const detectMessageType = (text: string) => {
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const match = text.match(urlRegex);
    if (!match) return null;

    const url = match[0];
    if (url.match(/\.(jpeg|jpg|gif|png|webp)$/i)) return { type: 'image' as const, url };
    if (url.includes('youtube.com') || url.includes('youtu.be')) return { type: 'video' as const, url };
    return { type: 'website' as const, url };
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const preview = detectMessageType(inputText);
    if (preview) {
      onSendMessage(inputText, 'text', { preview });
    } else {
      onSendMessage(inputText);
    }
    setInputText('');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const isImage = file.type.startsWith('image/');
      const url = URL.createObjectURL(file);
      if (isImage) {
        onSendMessage(`Shared an image`, 'file', { fileName: file.name, fileUrl: url, preview: { type: 'image', url } });
      } else {
        onSendMessage(`Shared a file: ${file.name}`, 'file', { fileName: file.name, fileUrl: url });
      }
    }
  };

  const toggleRecording = () => {
    if (isRecording) {
      setIsRecording(false);
      onSendMessage('Voice note sent', 'voice', { duration: Math.floor(Math.random() * 30) + 5 });
    } else {
      setIsRecording(true);
    }
  };

  return (
    <div className="flex flex-col h-full bg-gray-50/20">
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center opacity-30 grayscale">
            <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
            </svg>
            <p className="text-sm font-bold tracking-widest uppercase">Start the conversation</p>
          </div>
        ) : (
          messages.map((msg) => {
            const isMe = msg.senderId === currentUser.id;
            const sender = allUsers.find(u => u.id === msg.senderId);
            const isAI = msg.type === 'ai';

            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                <div className={`flex max-w-[85%] gap-3 ${isMe ? 'flex-row-reverse' : 'flex-row'}`}>
                  {!isMe && (
                    <img src={sender?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${msg.senderName}`} className="w-8 h-8 rounded-full border border-gray-100 mt-1 shadow-sm bg-white" alt={msg.senderName} />
                  )}
                  <div className="min-w-0">
                    {!isMe && <div className="text-[10px] font-black text-gray-400 mb-1 ml-1 uppercase tracking-tighter">{msg.senderName}</div>}
                    <div className={`
                      p-4 rounded-3xl shadow-sm text-sm relative break-words leading-relaxed
                      ${isMe ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-gray-800 rounded-tl-none border border-gray-50'}
                      ${isAI ? 'border-2 border-indigo-200 bg-indigo-50/50 shadow-indigo-100' : ''}
                    `}>
                      {isAI && (
                        <div className="flex items-center gap-1.5 text-[10px] font-black text-indigo-600 mb-2 uppercase tracking-widest">
                          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                          SARA Analysis
                        </div>
                      )}

                      {msg.type === 'file' && !msg.metadata?.preview ? (
                        <PreviewCard type="file" url={msg.metadata?.fileUrl || '#'} title={msg.metadata?.fileName} />
                      ) : msg.type === 'voice' ? (
                        <div className="flex items-center gap-4 py-1 px-2 min-w-[150px]">
                          <button className="text-indigo-600 hover:text-indigo-700">
                            <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                          </button>
                          <div className="flex-1 space-y-1">
                            <div className="h-1 bg-indigo-200 rounded-full w-full relative">
                                <div className="absolute inset-y-0 left-0 w-1/3 bg-indigo-600 rounded-full"></div>
                            </div>
                            <div className="text-[9px] font-black opacity-50 uppercase tracking-tighter">00:{msg.metadata?.duration?.toString().padStart(2, '0') || '12'}</div>
                          </div>
                        </div>
                      ) : (
                        <div>
                          <p>{msg.text}</p>
                          {msg.metadata?.preview && (
                            <PreviewCard 
                              type={msg.metadata.preview.type} 
                              url={msg.metadata.preview.url} 
                              title={msg.metadata.preview.title}
                            />
                          )}
                        </div>
                      )}

                      <div className={`text-[9px] mt-2 font-bold uppercase tracking-tight opacity-50 text-right ${isMe ? 'text-indigo-100' : 'text-gray-400'}`}>
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-4 bg-white/80 backdrop-blur-md border-t border-gray-100 flex items-center gap-3">
        <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
        <button 
          type="button" 
          onClick={() => fileInputRef.current?.click()}
          className="p-2 text-gray-400 hover:text-indigo-600 transition-colors"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
        </button>
        <div className="flex-1 relative">
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Share a link, file, or message..."
            className="w-full bg-gray-100 border-none rounded-2xl px-5 py-3.5 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder:text-gray-400 font-medium"
          />
        </div>
        <button 
          type="button" 
          onClick={toggleRecording}
          className={`p-2.5 rounded-xl transition-all ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'text-gray-400 hover:text-indigo-600 hover:bg-gray-100'}`}
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
        </button>
        <button 
          type="submit" 
          disabled={!inputText.trim() || isRecording}
          className="bg-indigo-600 text-white p-3.5 rounded-2xl hover:bg-indigo-700 disabled:opacity-50 disabled:grayscale shadow-lg shadow-indigo-100 transition-all active:scale-95"
        >
          <svg className="w-5 h-5 transform rotate-45" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
        </button>
      </form>
    </div>
  );
};

