import React, { useState } from 'react';
import { Message, SmartNote, VideoSession } from '../types';
import { getSaraResponse, generateSmartNotes } from '../services/gemini';
import Logo from './Logo';

interface SARAPanelProps {
  onClose: () => void;
  messages: Message[];
  notes: SmartNote[];
  videos: VideoSession[];
  onAiResponse: (msg: Message) => void;
  onNewNote: (note: SmartNote) => void;
}

const SARAPanel: React.FC<SARAPanelProps> = ({ onClose, messages, notes, videos, onAiResponse, onNewNote }) => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<{ role: 'user' | 'ai', text: string }[]>([
    { role: 'ai', text: "Ready to study! Ask me to 'Summarize', 'Create Notes', or 'Analyze Video'." }
  ]);

  const handleAsk = async (explicitQuery?: string) => {
    const q = explicitQuery || query;
    if (!q.trim() || loading) return;

    setHistory(prev => [...prev, { role: 'user', text: q }]);
    setQuery('');
    setLoading(true);

    const isVideoAnalysis = q.toLowerCase().includes('analyze video') || q.toLowerCase().includes('session note');

    try {
      if (isVideoAnalysis && videos.length > 0) {
        const latestVideo = videos[videos.length - 1];
        const analysisPrompt = `Analyze the content of the video session titled "${latestVideo.title}". Transcript: ${latestVideo.transcript}. Extract 3-5 key learning concepts and create a summary.`;
        const response = await getSaraResponse(analysisPrompt, `The group has shared video sessions.`);

        onNewNote({
          id: 'vid-note-' + Date.now(),
          title: `SARA Insights: ${latestVideo.title}`,
          content: response,
          tags: ['Video Analysis', 'Session Summary'],
          source: { type: 'video', id: latestVideo.id, title: latestVideo.title },
          createdAt: new Date().toISOString(),
          groupId: ''
        });

        setHistory(prev => [...prev, { role: 'ai', text: `I've analyzed your session "${latestVideo.title}". Check your Notebook for the smart notes I generated!` }]);
      } else if (q.toLowerCase().includes('create notes') || q.toLowerCase().includes('generate notes')) {
        const chatStr = messages.map(m => `${m.senderName}: ${m.text}`).join('\n');
        const newNotes = await generateSmartNotes(chatStr);
        if (newNotes && newNotes.length > 0) {
          newNotes.forEach((n: any) => {
            onNewNote({
              id: Date.now().toString() + Math.random(),
              title: n.title,
              content: n.content,
              tags: n.tags,
              source: { type: 'chat', id: 'ai-gen', title: 'Chat Analysis' },
              createdAt: new Date().toISOString(),
              groupId: ''
            });
          });
          setHistory(prev => [...prev, { role: 'ai', text: `Success! I've added ${newNotes.length} new notes to your group notebook based on the recent discussion.` }]);
        } else {
          setHistory(prev => [...prev, { role: 'ai', text: "I analyzed the chat but didn't find enough dense academic content for a high-quality note yet. Keep discussing!" }]);
        }
      } else {
        const context = `
          Discussion Snippet: ${messages.slice(-15).map(m => m.text).join(' | ')}
          Existing Note Titles: ${notes.map(n => n.title).join(', ')}
          Available Videos: ${videos.map(v => v.title).join(', ')}
        `;
        const response = await getSaraResponse(q, context);
        setHistory(prev => [...prev, { role: 'ai', text: response }]);

        if (q.toLowerCase().includes('summarize')) {
          onAiResponse({
              id: 'sara-' + Date.now(),
              senderId: 'sara',
              senderName: 'SARA',
              text: response,
              timestamp: new Date().toISOString(),
              type: 'ai'
          });
        }
      }
    } catch (err) {
      setHistory(prev => [...prev, { role: 'ai', text: "I encountered an error trying to process that. Please try again or rephrase." }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full overflow-hidden bg-white">
      <div className="p-6 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
        <div className="flex items-center gap-3">
          <Logo className="w-10 h-10 shadow-lg shadow-indigo-100 rounded-full" />
          <div>
            <h3 className="text-sm font-black text-gray-900 tracking-tight">SARA AI</h3>
            <div className="flex items-center gap-1.5">
               <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
               <span className="text-[9px] font-black text-green-600 uppercase tracking-widest">Grounded Analysis</span>
            </div>
          </div>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-xl transition-all">
          <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 scroll-smooth bg-gray-50/20">
        {history.map((h, i) => (
          <div key={i} className={`flex ${h.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
            <div className={`p-4 rounded-2xl text-xs leading-relaxed max-w-[92%] shadow-sm ${
              h.role === 'user' ? 'bg-indigo-600 text-white font-medium' : 'bg-white text-gray-800 font-bold border border-gray-100'
            }`}>
              {h.text}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start animate-pulse">
            <div className="p-4 bg-white border border-gray-100 rounded-2xl flex gap-1.5">
              <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 border-t border-gray-100 bg-white">
        <div className="flex flex-col gap-3 mb-6">
          <p className="text-[9px] text-gray-400 font-black uppercase tracking-widest px-1">Quick Actions</p>
          <div className="flex flex-wrap gap-2">
            {[
              { label: "Scan Chat", q: "Create notes from latest chat" },
              { label: "Explain Session", q: "Analyze the latest video session" },
              { label: "Clarify CAP", q: "What did we say about the CAP theorem?" }
            ].map(s => (
              <button 
                key={s.label} 
                onClick={() => handleAsk(s.q)}
                className="text-[10px] bg-white border border-indigo-100 text-indigo-600 px-3 py-1.5 rounded-xl font-bold hover:bg-indigo-600 hover:text-white transition-all shadow-sm active:scale-95"
              >
                {s.label}
              </button>
            ))}
          </div>
        </div>
        <div className="flex gap-2">
          <input 
            type="text" 
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleAsk()}
            placeholder="Search group context..."
            className="flex-1 bg-gray-50 border border-transparent rounded-2xl px-5 py-3 text-xs font-medium focus:bg-white focus:border-indigo-100 focus:ring-4 focus:ring-indigo-500/5 outline-none transition-all"
          />
          <button 
            onClick={() => handleAsk()}
            disabled={!query.trim() || loading}
            className="bg-indigo-600 text-white p-3 rounded-2xl hover:bg-indigo-700 disabled:opacity-50 transition-all shadow-lg shadow-indigo-100 active:scale-90"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default SARAPanel;

import React, { useState, useRef, useEffect } from 'react';
