import { User, Group, Message, AppTab, SmartNote, VideoSession } from './types';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VideoView from './components/VideoView';
import NotebookView from './components/NotebookView';
import SARAPanel from './components/SARAPanel';
import Auth from './components/Auth';
import VideoCall from './components/VideoCall';
import Logo from './components/Logo';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.CHAT);
  const [groups, setGroups] = useState<Group[]>([]);
  const [activeGroupId, setActiveGroupId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [notes, setNotes] = useState<SmartNote[]>([]);
  const [videos, setVideos] = useState<VideoSession[]>([]);
  const [isSARAOpen, setIsSARAOpen] = useState(false);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCalling, setIsCalling] = useState(false);

  // Load Initial Data
  useEffect(() => {
    const savedUser = localStorage.getItem('kivia_current_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));

    setGroups(JSON.parse(localStorage.getItem('kivia_groups') || '[]'));
    setMessages(JSON.parse(localStorage.getItem('kivia_messages') || '[]'));
    setNotes(JSON.parse(localStorage.getItem('kivia_notes') || '[]'));
    setVideos(JSON.parse(localStorage.getItem('kivia_videos') || '[]'));
    setAllUsers(JSON.parse(localStorage.getItem('kivia_users') || '[]'));

    // Check for join code in URL hash
    const hash = window.location.hash;
    if (hash && hash.startsWith('#join-')) {
      const code = hash.replace('#join-', '');
      handleJoinByCode(code);
    }
  }, []);

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('kivia_groups', JSON.stringify(groups));
    localStorage.setItem('kivia_messages', JSON.stringify(messages));
    localStorage.setItem('kivia_notes', JSON.stringify(notes));
    localStorage.setItem('kivia_videos', JSON.stringify(videos));
  }, [groups, messages, notes, videos]);

  // Global Search Logic
  const searchResults = useMemo(() => {
    if (!searchQuery.trim()) return null;
    const q = searchQuery.toLowerCase();
    return {
      messages: messages.filter(m => m.text.toLowerCase().includes(q)),
      notes: notes.filter(n => n.title.toLowerCase().includes(q) || n.content.toLowerCase().includes(q)),
      videos: videos.filter(v => v.title.toLowerCase().includes(q))
    };
  }, [searchQuery, messages, notes, videos]);

  if (!currentUser) {
    return <Auth onLogin={(user) => {
      setCurrentUser(user);
      localStorage.setItem('kivia_current_user', JSON.stringify(user));
    }} />;
  }

  const activeGroup = groups.find(g => g.id === activeGroupId) || null;
  const filteredMessages = messages.filter(m => m.metadata?.groupId === activeGroupId);

  const handleCreateGroup = (name: string) => {
    const joinCode = Math.floor(100000 + Math.random() * 900000).toString();
    const newGroup: Group = {
      id: Date.now().toString(),
      name,
      joinCode,
      memberIds: [currentUser.id],
      createdAt: new Date().toISOString(),
      lastMessage: 'Group created'
    };
    setGroups([...groups, newGroup]);
    setActiveGroupId(newGroup.id);
  };

  const handleJoinByCode = (code: string) => {
    // In a real app, we'd fetch the group by code from a DB.
    // For this MVP, we'll "find" it or simulate a join.
    const cleanCode = code.trim();
    if (!cleanCode) return;

    // Check if we already have it
    const existing = groups.find(g => g.joinCode === cleanCode);
    if (existing) {
      setActiveGroupId(existing.id);
      return;
    }

    // Simulate joining a new group found via code
    const newGroup: Group = {
      id: 'joined-' + Date.now(),
      name: `Study Session #${cleanCode}`,
      joinCode: cleanCode,
      memberIds: [currentUser.id],
      createdAt: new Date().toISOString(),
      lastMessage: 'You joined via code'
    };
    setGroups([...groups, newGroup]);
    setActiveGroupId(newGroup.id);
    alert(`Successfully joined Group: ${newGroup.name}`);
    window.location.hash = ''; // Clear hash
  };

  const handleJoinGroupPrompt = () => {
    const code = prompt('Enter 6-digit Study Group Code (e.g. 123456):');
    if (code) handleJoinByCode(code);
  };

  const handleSendMessage = (text: string, type: Message['type'] = 'text', metadata: any = {}) => {
    if (!activeGroupId) return;
    const newMessage: Message = {
      id: Date.now().toString(),
      senderId: currentUser.id,
      senderName: currentUser.name,
      text,
      timestamp: new Date().toISOString(),
      type,
      metadata: { ...metadata, groupId: activeGroupId }
    };
    setMessages([...messages, newMessage]);
    setGroups(groups.map(g => g.id === activeGroupId ? { ...g, lastMessage: type === 'text' ? text : `[Sent ${type}]` } : g));
  };

  const handleAddVideo = (title: string, url: string) => {
    if (!activeGroupId) return;
    const newVideo: VideoSession = {
      id: Date.now().toString(),
      groupId: activeGroupId,
      title,
      url,
      thumbnail: `https://picsum.photos/seed/${Date.now()}/400/225`,
      duration: 'Live',
      recordedAt: new Date().toISOString(),
      transcript: "In today's study session, we tackled key concepts about distributed systems..."
    };
    setVideos([...videos, newVideo]);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('kivia_current_user');
  };

  const handleShareGroupLink = (group: Group) => {
    const link = `${window.location.origin}${window.location.pathname}#join-${group.joinCode}`;
    navigator.clipboard.writeText(link);
    alert('Join link copied to clipboard!');
  };

  return (
    <div className="flex h-screen bg-white font-['Inter']">
      <div className="hidden md:block w-80 border-r border-gray-100 h-full">
        <Sidebar 
          groups={groups} 
          activeGroupId={activeGroupId} 
          onGroupSelect={setActiveGroupId} 
          currentUser={currentUser}
          onLogout={handleLogout}
          onCreateGroup={handleCreateGroup}
          onShareGroupLink={handleShareGroupLink}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-white relative">
        <header className="flex items-center justify-between px-8 py-5 border-b border-gray-100 glass sticky top-0 z-30 gap-6">
          <div className="flex items-center gap-5 flex-shrink-0">
            <Logo className="w-10 h-10 shadow-lg shadow-green-100 rounded-full cursor-pointer" />
            <div className="flex flex-col">
              <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none mb-1">KIVIA</h1>
              <div className="flex items-center gap-2">
                {activeGroup ? (
                  <>
                    <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest truncate max-w-[120px]">{activeGroup.name}</span>
                    <button 
                      onClick={() => setIsCalling(true)}
                      className="ml-1 p-1 bg-green-50 text-green-600 rounded-md hover:bg-green-600 hover:text-white transition-all shadow-sm"
                      title="Start Group Call"
                    >
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                    </button>
                  </>
                ) : (
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Workspace</span>
                )}
              </div>
            </div>
          </div>

          <div className="flex-1 max-w-xl relative mx-4">
            <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none text-gray-400">
              <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
            <input 
              type="text" 
              placeholder="Search concepts, chats, and resources..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-gray-50 border border-transparent rounded-[1.5rem] pl-14 pr-6 py-3 text-sm focus:bg-white focus:border-indigo-100 focus:ring-4 focus:ring-indigo-500/5 outline-none transition-all placeholder:text-gray-400 font-medium"
            />

            {searchQuery && searchResults && (
              <div className="absolute top-full left-0 right-0 mt-3 bg-white rounded-[2rem] shadow-[0_30px_60px_-15px_rgba(0,0,0,0.15)] border border-gray-100 overflow-hidden z-[100] animate-in fade-in slide-in-from-top-4 duration-300">
                <div className="max-h-[75vh] overflow-y-auto p-6 space-y-8">
                  {searchResults.messages.length > 0 && (
                    <div>
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 px-2 flex items-center gap-2">
                        <span className="w-1 h-1 bg-indigo-500 rounded-full"></span> Chat Results
                      </h4>
                      {searchResults.messages.slice(0, 5).map(m => (
                        <div key={m.id} className="p-3 hover:bg-indigo-50 rounded-2xl cursor-pointer transition-all border border-transparent hover:border-indigo-100 group" onClick={() => { setActiveGroupId(m.metadata?.groupId || null); setSearchQuery(''); setActiveTab(AppTab.CHAT); }}>
                          <div className="flex justify-between items-center mb-1">
                            <p className="text-xs font-black text-gray-800">{m.senderName}</p>
                            <span className="text-[9px] font-black text-gray-300 uppercase tracking-widest">{new Date(m.timestamp).toLocaleDateString()}</span>
                          </div>
                          <p className="text-xs text-gray-500 truncate group-hover:text-indigo-600 transition-colors">{m.text}</p>
                        </div>
                      ))}
                    </div>
                  )}
                  {searchResults.notes.length > 0 && (
                    <div>
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 px-2 flex items-center gap-2">
                         <span className="w-1 h-1 bg-green-500 rounded-full"></span> Knowledge Base
                      </h4>
                      {searchResults.notes.slice(0, 5).map(n => (
                        <div key={n.id} className="p-3 hover:bg-green-50 rounded-2xl cursor-pointer transition-all border border-transparent hover:border-green-100 group" onClick={() => { setActiveTab(AppTab.NOTEBOOK); setSearchQuery(''); setActiveGroupId(n.groupId); }}>
                          <p className="text-xs font-black text-gray-800">{n.title}</p>
                          <p className="text-xs text-gray-500 truncate group-hover:text-green-600 transition-colors">{n.content}</p>
                        </div>
                      ))}
                    </div>
                  )}
                  {searchResults.videos.length > 0 && (
                    <div>
                      <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 px-2 flex items-center gap-2">
                         <span className="w-1 h-1 bg-red-500 rounded-full"></span> Video Sessions
                      </h4>
                      {searchResults.videos.slice(0, 5).map(v => (
                        <div key={v.id} className="p-3 hover:bg-red-50 rounded-2xl cursor-pointer transition-all border border-transparent hover:border-red-100 group" onClick={() => { setActiveTab(AppTab.VIDEO); setSearchQuery(''); setActiveGroupId(v.groupId); }}>
                          <p className="text-xs font-black text-gray-800 group-hover:text-red-600 transition-colors">{v.title}</p>
                        </div>
                      ))}
                    </div>
                  )}
                  {Object.values(searchResults).every((arr: any) => arr.length === 0) && (
                    <div className="text-center py-12">
                      <div className="w-16 h-16 bg-gray-50 rounded-3xl flex items-center justify-center mx-auto mb-4">
                        <svg className="w-8 h-8 text-gray-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 9.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                      </div>
                      <p className="text-xs text-gray-400 font-black uppercase tracking-widest">No results found</p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>

          <nav className="flex bg-gray-100/50 p-1.5 rounded-[1.25rem] flex-shrink-0 border border-gray-100">
            {[
              { id: AppTab.CHAT, label: 'Chat', icon: <path d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /> },
              { id: AppTab.VIDEO, label: 'Video', icon: <path d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /> },
              { id: AppTab.NOTEBOOK, label: 'Notes', icon: <path d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /> },
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as AppTab)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                  activeTab === tab.id ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'
                }`}
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}>{tab.icon}</svg>
                <span className="hidden xl:inline">{tab.label}</span>
              </button>
            ))}
          </nav>

          <button 
            onClick={() => setIsSARAOpen(!isSARAOpen)}
            className={`flex-shrink-0 p-3 rounded-full transition-all duration-300 flex items-center gap-2 ${isSARAOpen ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-500 hover:bg-gray-50 border border-gray-100 shadow-sm'}`}
          >
            <div className="relative flex h-3 w-3">
              <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${isSARAOpen ? 'bg-white' : 'bg-indigo-400'}`}></span>
              <span className={`relative inline-flex rounded-full h-3 w-3 ${isSARAOpen ? 'bg-white' : 'bg-indigo-500'}`}></span>
            </div>
            <span className="text-[10px] font-black uppercase tracking-widest">SARA</span>
          </button>
        </header>

        <div className="flex-1 overflow-hidden">
          {!activeGroupId ? (
            <div className="h-full flex flex-col items-center justify-center p-8 text-center bg-[#F9FBEC]/10 animate-in zoom-in-95 duration-700">
              <Logo className="w-32 h-32 mb-10 shadow-[0_40px_80px_-15px_rgba(162,209,73,0.3)] rounded-full bg-white p-4" />
              <h2 className="text-4xl font-black text-gray-900 mb-4 tracking-tight leading-tight">Elevate Your Peer Study<br/>Experience with KIVIA.</h2>
              <p className="text-gray-500 max-w-md font-medium text-lg leading-relaxed mb-12">Connect with your peers, share files, and let SARA transform your study sessions into smart insights.</p>
              <div className="flex flex-wrap justify-center gap-4">
                <button 
                  onClick={() => {
                    const name = prompt('Enter Group Name:');
                    if (name) handleCreateGroup(name);
                  }}
                  className="bg-indigo-600 text-white px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-100 hover:bg-indigo-700 hover:scale-105 transition-all active:scale-95"
                >
                  Create Study Group
                </button>
                <button 
                  onClick={handleJoinGroupPrompt}
                  className="bg-white border-2 border-gray-100 text-gray-600 px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:border-indigo-100 hover:text-indigo-600 transition-all"
                >
                   Join Session with Code
                </button>
              </div>
            </div>
          ) : (
            <>
              {activeTab === AppTab.CHAT && <ChatView currentUser={currentUser} messages={filteredMessages} onSendMessage={handleSendMessage} allUsers={allUsers} />}
              {activeTab === AppTab.VIDEO && <VideoView videos={videos.filter(v => v.groupId === activeGroupId)} onAddVideo={handleAddVideo} />}
              {activeTab === AppTab.NOTEBOOK && <NotebookView notes={notes.filter(n => n.groupId === activeGroupId)} />}
            </>
          )}
        </div>

        {isSARAOpen && (
          <div className="absolute right-0 top-0 bottom-0 w-[380px] bg-white border-l border-gray-100 transform transition-all duration-500 shadow-2xl z-50 animate-in slide-in-from-right-full">
            <SARAPanel 
              onClose={() => setIsSARAOpen(false)} 
              messages={filteredMessages} 
              notes={notes.filter(n => n.groupId === activeGroupId)} 
              videos={videos.filter(v => v.groupId === activeGroupId)}
              onAiResponse={(msg) => setMessages([...messages, { ...msg, metadata: { ...msg.metadata, groupId: activeGroupId || '' } }])}
              onNewNote={(note) => setNotes([...notes, { ...note, groupId: activeGroupId || '' }])}
            />
          </div>
        )}
      </main>

      {isCalling && (
        <VideoCall 
          onClose={() => setIsCalling(false)} 
          currentUser={currentUser} 
          activeGroup={activeGroup!}
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Group, User } from '../types';
import Logo from './Logo';

interface SidebarProps {
  groups: Group[];
  activeGroupId: string | null;
  onGroupSelect: (id: string) => void;
  currentUser: User;
  onLogout: () => void;
  onCreateGroup: (name: string) => void;
  onShareGroupLink: (group: Group) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ groups, activeGroupId, onGroupSelect, currentUser, onLogout, onCreateGroup, onShareGroupLink }) => {
  const handleCreate = () => {
    const name = prompt('Enter Study Group Name:');
    if (name && name.trim()) onCreateGroup(name.trim());
  };

  return (
    <div className="flex flex-col h-full bg-gray-50/50">
      <div className="p-6 border-b border-gray-100">
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-3">
            <Logo className="w-10 h-10" />
            <h1 className="text-xl font-black text-gray-900 tracking-tight">KIVIA</h1>
          </div>
        </div>

        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="relative">
              <img src={currentUser.avatar} alt={currentUser.name} className="w-10 h-10 rounded-full border-2 border-white shadow-sm" />
              <span className="absolute bottom-0 right-0 block h-3 w-3 rounded-full bg-green-500 border-2 border-white"></span>
            </div>
            <div className="min-w-0">
              <h3 className="text-sm font-bold text-gray-900 truncate">{currentUser.name}</h3>
              <p className="text-[10px] text-indigo-600 font-bold uppercase tracking-tight">{currentUser.status}</p>
            </div>
          </div>
          <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-500 rounded-lg transition-colors">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-2">
        <div className="flex items-center justify-between mb-4 px-2">
          <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Study Groups</h2>
          <button 
            onClick={handleCreate}
            className="p-1.5 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-600 hover:text-white transition-all shadow-sm"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
          </button>
        </div>

        {groups.length === 0 ? (
          <div className="p-4 text-center">
            <p className="text-xs text-gray-400 italic">No groups yet.</p>
          </div>
        ) : (
          groups.map(group => (
            <div key={group.id} className="relative group/item">
              <button
                onClick={() => onGroupSelect(group.id)}
                className={`w-full text-left p-3 pr-10 rounded-2xl transition-all group ${
                  activeGroupId === group.id 
                    ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100 scale-[1.02]' 
                    : 'hover:bg-white text-gray-600 border border-transparent hover:border-gray-100'
                }`}
              >
                <div className="font-bold text-sm truncate">{group.name}</div>
                <div className={`text-[10px] mt-1 truncate font-medium ${activeGroupId === group.id ? 'text-indigo-100' : 'text-gray-400'}`}>
                  {group.lastMessage || 'No messages yet'}
                </div>
              </button>
              <button 
                onClick={(e) => { e.stopPropagation(); onShareGroupLink(group); }}
                className={`absolute right-3 top-1/2 -translate-y-1/2 p-1.5 rounded-lg opacity-0 group-hover/item:opacity-100 transition-opacity ${activeGroupId === group.id ? 'text-indigo-200 hover:bg-white/10' : 'text-gray-400 hover:bg-gray-100'}`}
                title="Share Join Link"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
              </button>
            </div>
          ))
        )}
      </div>

      <div className="p-4 border-t border-gray-100 bg-white/50">
        <div className="bg-gradient-to-r from-indigo-600 to-purple-600 p-4 rounded-2xl text-white shadow-lg shadow-indigo-100">
          <h4 className="text-xs font-black uppercase tracking-widest mb-1 opacity-80">Pro Tip</h4>
          <p className="text-[10px] font-medium leading-relaxed">Ask SARA to "Generate Notes" from your chat anytime!</p>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useRef, useEffect } from 'react';
import { User, Group } from '../types';
import Logo from './Logo';

interface VideoCallProps {
  onClose: () => void;
  currentUser: User;
  activeGroup: Group;
}

const VideoCall: React.FC<VideoCallProps> = ({ onClose, currentUser, activeGroup }) => {
  const [isMuted, setIsMuted] = useState(false);
  const [isVideoOff, setIsVideoOff] = useState(false);
  const [isScreenSharing, setIsScreenSharing] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const screenRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    startCamera();
    return () => {
      streamRef.current?.getTracks().forEach(track => track.stop());
    };
  }, []);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Error accessing camera:", err);
    }
  };

  const toggleScreenShare = async () => {
    if (isScreenSharing) {
      const tracks = (screenRef.current?.srcObject as MediaStream)?.getTracks();
      tracks?.forEach(t => t.stop());
      setIsScreenSharing(false);
    } else {
      try {
        const stream = await navigator.mediaDevices.getDisplayMedia({ video: true });
        if (screenRef.current) {
          screenRef.current.srcObject = stream;
        }
        setIsScreenSharing(true);
        stream.getTracks()[0].onended = () => setIsScreenSharing(false);
      } catch (err) {
        console.error("Error screen sharing:", err);
      }
    }
  };

  const shareCallLink = () => {
    const callId = Math.random().toString(36).substring(7);
    const link = `${window.location.origin}${window.location.pathname}#call-${callId}`;
    navigator.clipboard.writeText(link);
    alert('Session call link copied to clipboard! Share it with your peers.');
  };

  return (
