                <input required value={rLabel} onChange={e => setRLabel(e.target.value)} type="text" placeholder="e.g. Daily Sync" className="w-full bg-gray-50 rounded-xl px-5 py-3 text-sm focus:bg-white outline-none border border-transparent focus:border-green-100 font-medium transition-all" />
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Day</label>
                <select value={rDay} onChange={e => setRDay(e.target.value)} className="w-full bg-gray-50 rounded-xl px-5 py-3 text-sm focus:bg-white outline-none border border-transparent focus:border-green-100 font-medium transition-all">
                  {days.map((d, i) => <option key={d} value={i}>{d}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Time</label>
                <input required value={rTime} onChange={e => setRTime(e.target.value)} type="time" className="w-full bg-gray-50 rounded-xl px-5 py-3 text-sm focus:bg-white outline-none border border-transparent focus:border-green-100 font-medium transition-all" />
              </div>
            </div>
            <div className="flex justify-end gap-3 pt-4">
              <button type="button" onClick={() => setShowAddRoutine(false)} className="px-6 py-2 text-xs font-black uppercase text-gray-400">Cancel</button>
              <button type="submit" className="bg-green-600 text-white px-8 py-2 rounded-xl text-xs font-black uppercase">Add Recurring Slot</button>
            </div>
          </form>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {routines.length === 0 ? (
            <div className="col-span-full py-16 text-center bg-white/50 border-2 border-dashed border-gray-100 rounded-[2.5rem]">
              <p className="text-gray-400 font-medium">No recurring routines set.</p>
            </div>
          ) : (
            routines.map(r => (
              <div key={r.id} className="bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-md transition-all group flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 bg-green-50 text-green-600 rounded-xl flex items-center justify-center font-black text-xs">
                    {days[r.dayOfWeek].substring(0, 3)}
                  </div>
                  <div>
                    <h4 className="font-black text-gray-900 text-sm">{r.label}</h4>
                    <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{r.time}</p>
                  </div>
                </div>
                <button onClick={() => onRemoveRoutine(r.id)} className="p-1.5 text-gray-200 hover:text-red-500 transition-colors">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>
            ))
          )}
        </div>
      </section>

      {/* Alarms / Focus Mode Suggestion */}
      <section className="bg-indigo-600 rounded-[3rem] p-10 text-white relative overflow-hidden shadow-2xl shadow-indigo-100">
        <div className="absolute top-0 right-0 p-8 opacity-10">
          <Logo className="w-48 h-48" />
        </div>
        <div className="relative z-10 max-w-xl space-y-4">
          <h2 className="text-3xl font-black tracking-tight leading-tight">Master Your Momentum</h2>
          <p className="text-indigo-100 font-medium">Use SARA to suggest the best study times based on your group's peak activity, or set quick "Focus Alarms" to keep the session disciplined.</p>
          <div className="flex gap-4 pt-4">
            <button className="bg-white text-indigo-600 px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-900/20 hover:scale-105 transition-all">Enable Auto-Reminders</button>
            <button className="bg-indigo-500 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest border border-indigo-400 hover:bg-indigo-400 transition-all">SARA Scheduler</button>
          </div>
        </div>
      </section>
    </div>
  );
};

export default ScheduleView;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Group, Message, AppTab, SmartNote, VideoSession, ScheduledSession, StudyRoutine } from './types';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VideoView from './components/VideoView';
import NotebookView from './components/NotebookView';
import ScheduleView from './components/ScheduleView';
import SARAPanel from './components/SARAPanel';
import Auth from './components/Auth';
import VideoCall from './components/VideoCall';
import Logo from './components/Logo';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.CHAT);
  const [groups, setGroups] = useState<Group[]>([]);
  const [activeGroupId, setActiveGroupId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [notes, setNotes] = useState<SmartNote[]>([]);
  const [videos, setVideos] = useState<VideoSession[]>([]);
  const [scheduledSessions, setScheduledSessions] = useState<ScheduledSession[]>([]);
  const [studyRoutines, setStudyRoutines] = useState<StudyRoutine[]>([]);
  const [isSARAOpen, setIsSARAOpen] = useState(false);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCalling, setIsCalling] = useState(false);

  // Focus Alarm / Timer
  const [focusTimer, setFocusTimer] = useState<number | null>(null); // seconds
  const [isTimerRunning, setIsTimerRunning] = useState(false);

  // Load Initial Data
  useEffect(() => {
    const savedUser = localStorage.getItem('kivia_current_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));

    const savedGroups = JSON.parse(localStorage.getItem('kivia_groups') || '[]');
    setGroups(savedGroups);
    setMessages(JSON.parse(localStorage.getItem('kivia_messages') || '[]'));
    setNotes(JSON.parse(localStorage.getItem('kivia_notes') || '[]'));
    setVideos(JSON.parse(localStorage.getItem('kivia_videos') || '[]'));
    setScheduledSessions(JSON.parse(localStorage.getItem('kivia_schedules') || '[]'));
    setStudyRoutines(JSON.parse(localStorage.getItem('kivia_routines') || '[]'));
    setAllUsers(JSON.parse(localStorage.getItem('kivia_users') || '[]'));

    // Hash Routing for Join/Call links
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#join-')) {
        const code = hash.replace('#join-', '');
        handleJoinByCode(code);
      } else if (hash.startsWith('#call-')) {
        const callId = hash.replace('#call-', '');
        if (activeGroupId) {
          setIsCalling(true);
        } else {
           const firstGroup = savedGroups[0];
           if (firstGroup) {
             setActiveGroupId(firstGroup.id);
             setIsCalling(true);
           }
        }
      }
    };

    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('kivia_groups', JSON.stringify(groups));
    localStorage.setItem('kivia_messages', JSON.stringify(messages));
    localStorage.setItem('kivia_notes', JSON.stringify(notes));
    localStorage.setItem('kivia_videos', JSON.stringify(videos));
    localStorage.setItem('kivia_schedules', JSON.stringify(scheduledSessions));
    localStorage.setItem('kivia_routines', JSON.stringify(studyRoutines));
  }, [groups, messages, notes, videos, scheduledSessions, studyRoutines]);

  // Focus Timer Tick
  useEffect(() => {
    let interval: any;
    if (isTimerRunning && focusTimer !== null && focusTimer > 0) {
      interval = setInterval(() => {
        setFocusTimer(prev => (prev !== null ? prev - 1 : 0));
      }, 1000);
    } else if (focusTimer === 0) {
      setIsTimerRunning(false);
      setFocusTimer(null);
      alert('Focus session complete! Time for a break.');
    }
    return () => clearInterval(interval);
  }, [isTimerRunning, focusTimer]);

  // Global Search Logic
  const searchResults = useMemo(() => {
    if (!searchQuery.trim()) return null;
    const q = searchQuery.toLowerCase();
    return {
      messages: messages.filter(m => m.text.toLowerCase().includes(q)),
      notes: notes.filter(n => n.title.toLowerCase().includes(q) || n.content.toLowerCase().includes(q)),
      videos: videos.filter(v => v.title.toLowerCase().includes(q))
    };
  }, [searchQuery, messages, notes, videos]);

  if (!currentUser) {
    return <Auth onLogin={(user) => {
      setCurrentUser(user);
      localStorage.setItem('kivia_current_user', JSON.stringify(user));
    }} />;
  }

  const activeGroup = groups.find(g => g.id === activeGroupId) || null;
  const filteredMessages = messages.filter(m => m.metadata?.groupId === activeGroupId);

  const handleCreateGroup = (name: string) => {
    const joinCode = Math.floor(100000 + Math.random() * 900000).toString();
    const newGroup: Group = {
      id: Date.now().toString(),
      name,
      joinCode,
      memberIds: [currentUser.id],
      createdAt: new Date().toISOString(),
      lastMessage: 'Group created'
    };
    setGroups([...groups, newGroup]);
    setActiveGroupId(newGroup.id);
  };

  const handleJoinByCode = (code: string) => {
    const cleanCode = code.trim();
    if (!cleanCode) return;
    const existing = groups.find(g => g.joinCode === cleanCode);
    if (existing) {
      setActiveGroupId(existing.id);
      return;
    }
    const newGroup: Group = {
      id: 'joined-' + Date.now(),
      name: `Peer Session #${cleanCode.slice(-4)}`,
      joinCode: cleanCode,
      memberIds: [currentUser.id],
      createdAt: new Date().toISOString(),
      lastMessage: 'Joined via special link'
    };
    setGroups([...groups, newGroup]);
    setActiveGroupId(newGroup.id);
    window.location.hash = '';
  };

  const handleJoinGroupPrompt = () => {
    const code = prompt('Enter 6-digit Study Group Code:');
    if (code) handleJoinByCode(code);
  };

  const handleSendMessage = (text: string, type: Message['type'] = 'text', metadata: any = {}) => {
    if (!activeGroupId) return;
    const newMessage: Message = {
      id: Date.now().toString(),
      senderId: currentUser.id,
      senderName: currentUser.name,
      text,
      timestamp: new Date().toISOString(),
      type,
      metadata: { ...metadata, groupId: activeGroupId }
    };
    setMessages([...messages, newMessage]);
    setGroups(groups.map(g => g.id === activeGroupId ? { ...g, lastMessage: type === 'text' ? text : `[Sent ${type}]` } : g));
  };

  const handleAddVideo = (title: string, url: string) => {
    if (!activeGroupId) return;
    const newVideo: VideoSession = {
      id: Date.now().toString(),
      groupId: activeGroupId,
      title,
      url,
      thumbnail: `https://picsum.photos/seed/${Date.now()}/400/225`,
      duration: 'Live',
      recordedAt: new Date().toISOString(),
      transcript: "This is a simulated transcript for the session."
    };
    setVideos([...videos, newVideo]);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('kivia_current_user');
  };

  const handleShareGroupLink = (group: Group) => {
    const link = `${window.location.origin}${window.location.pathname}#join-${group.joinCode}`;
    navigator.clipboard.writeText(link);
    alert(`Join link for "${group.name}" copied!`);
  };

  const formatTimer = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const setFocusAlarm = () => {
    const mins = prompt('Set focus timer for how many minutes?', '25');
    if (mins) {
      setFocusTimer(parseInt(mins) * 60);
      setIsTimerRunning(true);
    }
  };

  return (
    <div className="flex h-screen bg-white font-['Inter']">
      <div className="hidden md:block w-80 border-r border-gray-100 h-full">
        <Sidebar 
          groups={groups} 
          activeGroupId={activeGroupId} 
          onGroupSelect={setActiveGroupId} 
          currentUser={currentUser}
          onLogout={handleLogout}
          onCreateGroup={handleCreateGroup}
          onShareGroupLink={handleShareGroupLink}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-white relative">
        <header className="flex items-center justify-between px-8 py-5 border-b border-gray-100 glass sticky top-0 z-30 gap-6">
          <div className="flex items-center gap-5 flex-shrink-0">
            <Logo className="w-10 h-10 shadow-lg shadow-green-100 rounded-full cursor-pointer hover:scale-110 transition-transform" />
            <div className="flex flex-col">
              <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none mb-1">KIVIA</h1>
              <div className="flex items-center gap-2">
                {activeGroup ? (
                  <div className="flex items-center gap-2 group cursor-pointer" onClick={() => handleShareGroupLink(activeGroup)}>
                    <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest truncate max-w-[120px]">{activeGroup.name}</span>
                    <span className="text-[9px] font-bold text-gray-300 bg-gray-50 px-1.5 py-0.5 rounded border border-gray-100">ID: {activeGroup.joinCode}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setIsCalling(true); }}
                      className="ml-1 p-1 bg-green-50 text-green-600 rounded-md hover:bg-green-600 hover:text-white transition-all shadow-sm"
                      title="Start Session"
                    >
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                    </button>
                  </div>
                ) : (
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Global Dashboard</span>
                )}
              </div>
            </div>
          </div>

          <div className="flex-1 max-w-sm relative mx-4 hidden lg:block">
            <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none text-gray-400">
              <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
            <input 
              type="text" 
              placeholder="Search concepts..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-gray-50 border border-transparent rounded-[1.5rem] pl-14 pr-6 py-2.5 text-sm focus:bg-white focus:border-indigo-100 outline-none transition-all font-medium"
            />
          </div>

          <div className="flex items-center gap-4">
            {focusTimer !== null && (
              <div className="flex items-center gap-3 bg-red-50 text-red-600 px-4 py-2 rounded-2xl border border-red-100 animate-pulse">
                <span className="text-xs font-black tracking-widest">{formatTimer(focusTimer)}</span>
                <button onClick={() => setIsTimerRunning(!isTimerRunning)} className="hover:scale-110 transition-transform">
                  {isTimerRunning ? <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg> : <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>}
                </button>
              </div>
            )}
            {!focusTimer && (
              <button onClick={setFocusAlarm} className="p-2.5 bg-gray-50 text-gray-400 hover:text-indigo-600 rounded-xl transition-all border border-transparent hover:border-indigo-50" title="Set Focus Alarm">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
              </button>
            )}

            <nav className="flex bg-gray-100/50 p-1 rounded-[1.25rem] border border-gray-100">
              {[
                { id: AppTab.CHAT, icon: <path d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /> },
                { id: AppTab.VIDEO, icon: <path d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /> },
