            >
              <div className="relative flex h-3 w-3">
                <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${isSARAOpen ? 'bg-white' : 'bg-indigo-400'}`}></span>
                <span className={`relative inline-flex rounded-full h-3 w-3 ${isSARAOpen ? 'bg-white' : 'bg-indigo-500'}`}></span>
              </div>
              <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">SARA</span>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-hidden">
          {!activeGroupId ? (
            <div className="h-full flex flex-col items-center justify-center p-8 text-center bg-[#F9FBEC]/10 animate-in zoom-in-95 duration-700">
              <Logo className="w-32 h-32 mb-10 shadow-[0_40px_80px_-15px_rgba(162,209,73,0.3)] rounded-full bg-white p-4" />
              <h2 className="text-4xl font-black text-gray-900 mb-4 tracking-tight leading-tight">Your Academic Hub,<br/>Powered by AI Peers.</h2>
              <div className="flex flex-wrap justify-center gap-4">
                <button onClick={() => { const name = prompt('Enter Group Name:'); if (name) handleCreateGroup(name); }} className="bg-indigo-600 text-white px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-100 hover:bg-indigo-700 hover:scale-105 transition-all">Create Study Group</button>
                <button onClick={handleJoinGroupPrompt} className="bg-white border-2 border-gray-100 text-gray-600 px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:border-indigo-100 hover:text-indigo-600 transition-all">Join with Code</button>
              </div>
            </div>
          ) : (
            <>
              {activeTab === AppTab.CHAT && <ChatView currentUser={currentUser} messages={filteredMessages} onSendMessage={handleSendMessage} allUsers={allUsers} activeGroup={activeGroup} />}
              {activeTab === AppTab.VIDEO && <VideoView videos={videos.filter(v => v.groupId === activeGroupId)} onAddVideo={handleAddVideo} />}
              {activeTab === AppTab.NOTEBOOK && <NotebookView notes={notes.filter(n => n.groupId === activeGroupId)} />}
              {activeTab === AppTab.SCHEDULE && (
                <ScheduleView 
                  groupId={activeGroupId} 
                  sessions={scheduledSessions.filter(s => s.groupId === activeGroupId)} 
                  routines={studyRoutines.filter(r => r.groupId === activeGroupId)}
                  onAddSession={(s) => setScheduledSessions([...scheduledSessions, { ...s, id: Date.now().toString(), groupId: activeGroupId }])}
                  onAddRoutine={(r) => setStudyRoutines([...studyRoutines, { ...r, id: Date.now().toString(), groupId: activeGroupId }])}
                  onRemoveSession={(id) => setScheduledSessions(scheduledSessions.filter(s => s.id !== id))}
                  onRemoveRoutine={(id) => setStudyRoutines(studyRoutines.filter(r => r.id !== id))}
                />
              )}
            </>
          )}
        </div>

        {isSARAOpen && (
          <div className="absolute right-0 top-0 bottom-0 w-[400px] bg-white border-l border-gray-100 transform transition-all duration-500 shadow-2xl z-50 animate-in slide-in-from-right-full">
            <SARAPanel 
              onClose={() => setIsSARAOpen(false)} 
              messages={filteredMessages} 
              notes={notes.filter(n => n.groupId === activeGroupId)} 
              videos={videos.filter(v => v.groupId === activeGroupId)}
              onAiResponse={(msg) => setMessages([...messages, { ...msg, metadata: { ...msg.metadata, groupId: activeGroupId || '' } }])}
              onNewNote={(note) => setNotes([...notes, { ...note, groupId: activeGroupId || '' }])}
              activeGroupId={activeGroupId || ''}
            />
          </div>
        )}
      </main>

      {isCalling && (
        <VideoCall 
          onClose={() => setIsCalling(false)} 
          currentUser={currentUser} 
          activeGroup={activeGroup!}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Group, Message, AppTab, SmartNote, VideoSession, ScheduledSession, StudyRoutine } from './types';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VideoView from './components/VideoView';
import NotebookView from './components/NotebookView';
import ScheduleView from './components/ScheduleView';
import SARAPanel from './components/SARAPanel';
import Auth from './components/Auth';
import VideoCall from './components/VideoCall';
import Logo from './components/Logo';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.CHAT);
  const [groups, setGroups] = useState<Group[]>([]);
  const [activeGroupId, setActiveGroupId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [notes, setNotes] = useState<SmartNote[]>([]);
  const [videos, setVideos] = useState<VideoSession[]>([]);
  const [scheduledSessions, setScheduledSessions] = useState<ScheduledSession[]>([]);
  const [studyRoutines, setStudyRoutines] = useState<StudyRoutine[]>([]);
  const [isSARAOpen, setIsSARAOpen] = useState(false);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCalling, setIsCalling] = useState(false);

  // Focus Alarm / Timer
  const [focusTimer, setFocusTimer] = useState<number | null>(null); 
  const [isTimerRunning, setIsTimerRunning] = useState(false);

  // Load Initial Data
  useEffect(() => {
    const savedUser = localStorage.getItem('kivia_current_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));

    const savedGroups = JSON.parse(localStorage.getItem('kivia_groups') || '[]');
    setGroups(savedGroups);
    setMessages(JSON.parse(localStorage.getItem('kivia_messages') || '[]'));
    setNotes(JSON.parse(localStorage.getItem('kivia_notes') || '[]'));
    setVideos(JSON.parse(localStorage.getItem('kivia_videos') || '[]'));
    setScheduledSessions(JSON.parse(localStorage.getItem('kivia_schedules') || '[]'));
    setStudyRoutines(JSON.parse(localStorage.getItem('kivia_routines') || '[]'));
    setAllUsers(JSON.parse(localStorage.getItem('kivia_users') || '[]'));

    // Check deep links on mount
    handleHashRouting();
    window.addEventListener('hashchange', handleHashRouting);
    return () => window.removeEventListener('hashchange', handleHashRouting);
  }, []);

  // Check for upcoming session reminders
  useEffect(() => {
    const reminderInterval = setInterval(() => {
      const now = new Date();
      scheduledSessions.forEach(session => {
        const startTime = new Date(session.startTime);
        const diff = startTime.getTime() - now.getTime();
        // Reminder 5 minutes before
        if (diff > 290000 && diff < 310000) {
          const groupName = groups.find(g => g.id === session.groupId)?.name || 'Study Group';
          alert(`Reminder: Your session "${session.title}" in ${groupName} starts in 5 minutes!`);
        }
      });
    }, 10000); // Check every 10 seconds
    return () => clearInterval(reminderInterval);
  }, [scheduledSessions, groups]);

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('kivia_groups', JSON.stringify(groups));
    localStorage.setItem('kivia_messages', JSON.stringify(messages));
    localStorage.setItem('kivia_notes', JSON.stringify(notes));
    localStorage.setItem('kivia_videos', JSON.stringify(videos));
    localStorage.setItem('kivia_schedules', JSON.stringify(scheduledSessions));
    localStorage.setItem('kivia_routines', JSON.stringify(studyRoutines));
  }, [groups, messages, notes, videos, scheduledSessions, studyRoutines]);

  // Focus Timer Tick
  useEffect(() => {
    let interval: any;
    if (isTimerRunning && focusTimer !== null && focusTimer > 0) {
      interval = setInterval(() => {
        setFocusTimer(prev => (prev !== null ? prev - 1 : 0));
      }, 1000);
    } else if (focusTimer === 0) {
      setIsTimerRunning(false);
      setFocusTimer(null);
      alert('Focus session complete! SARA recommends a 5-minute brain break.');
    }
    return () => clearInterval(interval);
  }, [isTimerRunning, focusTimer]);

  const handleHashRouting = () => {
    const hash = window.location.hash;
    if (hash.startsWith('#join-')) {
      const code = hash.replace('#join-', '');
      handleJoinByCode(code);
    } else if (hash.startsWith('#call-')) {
      // Find a group to launch the call in
      if (!activeGroupId && groups.length > 0) {
        setActiveGroupId(groups[0].id);
      }
      setIsCalling(true);
      window.location.hash = ''; // Clear after trigger
    }
  };

  const handleJoinByCode = (code: string) => {
    const cleanCode = code.trim();
    if (!cleanCode) return;
    const existing = groups.find(g => g.joinCode === cleanCode);
    if (existing) {
      setActiveGroupId(existing.id);
      return;
    }
    const newGroup: Group = {
      id: 'joined-' + Date.now(),
      name: `Study Session #${cleanCode.slice(-4)}`,
      joinCode: cleanCode,
      memberIds: [currentUser?.id || 'anon'],
      createdAt: new Date().toISOString(),
      lastMessage: 'You joined via a peer link'
    };
    setGroups(prev => [...prev, newGroup]);
    setActiveGroupId(newGroup.id);
    window.location.hash = '';
  };

  const activeGroup = groups.find(g => g.id === activeGroupId) || null;
  const filteredMessages = messages.filter(m => m.metadata?.groupId === activeGroupId);

  const handleCreateGroup = (name: string) => {
    const joinCode = Math.floor(100000 + Math.random() * 900000).toString();
    const newGroup: Group = {
      id: Date.now().toString(),
      name,
      joinCode,
      memberIds: [currentUser!.id],
      createdAt: new Date().toISOString(),
      lastMessage: 'Group created'
    };
    setGroups([...groups, newGroup]);
    setActiveGroupId(newGroup.id);
  };

  const handleSendMessage = (text: string, type: Message['type'] = 'text', metadata: any = {}) => {
    if (!activeGroupId) return;
    const newMessage: Message = {
      id: Date.now().toString(),
      senderId: currentUser!.id,
      senderName: currentUser!.name,
      text,
      timestamp: new Date().toISOString(),
      type,
      metadata: { ...metadata, groupId: activeGroupId }
    };
    setMessages(prev => [...prev, newMessage]);
    setGroups(prev => prev.map(g => g.id === activeGroupId ? { ...g, lastMessage: type === 'text' ? text : `[${type}]` } : g));
  };

  const formatTimer = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const setFocusAlarm = () => {
    const mins = prompt('How many minutes would you like to focus?', '25');
    if (mins) {
      setFocusTimer(parseInt(mins) * 60);
      setIsTimerRunning(true);
    }
  };

  if (!currentUser) {
    return <Auth onLogin={(user) => {
      setCurrentUser(user);
      localStorage.setItem('kivia_current_user', JSON.stringify(user));
    }} />;
  }

  return (
    <div className="flex h-screen bg-white font-['Inter'] selection:bg-indigo-100 selection:text-indigo-900">
      <div className="hidden md:block w-80 border-r border-gray-100 h-full overflow-hidden">
        <Sidebar 
          groups={groups} 
          activeGroupId={activeGroupId} 
          onGroupSelect={setActiveGroupId} 
          currentUser={currentUser}
          onLogout={() => { setCurrentUser(null); localStorage.removeItem('kivia_current_user'); }}
          onCreateGroup={handleCreateGroup}
          onShareGroupLink={(g) => {
             const link = `${window.location.origin}${window.location.pathname}#join-${g.joinCode}`;
             navigator.clipboard.writeText(link);
             alert(`Join Link Copied: ${g.name}`);
          }}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-white relative">
        <header className="flex items-center justify-between px-8 py-5 border-b border-gray-100 glass sticky top-0 z-30 gap-6">
          <div className="flex items-center gap-5 flex-shrink-0">
            <Logo className="w-10 h-10 shadow-lg shadow-green-100 rounded-full cursor-pointer hover:scale-110 transition-transform" />
            <div className="flex flex-col">
              <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none mb-1">KIVIA</h1>
              <div className="flex items-center gap-2">
                {activeGroup ? (
                  <div className="flex items-center gap-2 group cursor-pointer" onClick={() => { setActiveTab(AppTab.CHAT); }}>
                    <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest truncate max-w-[120px]">{activeGroup.name}</span>
                    <span className="text-[9px] font-bold text-gray-300 bg-gray-50 px-1.5 py-0.5 rounded border border-gray-100">ID: {activeGroup.joinCode}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setIsCalling(true); }}
                      className="ml-1 p-1 bg-green-50 text-green-600 rounded-md hover:bg-green-600 hover:text-white transition-all shadow-sm"
                      title="Start Session"
                    >
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                    </button>
                  </div>
                ) : (
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Global Command Center</span>
                )}
              </div>
            </div>
          </div>

          <div className="flex-1 max-w-sm relative mx-4 hidden lg:block">
            <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none text-gray-400">
              <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
            <input 
              type="text" 
              placeholder="Search study assets..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-gray-50 border border-transparent rounded-[1.5rem] pl-14 pr-6 py-2.5 text-sm focus:bg-white focus:border-indigo-100 outline-none transition-all font-medium"
            />
          </div>

          <div className="flex items-center gap-4">
            {focusTimer !== null && (
              <div className="flex items-center gap-3 bg-red-50 text-red-600 px-4 py-2 rounded-2xl border border-red-100 animate-pulse shadow-sm shadow-red-100">
                <span className="text-xs font-black tracking-widest">{formatTimer(focusTimer)}</span>
                <button onClick={() => setIsTimerRunning(!isTimerRunning)} className="hover:scale-110 transition-transform">
                  {isTimerRunning ? <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg> : <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>}
                </button>
              </div>
            )}

            {!focusTimer && (
              <button onClick={setFocusAlarm} className="p-2.5 bg-gray-50 text-gray-400 hover:text-indigo-600 rounded-xl transition-all border border-transparent hover:border-indigo-50" title="Start Focus Timer">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
              </button>
            )}

            <nav className="flex bg-gray-100/50 p-1 rounded-[1.25rem] border border-gray-100 shadow-inner">
              {[
                { id: AppTab.CHAT, icon: <path d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /> },
                { id: AppTab.VIDEO, icon: <path d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /> },
                { id: AppTab.NOTEBOOK, icon: <path d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /> },
                { id: AppTab.SCHEDULE, icon: <path d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /> },
              ].map(tab => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as AppTab)}
                  className={`p-2.5 rounded-xl transition-all ${activeTab === tab.id ? 'bg-white text-indigo-600 shadow-md' : 'text-gray-400 hover:text-gray-600'}`}
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}>{tab.icon}</svg>
                </button>
              ))}
            </nav>

            <button 
              onClick={() => setIsSARAOpen(!isSARAOpen)}
              className={`p-3 rounded-full transition-all duration-300 flex items-center gap-2 border ${isSARAOpen ? 'bg-indigo-600 text-white border-indigo-500 shadow-xl' : 'bg-white text-gray-500 hover:bg-gray-50 border-gray-100 shadow-sm'}`}
            >
              <div className="relative flex h-3 w-3">
                <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${isSARAOpen ? 'bg-white' : 'bg-indigo-400'}`}></span>
                <span className={`relative inline-flex rounded-full h-3 w-3 ${isSARAOpen ? 'bg-white' : 'bg-indigo-500'}`}></span>
              </div>
              <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">SARA AI</span>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-hidden relative">
          {!activeGroupId ? (
            <div className="h-full flex flex-col items-center justify-center p-8 text-center bg-[#F9FBEC]/10 animate-in zoom-in-95 duration-1000">
              <Logo className="w-32 h-32 mb-10 shadow-[0_40px_80px_-15px_rgba(162,209,73,0.3)] rounded-full bg-white p-4" />
              <h2 className="text-4xl font-black text-gray-900 mb-4 tracking-tight leading-tight">Your Academic Haven,<br/>Amplified by AI.</h2>
              <div className="flex flex-wrap justify-center gap-4">
                <button onClick={() => { const name = prompt('Enter Group Name:'); if (name) handleCreateGroup(name); }} className="bg-indigo-600 text-white px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-100 hover:bg-indigo-700 hover:scale-105 transition-all">Create Study Group</button>
                <button onClick={() => { const code = prompt('Enter 6-digit Study Group Code:'); if (code) handleJoinByCode(code); }} className="bg-white border-2 border-gray-100 text-gray-600 px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:border-indigo-100 hover:text-indigo-600 transition-all">Join Session</button>
              </div>
            </div>
          ) : (
            <>
              {activeTab === AppTab.CHAT && <ChatView currentUser={currentUser} messages={filteredMessages} onSendMessage={handleSendMessage} allUsers={allUsers} activeGroup={activeGroup} />}
              {activeTab === AppTab.VIDEO && <VideoView videos={videos.filter(v => v.groupId === activeGroupId)} onAddVideo={(t, u) => setVideos([...videos, { id: Date.now().toString(), groupId: activeGroupId, title: t, url: u, thumbnail: `https://picsum.photos/seed/${Date.now()}/400/225`, duration: '0:00', recordedAt: new Date().toISOString() }])} />}
              {activeTab === AppTab.NOTEBOOK && <NotebookView notes={notes.filter(n => n.groupId === activeGroupId)} />}
              {activeTab === AppTab.SCHEDULE && (
                <ScheduleView 
                  groupId={activeGroupId} 
                  sessions={scheduledSessions.filter(s => s.groupId === activeGroupId)} 
                  routines={studyRoutines.filter(r => r.groupId === activeGroupId)}
                  onAddSession={(s) => setScheduledSessions([...scheduledSessions, { ...s, id: Date.now().toString(), groupId: activeGroupId }])}
                  onAddRoutine={(r) => setStudyRoutines([...studyRoutines, { ...r, id: Date.now().toString(), groupId: activeGroupId }])}
                  onRemoveSession={(id) => setScheduledSessions(scheduledSessions.filter(s => s.id !== id))}
                  onRemoveRoutine={(id) => setStudyRoutines(studyRoutines.filter(r => r.id !== id))}
                />
              )}
            </>
          )}

          {isSARAOpen && (
            <div className="absolute right-0 top-0 bottom-0 w-full sm:w-[400px] bg-white border-l border-gray-100 transform transition-all duration-500 shadow-2xl z-50 animate-in slide-in-from-right-full">
              <SARAPanel 
                onClose={() => setIsSARAOpen(false)} 
                messages={filteredMessages} 
                notes={notes.filter(n => n.groupId === activeGroupId)} 
                videos={videos.filter(v => v.groupId === activeGroupId)}
                onAiResponse={(msg) => handleSendMessage(msg.text, 'ai')}
                onNewNote={(note) => setNotes([...notes, { ...note, groupId: activeGroupId || '' }])}
                activeGroupId={activeGroupId || ''}
              />
            </div>
          )}
        </div>
      </main>

      {isCalling && (
        <VideoCall 
          onClose={() => setIsCalling(false)} 
          currentUser={currentUser} 
          activeGroup={activeGroup!}
        />
      )}
    </div>
  );
};

