import React, { useState } from 'react';
import { Post, User } from '../types';
import Logo from './Logo';

interface HomeViewProps {
  currentUser: User;
  posts: Post[];
  onAddPost: (content: string, type: 'text' | 'image' | 'video', mediaUrl?: string) => void;
  onLikePost: (postId: string) => void;
}

const HomeView: React.FC<HomeViewProps> = ({ currentUser, posts, onAddPost, onLikePost }) => {
  const [newPostContent, setNewPostContent] = useState('');
  const [mediaUrl, setMediaUrl] = useState('');
  const [postType, setPostType] = useState<'text' | 'image' | 'video'>('text');
  const [showPublisher, setShowPublisher] = useState(false);

  const handlePublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPostContent.trim()) return;
    onAddPost(newPostContent, postType, mediaUrl);
    setNewPostContent('');
    setMediaUrl('');
    setPostType('text');
    setShowPublisher(false);
  };

  return (
    <div className="h-full overflow-y-auto bg-gray-50/20 p-8 flex flex-col items-center">
      <div className="w-full max-w-2xl space-y-10">
        {/* Welcome Header */}
        <div className="space-y-2">
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">Study Community</h2>
          <p className="text-gray-500 font-medium">What's the breakthrough today, <span className="text-indigo-600">@{currentUser.name}</span>?</p>
        </div>

        {/* Post Creator */}
        <div className="bg-white rounded-[2.5rem] p-6 shadow-xl shadow-gray-200/50 border border-gray-100 transition-all">
          {!showPublisher ? (
            <div className="flex items-center gap-4 cursor-pointer" onClick={() => setShowPublisher(true)}>
              <img src={currentUser.avatar} className="w-10 h-10 rounded-full" />
              <div className="flex-1 bg-gray-50 hover:bg-gray-100 rounded-2xl px-6 py-3 text-gray-400 text-sm font-medium transition-colors">
                Share a study tip or a resource...
              </div>
            </div>
          ) : (
            <form onSubmit={handlePublish} className="space-y-6 animate-in fade-in duration-300">
              <textarea 
                autoFocus
                value={newPostContent}
                onChange={e => setNewPostContent(e.target.value)}
                placeholder="Break down a concept or share progress..."
                className="w-full bg-transparent border-none focus:ring-0 text-gray-800 placeholder:text-gray-300 font-medium resize-none text-lg min-h-[120px]"
              />

              <div className="space-y-4 pt-4 border-t border-gray-50">
                <div className="flex items-center gap-4">
                   <button 
                    type="button" 
                    onClick={() => setPostType('text')}
                    className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${postType === 'text' ? 'bg-indigo-600 text-white' : 'bg-gray-50 text-gray-400 hover:text-gray-600'}`}
                   >
                    Text
                   </button>
                   <button 
                    type="button" 
                    onClick={() => setPostType('image')}
                    className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${postType === 'image' ? 'bg-indigo-600 text-white' : 'bg-gray-50 text-gray-400 hover:text-gray-600'}`}
                   >
                    Image
                   </button>
                   <button 
                    type="button" 
                    onClick={() => setPostType('video')}
                    className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${postType === 'video' ? 'bg-indigo-600 text-white' : 'bg-gray-50 text-gray-400 hover:text-gray-600'}`}
                   >
                    Video Link
                   </button>
                </div>

                {postType !== 'text' && (
                  <input 
                    type="url" 
                    value={mediaUrl}
                    onChange={e => setMediaUrl(e.target.value)}
                    placeholder={postType === 'image' ? "Paste image URL..." : "Paste YouTube URL..."}
                    className="w-full bg-gray-50 rounded-xl px-5 py-3 text-sm focus:bg-white border border-transparent focus:border-indigo-100 outline-none transition-all font-medium"
                  />
                )}
              </div>

              <div className="flex justify-end gap-3 items-center">
                <button type="button" onClick={() => setShowPublisher(false)} className="text-xs font-black text-gray-400 uppercase tracking-widest px-4">Cancel</button>
                <button type="submit" className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all">Publish Post</button>
              </div>
            </form>
          )}
        </div>

        {/* Feed List */}
        <div className="space-y-8 pb-20">
          {posts.length === 0 ? (
            <div className="text-center py-20 opacity-30 flex flex-col items-center">
              <Logo className="w-16 h-16 mb-4 grayscale" />
              <p className="font-bold">The feed is quiet. Start the conversation!</p>
            </div>
          ) : (
            posts.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()).map(post => (
              <div key={post.id} className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-gray-100 space-y-6 hover:shadow-lg transition-all group animate-in slide-in-from-bottom-4 duration-500">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <img src={post.authorAvatar} className="w-12 h-12 rounded-full border border-gray-50" />
                    <div>
                      <h4 className="font-black text-gray-900 leading-none mb-1">@{post.authorName}</h4>
                      <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">
                        {new Date(post.timestamp).toLocaleDateString()} at {new Date(post.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </p>
                    </div>
                  </div>
                  <Logo className="w-6 h-6 opacity-20 group-hover:opacity-100 transition-opacity" />
                </div>

                <p className="text-gray-800 font-medium leading-relaxed text-lg">{post.content}</p>

                {post.type === 'image' && post.mediaUrl && (
                  <div className="rounded-[2rem] overflow-hidden border border-gray-50">
                    <img src={post.mediaUrl} className="w-full h-auto max-h-[500px] object-cover" />
                  </div>
                )}

                {post.type === 'video' && post.mediaUrl && (
                  <div className="rounded-[2rem] overflow-hidden border border-gray-50 bg-black aspect-video">
                    <iframe 
                      src={post.mediaUrl.replace('watch?v=', 'embed/')} 
                      className="w-full h-full"
                      allowFullScreen
                    ></iframe>
                  </div>
                )}

                <div className="flex items-center gap-6 pt-4 border-t border-gray-50">
                  <button 
                    onClick={() => onLikePost(post.id)}
                    className={`flex items-center gap-2 group/btn transition-colors ${post.likes.includes(currentUser.id) ? 'text-red-500' : 'text-gray-400 hover:text-red-500'}`}
                  >
                    <svg className={`w-6 h-6 ${post.likes.includes(currentUser.id) ? 'fill-current' : 'fill-none group-hover/btn:fill-current'}`} stroke="currentColor" strokeWidth={2.5} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
                    <span className="text-xs font-black uppercase tracking-widest">{post.likes.length}</span>
                  </button>
                  <button className="flex items-center gap-2 text-gray-400 hover:text-indigo-600 transition-colors">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" strokeWidth={2.5} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M7 8h10M7 12h4m1 8l-4-4H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-3l-4 4z" /></svg>
                    <span className="text-xs font-black uppercase tracking-widest">Share</span>
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

