import React, { useState, useRef, useEffect } from 'react';
import { Message, User, Group } from '../types';
import PreviewCard from './PreviewCard';
import Logo from './Logo';

interface ChatViewProps {
  currentUser: User;
  messages: Message[];
  onSendMessage: (text: string, type?: Message['type'], metadata?: any) => void;
  allUsers: User[];
  activeGroup: Group | null;
}

const ChatView: React.FC<ChatViewProps> = ({ currentUser, messages, onSendMessage, allUsers, activeGroup }) => {
  const [inputText, setInputText] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const detectMessageType = (text: string) => {
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const match = text.match(urlRegex);
    if (!match) return null;

    const url = match[0];
    if (url.match(/\.(jpeg|jpg|gif|png|webp)$/i)) return { type: 'image' as const, url };
    if (url.includes('youtube.com') || url.includes('youtu.be')) return { type: 'video' as const, url };
    return { type: 'website' as const, url };
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const preview = detectMessageType(inputText);
    if (preview) {
      onSendMessage(inputText, 'text', { preview });
    } else {
      onSendMessage(inputText);
    }
    setInputText('');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const isImage = file.type.startsWith('image/');
      const url = URL.createObjectURL(file);
      if (isImage) {
        onSendMessage(`Shared an image`, 'file', { fileName: file.name, fileUrl: url, preview: { type: 'image', url } });
      } else {
        onSendMessage(`Shared a file: ${file.name}`, 'file', { fileName: file.name, fileUrl: url });
      }
    }
  };

  const toggleRecording = () => {
    if (isRecording) {
      setIsRecording(false);
      onSendMessage('Voice note sent', 'voice', { duration: Math.floor(Math.random() * 30) + 5 });
    } else {
      setIsRecording(true);
    }
  };

  return (
    <div className="flex flex-col h-full bg-gray-50/20">
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-4">
            <Logo className="w-20 h-20 opacity-20 grayscale" />
            <div className="space-y-1">
              <h3 className="text-xl font-black text-gray-300 tracking-tight uppercase">Welcome to {activeGroup?.name}</h3>
              <p className="text-xs text-gray-400 font-medium max-w-[250px] mx-auto leading-relaxed">
                Invite peers using code <span className="font-black text-indigo-400">{activeGroup?.joinCode}</span> or just start the conversation!
              </p>
            </div>
          </div>
        ) : (
          messages.map((msg) => {
            const isMe = msg.senderId === currentUser.id;
            const sender = allUsers.find(u => u.id === msg.senderId);
            const isAI = msg.type === 'ai';

            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
                <div className={`flex max-w-[85%] gap-3 ${isMe ? 'flex-row-reverse' : 'flex-row'}`}>
                  {!isMe && (
                    <img src={sender?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${msg.senderName}`} className="w-9 h-9 rounded-full border border-gray-100 mt-1 shadow-sm bg-white" alt={msg.senderName} />
                  )}
                  <div className="min-w-0">
                    {!isMe && <div className="text-[10px] font-black text-gray-400 mb-1 ml-1 uppercase tracking-tighter">{msg.senderName}</div>}
                    <div className={`
                      p-4 rounded-3xl shadow-sm text-sm relative break-words leading-relaxed
                      ${isMe ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-gray-800 rounded-tl-none border border-gray-50'}
                      ${isAI ? 'border-2 border-indigo-200 bg-indigo-50/50 shadow-indigo-100' : ''}
                    `}>
                      {isAI && (
                        <div className="flex items-center gap-1.5 text-[10px] font-black text-indigo-600 mb-2 uppercase tracking-widest">
                          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                          SARA Analysis
                        </div>
                      )}

                      {msg.type === 'file' && !msg.metadata?.preview ? (
                        <PreviewCard type="file" url={msg.metadata?.fileUrl || '#'} title={msg.metadata?.fileName} />
                      ) : msg.type === 'voice' ? (
                        <div className="flex items-center gap-4 py-1 px-2 min-w-[180px]">
                          <button className="text-indigo-600 hover:text-indigo-700 transition-transform active:scale-90">
                            <svg className="w-9 h-9" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                          </button>
                          <div className="flex-1 space-y-1.5">
                            <div className="h-1.5 bg-indigo-200 rounded-full w-full relative overflow-hidden">
                                <div className="absolute inset-y-0 left-0 w-1/3 bg-indigo-600 rounded-full"></div>
                            </div>
                            <div className="flex justify-between items-center text-[9px] font-black opacity-60 uppercase tracking-tighter">
                                <span>00:{msg.metadata?.duration?.toString().padStart(2, '0') || '12'}</span>
                                <span>Voice Note</span>
                            </div>
                          </div>
                        </div>
                      ) : (
                        <div>
                          <p className="whitespace-pre-wrap">{msg.text}</p>
                          {msg.metadata?.preview && (
                            <PreviewCard 
                              type={msg.metadata.preview.type} 
                              url={msg.metadata.preview.url} 
                              title={msg.metadata.preview.title}
                            />
                          )}
                        </div>
                      )}

                      <div className={`text-[9px] mt-2 font-bold uppercase tracking-tight opacity-50 text-right ${isMe ? 'text-indigo-100' : 'text-gray-400'}`}>
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-5 bg-white/80 backdrop-blur-md border-t border-gray-100 flex items-center gap-4">
        <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
        <button 
          type="button" 
          onClick={() => fileInputRef.current?.click()}
          className="p-2.5 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
          title="Share File"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
        </button>
        <div className="flex-1 relative">
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Discuss concepts or share resources..."
            className="w-full bg-gray-50 border-transparent rounded-[1.5rem] px-6 py-4 text-sm focus:bg-white focus:ring-0 outline-none transition-all placeholder:text-gray-400 font-medium"
          />
        </div>
        <button 
          type="button" 
          onClick={toggleRecording}
          className={`p-3 rounded-2xl transition-all ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'text-gray-400 hover:text-indigo-600 hover:bg-gray-100'}`}
          title="Voice Note"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
        </button>
        <button 
          type="submit" 
          disabled={!inputText.trim() || isRecording}
          className="bg-indigo-600 text-white p-4 rounded-2xl hover:bg-indigo-700 disabled:opacity-50 disabled:grayscale shadow-lg shadow-indigo-100 transition-all active:scale-95"
        >
          <svg className="w-5 h-5 transform rotate-45" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
        </button>
      </form>
    </div>
  );
};

export default ChatView;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Group, Message, AppTab, SmartNote, VideoSession, ScheduledSession, StudyRoutine, Post } from './types';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VideoView from './components/VideoView';
import NotebookView from './components/NotebookView';
import ScheduleView from './components/ScheduleView';
import SARAPanel from './components/SARAPanel';
import Auth from './components/Auth';
import VideoCall from './components/VideoCall';
import Logo from './components/Logo';
import SettingsModal, { SettingsTab } from './components/SettingsModal';
import HomeView from './components/HomeView';
import SearchView from './components/SearchView';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.HOME);
  const [groups, setGroups] = useState<Group[]>([]);
  const [activeGroupId, setActiveGroupId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [notes, setNotes] = useState<SmartNote[]>([]);
  const [videos, setVideos] = useState<VideoSession[]>([]);
  const [scheduledSessions, setScheduledSessions] = useState<ScheduledSession[]>([]);
  const [studyRoutines, setStudyRoutines] = useState<StudyRoutine[]>([]);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isSARAOpen, setIsSARAOpen] = useState(false);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCalling, setIsCalling] = useState(false);

  // Modals state
  const [isGroupModalOpen, setIsGroupModalOpen] = useState<'create' | 'join' | null>(null);
  const [settingsModal, setSettingsModal] = useState<{ isOpen: boolean; tab: SettingsTab }>({ isOpen: false, tab: SettingsTab.PROFILE });
  const [groupInput, setGroupInput] = useState('');

  // Focus Alarm / Timer
  const [focusTimer, setFocusTimer] = useState<number | null>(null); 
  const [isTimerRunning, setIsTimerRunning] = useState(false);

  // Load Initial Data
  useEffect(() => {
    const savedUser = localStorage.getItem('kivia_current_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));

    setGroups(JSON.parse(localStorage.getItem('kivia_groups') || '[]'));
    setMessages(JSON.parse(localStorage.getItem('kivia_messages') || '[]'));
    setNotes(JSON.parse(localStorage.getItem('kivia_notes') || '[]'));
    setVideos(JSON.parse(localStorage.getItem('kivia_videos') || '[]'));
    setScheduledSessions(JSON.parse(localStorage.getItem('kivia_schedules') || '[]'));
    setStudyRoutines(JSON.parse(localStorage.getItem('kivia_routines') || '[]'));
    setAllUsers(JSON.parse(localStorage.getItem('kivia_users') || '[]'));
    setPosts(JSON.parse(localStorage.getItem('kivia_posts') || '[]'));

    handleHashRouting();
    window.addEventListener('hashchange', handleHashRouting);
    return () => window.removeEventListener('hashchange', handleHashRouting);
  }, []);

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('kivia_groups', JSON.stringify(groups));
    localStorage.setItem('kivia_messages', JSON.stringify(messages));
    localStorage.setItem('kivia_notes', JSON.stringify(notes));
    localStorage.setItem('kivia_videos', JSON.stringify(videos));
    localStorage.setItem('kivia_schedules', JSON.stringify(scheduledSessions));
    localStorage.setItem('kivia_routines', JSON.stringify(studyRoutines));
    localStorage.setItem('kivia_users', JSON.stringify(allUsers));
    localStorage.setItem('kivia_posts', JSON.stringify(posts));
    if (currentUser) localStorage.setItem('kivia_current_user', JSON.stringify(currentUser));
  }, [groups, messages, notes, videos, scheduledSessions, studyRoutines, allUsers, posts, currentUser]);

  // Focus Timer Tick
  useEffect(() => {
    let interval: any;
    if (isTimerRunning && focusTimer !== null && focusTimer > 0) {
      interval = setInterval(() => {
        setFocusTimer(prev => (prev !== null ? prev - 1 : 0));
      }, 1000);
    } else if (focusTimer === 0) {
      setIsTimerRunning(false);
      setFocusTimer(null);
      alert('Focus session complete! SARA recommends a 5-minute brain break.');
    }
    return () => clearInterval(interval);
  }, [isTimerRunning, focusTimer]);

  const handleHashRouting = () => {
    const hash = window.location.hash;
    if (hash.startsWith('#join-')) {
      const code = hash.replace('#join-', '');
      handleJoinByCode(code);
    } else if (hash.startsWith('#call-')) {
      if (!activeGroupId && groups.length > 0) {
        setActiveGroupId(groups[0].id);
      }
      setIsCalling(true);
      window.location.hash = ''; 
    }
  };

  const handleJoinByCode = (code: string) => {
    const cleanCode = code.trim();
    if (!cleanCode) return;
    const existing = groups.find(g => g.joinCode === cleanCode);
    if (existing) {
      setActiveGroupId(existing.id);
      setActiveTab(AppTab.CHAT);
      setIsGroupModalOpen(null);
      setGroupInput('');
      return;
    }
    const newGroup: Group = {
      id: Date.now().toString(),
      name: `Peer Session #${cleanCode.slice(-4)}`,
      joinCode: cleanCode,
      memberIds: [currentUser?.id || 'anon'],
      createdAt: new Date().toISOString(),
      lastMessage: 'You joined via a peer link'
    };
    setGroups(prev => [...prev, newGroup]);
    setActiveGroupId(newGroup.id);
    setActiveTab(AppTab.CHAT);
    setIsGroupModalOpen(null);
    setGroupInput('');
    window.location.hash = '';
  };

  const handleCreateGroup = () => {
    if (!groupInput.trim()) return;
    const joinCode = Math.floor(100000 + Math.random() * 900000).toString();
    const newGroup: Group = {
      id: Date.now().toString(),
      name: groupInput,
      joinCode,
      memberIds: [currentUser!.id],
      createdAt: new Date().toISOString(),
      lastMessage: 'Group created'
    };
    setGroups([...groups, newGroup]);
    setActiveGroupId(newGroup.id);
    setActiveTab(AppTab.CHAT);
    setIsGroupModalOpen(null);
    setGroupInput('');
  };

  const handleUpdateUser = (updatedUser: Partial<User>) => {
    if (!currentUser) return;
    const newUser = { ...currentUser, ...updatedUser };
    setCurrentUser(newUser);
    setAllUsers(allUsers.map(u => u.id === newUser.id ? newUser : u));
  };

  const handleUpdateGroup = (groupId: string, updatedGroup: Partial<Group>) => {
    setGroups(groups.map(g => g.id === groupId ? { ...g, ...updatedGroup } : g));
  };

  const handleDeleteGroup = (groupId: string) => {
    setGroups(groups.filter(g => g.id !== groupId));
    if (activeGroupId === groupId) {
      setActiveGroupId(null);
      setActiveTab(AppTab.HOME);
    }
  };

  const handleSendMessage = (text: string, type: Message['type'] = 'text', metadata: any = {}) => {
    const gid = metadata.groupId || activeGroupId;
    if (!gid) return;
    const newMessage: Message = {
      id: Date.now().toString(),
      senderId: currentUser!.id,
      senderName: currentUser!.name,
      text,
      timestamp: new Date().toISOString(),
      type,
      metadata: { ...metadata, groupId: gid }
    };
    setMessages(prev => [...prev, newMessage]);
    setGroups(prev => prev.map(g => g.id === gid ? { ...g, lastMessage: type === 'text' ? text : `[${type}]` } : g));
  };

  const handleSharePostToGroup = (post: Post, groupId: string) => {
    const group = groups.find(g => g.id === groupId);
    if (!group) return;

    let shareText = `Check out this breakthrough from @${post.authorName}: ${post.content}`;
    let preview = undefined;

    if (post.type !== 'text' && post.mediaUrl) {
      preview = {
        type: post.type as 'image' | 'video',
        url: post.mediaUrl,
        title: `Post by ${post.authorName}`
      };
    }

    handleSendMessage(shareText, 'text', { groupId, preview });
    alert(`Post shared to ${group.name}!`);
  };

  const handleAddPost = (content: string, type: 'text' | 'image' | 'video', mediaUrl?: string) => {
    const newPost: Post = {
      id: Date.now().toString(),
      authorId: currentUser!.id,
      authorName: currentUser!.name,
      authorAvatar: currentUser!.avatar,
      content,
      type,
      mediaUrl,
      timestamp: new Date().toISOString(),
      likes: []
    };
    setPosts([newPost, ...posts]);
  };

  const handleLikePost = (postId: string) => {
    setPosts(posts.map(p => {
      if (p.id === postId) {
        const hasLiked = p.likes.includes(currentUser!.id);
        return {
          ...p,
          likes: hasLiked ? p.likes.filter(id => id !== currentUser!.id) : [...p.likes, currentUser!.id]
        };
      }
      return p;
    }));
  };

  const formatTimer = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const setFocusAlarm = () => {
    const mins = prompt('How many minutes would you like to focus?', '25');
    if (mins) {
      setFocusTimer(parseInt(mins) * 60);
      setIsTimerRunning(true);
    }
  };

  const activeGroup = groups.find(g => g.id === activeGroupId) || null;
  const filteredMessages = messages.filter(m => m.metadata?.groupId === activeGroupId);

  if (!currentUser) {
    return <Auth onLogin={(user) => {
      setCurrentUser(user);
      localStorage.setItem('kivia_current_user', JSON.stringify(user));
    }} />;
  }

  return (
    <div className="flex h-screen bg-white font-['Inter'] selection:bg-indigo-100 selection:text-indigo-900 overflow-hidden">
      <div className="hidden md:block w-80 border-r border-gray-100 h-full overflow-hidden">
        <Sidebar 
          groups={groups} 
          activeGroupId={activeGroupId} 
          onGroupSelect={(id) => {
            setActiveGroupId(id);
            setActiveTab(AppTab.CHAT);
          }} 
          currentUser={currentUser}
          onLogout={() => { setCurrentUser(null); localStorage.removeItem('kivia_current_user'); }}
          onCreateGroup={() => setIsGroupModalOpen('create')}
          onProfileEdit={() => setSettingsModal({ isOpen: true, tab: SettingsTab.PROFILE })}
          onGroupSettings={() => setSettingsModal({ isOpen: true, tab: SettingsTab.GROUP })}
          onShareGroupLink={(g) => {
             const link = `${window.location.origin}${window.location.pathname}#join-${g.joinCode}`;
             navigator.clipboard.writeText(link);
             alert(`Join Link Copied: ${g.name}`);
          }}
        />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-white relative h-full">
        <header className="flex items-center justify-between px-8 py-5 border-b border-gray-100 glass sticky top-0 z-30 gap-6">
          <div className="flex items-center gap-5 flex-shrink-0">
            <Logo 
              className="w-10 h-10 shadow-lg shadow-green-100 rounded-full cursor-pointer hover:scale-110 transition-transform" 
              onClick={() => {
                setActiveGroupId(null);
                setActiveTab(AppTab.HOME);
              }} 
            />
            <div className="flex flex-col">
              <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none mb-1">KIVIA</h1>
              <div className="flex items-center gap-2">
                {activeGroup ? (
                  <div className="flex items-center gap-2 group cursor-pointer" onClick={() => { setActiveTab(AppTab.CHAT); }}>
                    <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest truncate max-w-[120px]">{activeGroup.name}</span>
                    <span className="text-[9px] font-bold text-gray-300 bg-gray-50 px-1.5 py-0.5 rounded border border-gray-100">ID: {activeGroup.joinCode}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setIsCalling(true); }}
                      className="ml-1 p-1 bg-green-50 text-green-600 rounded-md hover:bg-green-600 hover:text-white transition-all shadow-sm"
                      title="Start Session"
                    >
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                    </button>
                  </div>
                ) : (
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Community Pulse</span>
                )}
              </div>
            </div>
          </div>

          <div className="flex-1 max-w-sm relative mx-4 hidden lg:block">
            <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none text-gray-400">
              <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
            <input 
              type="text" 
              placeholder="Search peers, messages, notes..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-gray-50 border border-transparent rounded-[1.5rem] pl-14 pr-6 py-2.5 text-sm focus:bg-white focus:border-indigo-100 outline-none transition-all font-medium"
            />
          </div>

          <div className="flex items-center gap-4">
            {focusTimer !== null && (
              <div className="flex items-center gap-3 bg-red-50 text-red-600 px-4 py-2 rounded-2xl border border-red-100 animate-pulse shadow-sm">
                <span className="text-xs font-black tracking-widest">{formatTimer(focusTimer)}</span>
                <button onClick={() => setIsTimerRunning(!isTimerRunning)} className="hover:scale-110 transition-transform">
                  {isTimerRunning ? <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" /></svg> : <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" /></svg>}
                </button>
              </div>
            )}

            {!focusTimer && (
              <button onClick={setFocusAlarm} className="p-2.5 bg-gray-50 text-gray-400 hover:text-indigo-600 rounded-xl transition-all border border-transparent hover:border-indigo-50" title="Start Focus Timer">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
              </button>
            )}

            <nav className="flex bg-gray-100/50 p-1 rounded-[1.25rem] border border-gray-100 shadow-inner">
              {[
                { id: AppTab.HOME, icon: <path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />, hideIfNoGroup: false },
                { id: AppTab.CHAT, icon: <path d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />, hideIfNoGroup: true },
                { id: AppTab.VIDEO, icon: <path d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />, hideIfNoGroup: true },
                { id: AppTab.NOTEBOOK, icon: <path d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />, hideIfNoGroup: true },
                { id: AppTab.SCHEDULE, icon: <path d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />, hideIfNoGroup: true },
              ].map(tab => (
                (!tab.hideIfNoGroup || activeGroupId) && (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as AppTab)}
                    className={`p-2.5 rounded-xl transition-all ${activeTab === tab.id ? 'bg-white text-indigo-600 shadow-md' : 'text-gray-400 hover:text-gray-600'}`}
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}>{tab.icon}</svg>
                  </button>
                )
              ))}
            </nav>

            <button 
              onClick={() => setIsSARAOpen(!isSARAOpen)}
              className={`p-3 rounded-full transition-all duration-300 flex items-center gap-2 border ${isSARAOpen ? 'bg-indigo-600 text-white border-indigo-500 shadow-xl' : 'bg-white text-gray-500 hover:bg-gray-50 border-gray-100 shadow-sm'}`}
            >
              <div className="relative flex h-3 w-3">
                <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${isSARAOpen ? 'bg-white' : 'bg-indigo-400'}`}></span>
                <span className={`relative inline-flex rounded-full h-3 w-3 ${isSARAOpen ? 'bg-white' : 'bg-indigo-50'}`}></span>
              </div>
              <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">SARA</span>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-hidden relative">
          {searchQuery ? (
            <SearchView 
              query={searchQuery}
              users={allUsers}
              messages={messages}
              notes={notes}
              videos={videos}
              groups={groups}
              onNavigate={(gid, tab) => {
                setActiveGroupId(gid);
                setActiveTab(tab);
                setSearchQuery('');
              }}
              onClose={() => setSearchQuery('')}
            />
          ) : activeTab === AppTab.HOME ? (
            <HomeView 
              currentUser={currentUser} 
              posts={posts} 
              groups={groups}
              onAddPost={handleAddPost} 
              onLikePost={handleLikePost} 
              onSharePostToGroup={handleSharePostToGroup}
            />
          ) : !activeGroupId ? (
            <div className="h-full flex flex-col items-center justify-center p-8 text-center bg-[#F9FBEC]/10 animate-in zoom-in-95 duration-1000">
              <Logo className="w-32 h-32 mb-10 shadow-[0_40px_80px_-15px_rgba(162,209,73,0.3)] rounded-full bg-white p-4" />
              <h2 className="text-4xl font-black text-gray-900 mb-4 tracking-tight leading-tight">Your Academic Hub,<br/>Amplified by AI.</h2>
              <p className="text-gray-500 max-w-md font-medium text-lg mb-12">Connect with peers, organize your schedule, and let SARA synthesize your learning journey.</p>
              <div className="flex flex-wrap justify-center gap-4">
                <button 
                  onClick={() => setIsGroupModalOpen('create')} 
                  className="bg-indigo-600 text-white px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-100 hover:bg-indigo-700 hover:scale-105 transition-all"
                >
                  Create Study Group
                </button>
                <button 
                  onClick={() => setSettingsModal({ isOpen: true, tab: SettingsTab.JOIN })} 
                  className="bg-white border-2 border-gray-100 text-gray-600 px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:border-indigo-100 hover:text-indigo-600 transition-all"
                >
                  Join Session
                </button>
              </div>
            </div>
          ) : (
            <div className="h-full">
              {activeTab === AppTab.CHAT && <ChatView currentUser={currentUser} messages={filteredMessages} onSendMessage={handleSendMessage} allUsers={allUsers} activeGroup={activeGroup} />}
              {activeTab === AppTab.VIDEO && <VideoView videos={videos.filter(v => v.groupId === activeGroupId)} onAddVideo={(t, u) => setVideos([...videos, { id: Date.now().toString(), groupId: activeGroupId, title: t, url: u, thumbnail: `https://picsum.photos/seed/${Date.now()}/400/225`, duration: '0:00', recordedAt: new Date().toISOString() }])} />}
              {activeTab === AppTab.NOTEBOOK && <NotebookView notes={notes.filter(n => n.groupId === activeGroupId)} />}
              {activeTab === AppTab.SCHEDULE && (
                <ScheduleView 
                  groupId={activeGroupId} 
                  sessions={scheduledSessions.filter(s => s.groupId === activeGroupId)} 
                  routines={studyRoutines.filter(r => r.groupId === activeGroupId)}
                  onAddSession={(s) => setScheduledSessions([...scheduledSessions, { ...s, id: Date.now().toString(), groupId: activeGroupId }])}
                  onAddRoutine={(r) => setStudyRoutines([...studyRoutines, { ...r, id: Date.now().toString(), groupId: activeGroupId }])}
                  onRemoveSession={(id) => setScheduledSessions(scheduledSessions.filter(s => s.id !== id))}
                  onRemoveRoutine={(id) => setStudyRoutines(studyRoutines.filter(r => r.id !== id))}
                />
              )}
            </div>
          )}

          {isSARAOpen && activeGroupId && (
            <div className="absolute right-0 top-0 bottom-0 w-full sm:w-[400px] bg-white border-l border-gray-100 transform transition-all duration-500 shadow-2xl z-50 animate-in slide-in-from-right-full">
              <SARAPanel 
                onClose={() => setIsSARAOpen(false)} 
                messages={filteredMessages} 
                notes={notes.filter(n => n.groupId === activeGroupId)} 
                videos={videos.filter(v => v.groupId === activeGroupId)}
                onAiResponse={(msg) => handleSendMessage(msg.text, 'ai')}
                onNewNote={(note) => setNotes([...notes, { ...note, groupId: activeGroupId || '' }])}
                activeGroupId={activeGroupId || ''}
              />
            </div>
          )}
        </div>
      </main>

      {/* Unified Settings Modal */}
      {settingsModal.isOpen && (
        <SettingsModal 
          user={currentUser}
          activeGroup={activeGroup}
          initialTab={settingsModal.tab}
          onClose={() => setSettingsModal({ ...settingsModal, isOpen: false })}
          onUpdateUser={handleUpdateUser}
          onUpdateGroup={(updated) => activeGroup && handleUpdateGroup(activeGroup.id, updated)}
          onDeleteGroup={() => activeGroup && handleDeleteGroup(activeGroup.id)}
          onJoinGroup={handleJoinByCode}
        />
      )}

      {/* Group Create Modal */}
      {isGroupModalOpen === 'create' && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-start mb-8">
              <div className="flex items-center gap-4">
                <Logo className="w-12 h-12" />
                <div>
                  <h2 className="text-2xl font-black text-gray-900 tracking-tight">Build a Squad</h2>
                  <p className="text-sm text-gray-500 font-medium">Start a fresh collaborative space.</p>
                </div>
              </div>
              <button onClick={() => setIsGroupModalOpen(null)} className="p-2 text-gray-400 hover:text-gray-900 transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 ml-1">Study Group Name</label>
                <input 
                  autoFocus
                  type="text"
                  value={groupInput}
                  onChange={(e) => setGroupInput(e.target.value)}
                  placeholder="e.g. Bio 101 Finals Prep"
                  onKeyPress={(e) => e.key === 'Enter' && handleCreateGroup()}
                  className="w-full bg-gray-50 border-transparent rounded-2xl px-6 py-4 text-sm focus:bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-100 outline-none transition-all font-medium"
                />
              </div>
              <button onClick={handleCreateGroup} disabled={!groupInput.trim()} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">Create Space</button>
            </div>
          </div>
        </div>
      )}

      {isCalling && activeGroup && (
        <VideoCall 
          onClose={() => setIsCalling(false)} 
          currentUser={currentUser} 
          activeGroup={activeGroup}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Post, User, Group } from '../types';
import Logo from './Logo';

interface HomeViewProps {
  currentUser: User;
  posts: Post[];
  groups: Group[];
  onAddPost: (content: string, type: 'text' | 'image' | 'video', mediaUrl?: string) => void;
  onLikePost: (postId: string) => void;
  onSharePostToGroup: (post: Post, groupId: string) => void;
}

const HomeView: React.FC<HomeViewProps> = ({ currentUser, posts, groups, onAddPost, onLikePost, onSharePostToGroup }) => {
  const [newPostContent, setNewPostContent] = useState('');
  const [mediaPreview, setMediaPreview] = useState<string | null>(null);
  const [postType, setPostType] = useState<'text' | 'image' | 'video'>('text');
  const [showPublisher, setShowPublisher] = useState(false);
  const [sharingPost, setSharingPost] = useState<Post | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'image' | 'video') => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setMediaPreview(url);
      setPostType(type);
    }
  };

  const handlePublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPostContent.trim() && !mediaPreview) return;
    onAddPost(newPostContent, postType, mediaPreview || undefined);
    setNewPostContent('');
    setMediaPreview(null);
    setPostType('text');
    setShowPublisher(false);
  };

  const clearMedia = () => {
    setMediaPreview(null);
    setPostType('text');
  };

  const handleExternalShare = async (post: Post) => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Breakthrough from @${post.authorName} | KIVIA`,
          text: post.content,
          url: window.location.href,
        });
      } catch (err) {
        console.error('Error sharing:', err);
      }
    } else {
      navigator.clipboard.writeText(`${post.content} - Sent via KIVIA`);
      alert('Link copied to clipboard!');
    }
  };

  return (
    <div className="h-full overflow-y-auto bg-gray-50/20 p-8 flex flex-col items-center relative">
      <div className="w-full max-w-2xl space-y-10">
        {/* Welcome Header */}
        <div className="space-y-2">
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">Study Community</h2>
          <p className="text-gray-500 font-medium">What's the breakthrough today, <span className="text-indigo-600">@{currentUser.name}</span>?</p>
        </div>

        {/* Post Creator */}
        <div className="bg-white rounded-[2.5rem] p-6 shadow-xl shadow-gray-200/50 border border-gray-100 transition-all">
          {!showPublisher ? (
            <div className="flex items-center gap-4 cursor-pointer" onClick={() => setShowPublisher(true)}>
              <img src={currentUser.avatar} className="w-10 h-10 rounded-full bg-gray-50" />
              <div className="flex-1 bg-gray-50 hover:bg-gray-100 rounded-2xl px-6 py-3 text-gray-400 text-sm font-medium transition-colors">
                Share a study tip, image, or video...
              </div>
            </div>
          ) : (
            <form onSubmit={handlePublish} className="space-y-6 animate-in fade-in duration-300">
              <textarea 
                autoFocus
                value={newPostContent}
                onChange={e => setNewPostContent(e.target.value)}
                placeholder="Break down a concept or share progress..."
                className="w-full bg-transparent border-none focus:ring-0 text-gray-800 placeholder:text-gray-300 font-medium resize-none text-lg min-h-[100px] outline-none shadow-none"
              />

              {mediaPreview && (
                <div className="relative group rounded-3xl overflow-hidden border border-gray-100">
                  {postType === 'image' ? (
                    <img src={mediaPreview} className="w-full h-auto max-h-[300px] object-cover" />
                  ) : (
                    <video src={mediaPreview} className="w-full h-auto max-h-[300px] object-cover" controls />
                  )}
                  <button 
                    type="button" 
                    onClick={clearMedia}
                    className="absolute top-4 right-4 bg-black/60 text-white p-2 rounded-full hover:bg-red-500 transition-colors"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
              )}

              <div className="pt-4 border-t border-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                   <input 
                    type="file" 
                    accept="image/*" 
                    className="hidden" 
                    ref={fileInputRef} 
                    onChange={(e) => handleFileChange(e, 'image')}
                   />
                   <button 
                    type="button" 
                    onClick={() => fileInputRef.current?.click()}
                    className="p-3 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
                    title="Upload Image"
                   >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                   </button>

                   <input 
                    type="file" 
                    accept="video/*" 
                    className="hidden" 
                    id="video-upload" 
                    onChange={(e) => handleFileChange(e, 'video')}
                   />
                   <label 
                    htmlFor="video-upload"
                    className="p-3 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all cursor-pointer"
                    title="Upload Video"
                   >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                   </label>
                </div>

                <div className="flex gap-3 items-center">
                  <button type="button" onClick={() => setShowPublisher(false)} className="text-xs font-black text-gray-400 uppercase tracking-widest px-4 hover:text-gray-600">Cancel</button>
                  <button 
                    type="submit" 
                    disabled={!newPostContent.trim() && !mediaPreview}
                    className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all disabled:opacity-50"
                  >
                    Publish
                  </button>
                </div>
              </div>
            </form>
          )}
        </div>

        {/* Feed List */}
        <div className="space-y-8 pb-20">
          {posts.length === 0 ? (
            <div className="text-center py-20 opacity-30 flex flex-col items-center">
              <Logo className="w-16 h-16 mb-4 grayscale" />
              <p className="font-bold">The feed is quiet. Start the conversation!</p>
            </div>
          ) : (
            posts.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()).map(post => (
              <div key={post.id} className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-gray-100 space-y-6 hover:shadow-lg transition-all group animate-in slide-in-from-bottom-4 duration-500">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <img src={post.authorAvatar} className="w-12 h-12 rounded-full border border-gray-50" />
                    <div>
                      <h4 className="font-black text-gray-900 leading-none mb-1">@{post.authorName}</h4>
                      <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">
                        {new Date(post.timestamp).toLocaleDateString()}
                      </p>
                    </div>
                  </div>
                  <Logo className="w-6 h-6 opacity-20 group-hover:opacity-100 transition-opacity" />
                </div>

                {post.content && <p className="text-gray-800 font-medium leading-relaxed text-lg">{post.content}</p>}

                {post.type === 'image' && post.mediaUrl && (
                  <div className="rounded-[2rem] overflow-hidden border border-gray-50 bg-gray-50">
                    <img src={post.mediaUrl} className="w-full h-auto max-h-[500px] object-cover" />
                  </div>
                )}

                {post.type === 'video' && post.mediaUrl && (
                  <div className="rounded-[2rem] overflow-hidden border border-gray-50 bg-black aspect-video flex items-center justify-center">
                    {post.mediaUrl.startsWith('blob:') ? (
                      <video src={post.mediaUrl} className="w-full h-full" controls />
                    ) : (
                      <iframe 
                        src={post.mediaUrl.replace('watch?v=', 'embed/')} 
                        className="w-full h-full"
                        allowFullScreen
                      ></iframe>
                    )}
                  </div>
                )}

                <div className="flex items-center gap-6 pt-4 border-t border-gray-50">
                  <button 
                    onClick={() => onLikePost(post.id)}
                    className={`flex items-center gap-2 group/btn transition-colors ${post.likes.includes(currentUser.id) ? 'text-red-500' : 'text-gray-400 hover:text-red-500'}`}
                  >
                    <svg className={`w-6 h-6 ${post.likes.includes(currentUser.id) ? 'fill-current' : 'fill-none group-hover/btn:fill-current'}`} stroke="currentColor" strokeWidth={2.5} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
                    <span className="text-xs font-black uppercase tracking-widest">{post.likes.length}</span>
                  </button>
                  <button 
                    onClick={() => setSharingPost(post)}
                    className="flex items-center gap-2 text-gray-400 hover:text-indigo-600 transition-colors"
                  >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" strokeWidth={2.5} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
                    <span className="text-xs font-black uppercase tracking-widest">Share</span>
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {/* Share Modal */}
      {sharingPost && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
