                  <p className="text-sm text-gray-500 italic">No groups available to share.</p>
                ) : (
                  <div className="space-y-2">
                    {groups.map(group => (
                      <button 
                        key={group.id} 
                        onClick={() => {
                          onSharePostToGroup(sharingPost, group.id);
                          setSharingPost(null);
                        }}
