      </div>

      <div className="flex-1 overflow-y-auto px-4 py-6 space-y-8">
        {/* Global Navigation */}
        <section className="space-y-1">
          <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-4 mb-3">Workspace</h2>
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
                activeTab === item.id 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' 
                  : 'text-gray-500 hover:bg-white hover:text-indigo-600'
              }`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}>{item.icon}</svg>
              {item.label}
            </button>
          ))}
        </section>

        {/* Group Specific Navigation */}
        {activeGroupId && (
          <section className="space-y-1">
            <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-4 mb-3">Active Session</h2>
            {groupSpecificItems.map(item => (
              <button
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
                  activeTab === item.id 
                    ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' 
                    : 'text-gray-500 hover:bg-white hover:text-indigo-600'
