          </section>
        </div>

        {/* Alerts Settings Section */}
        <section className="bg-white rounded-[3rem] p-10 border border-gray-100 space-y-8">
           <div className="flex items-center gap-4">
              <div className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round"/></svg>
              </div>
              <div>
                <h3 className="text-xl font-black text-gray-900 tracking-tight">Focus Alerts & Nudges</h3>
                <p className="text-sm text-gray-500 font-medium">Let SARA keep you on track during long study sprints.</p>
              </div>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {[
                { title: 'Break Reminders', desc: 'Alert every 45 mins to stretch.', color: 'bg-green-500' },
                { title: 'Hydration Nudges', desc: 'SARA reminds you to drink water.', color: 'bg-blue-500' },
                { title: 'Session Proximity', desc: 'Alerts 5 mins before a group call.', color: 'bg-indigo-500' }
              ].map(item => (
