import React, { useState } from 'react';
import { Alarm, PlannerTask } from '../types';
import Logo from './Logo';

interface PlannerViewProps {
  alarms: Alarm[];
  tasks: PlannerTask[];
  onAddAlarm: (alarm: Omit<Alarm, 'id'>) => void;
  onToggleAlarm: (id: string) => void;
  onDeleteAlarm: (id: string) => void;
  onAddTask: (task: Omit<PlannerTask, 'id'>) => void;
  onDeleteTask: (id: string) => void;
  onBack: () => void;
}

const PlannerView: React.FC<PlannerViewProps> = ({
  alarms,
  tasks,
  onAddAlarm,
  onToggleAlarm,
  onDeleteAlarm,
  onAddTask,
  onDeleteTask,
  onBack
}) => {
  const [showAddAlarm, setShowAddAlarm] = useState(false);
  const [showAddTask, setShowAddTask] = useState(false);

  // Alarm Form
  const [alarmTime, setAlarmTime] = useState('08:00');
  const [alarmLabel, setAlarmLabel] = useState('');
  const [alarmDays, setAlarmDays] = useState<number[]>([]);

  // Task Form
  const [taskTitle, setTaskTitle] = useState('');
  const [taskDay, setTaskDay] = useState(1);
  const [taskTime, setTaskTime] = useState('09:00');
  const [taskCategory, setTaskCategory] = useState<'study' | 'break' | 'review'>('study');

  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

  const toggleDay = (dayIndex: number) => {
    setAlarmDays(prev => 
      prev.includes(dayIndex) ? prev.filter(d => d !== dayIndex) : [...prev, dayIndex]
    );
  };

  const handleAddAlarm = (e: React.FormEvent) => {
    e.preventDefault();
    onAddAlarm({ time: alarmTime, label: alarmLabel || 'Alarm', isEnabled: true, days: alarmDays });
    setAlarmLabel('');
    setAlarmDays([]);
    setShowAddAlarm(false);
  };

  const handleAddTask = (e: React.FormEvent) => {
    e.preventDefault();
    onAddTask({ title: taskTitle, day: taskDay, time: taskTime, category: taskCategory });
    setTaskTitle('');
    setShowAddTask(false);
  };

  return (
    <div className="h-full overflow-y-auto bg-gray-50/20 p-8 flex flex-col items-center">
      <div className="w-full max-w-5xl space-y-12 pb-20">

        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-3 bg-white hover:bg-gray-100 rounded-2xl shadow-sm border border-gray-100 transition-all text-gray-400 hover:text-indigo-600">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
            </button>
            <div>
              <h2 className="text-3xl font-black text-gray-900 tracking-tight">Study Planner & Alarms</h2>
              <p className="text-gray-500 font-medium">Structure your day and never miss a peer breakthrough.</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowAddAlarm(true)}
              className="px-6 py-3 bg-white border-2 border-gray-100 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:border-indigo-100 hover:text-indigo-600 transition-all shadow-sm"
            >
              Add Alarm
            </button>
            <button 
              onClick={() => setShowAddTask(true)}
              className="px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all"
            >
              New Task
            </button>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">

          {/* Alarms Column */}
          <section className="lg:col-span-1 space-y-6">
            <div className="flex items-center gap-3 px-2">
              <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
              <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Active Alarms</h3>
            </div>

            {showAddAlarm && (
              <form onSubmit={handleAddAlarm} className="bg-white p-6 rounded-[2rem] shadow-xl border border-gray-100 animate-in slide-in-from-top-4 space-y-4">
                <input 
                  type="time" 
                  value={alarmTime}
                  onChange={e => setAlarmTime(e.target.value)}
                  className="w-full text-4xl font-black text-center bg-gray-50 rounded-2xl p-4 focus:bg-white outline-none border border-transparent focus:border-indigo-100 transition-all"
                />
                <input 
                  type="text" 
                  placeholder="Alarm label..."
                  value={alarmLabel}
                  onChange={e => setAlarmLabel(e.target.value)}
                  className="w-full bg-gray-50 rounded-xl px-4 py-3 text-sm font-medium focus:bg-white outline-none border border-transparent focus:border-indigo-100 transition-all"
                />
                <div className="flex justify-between">
                  {days.map((d, i) => (
                    <button 
                      key={d} 
                      type="button"
                      onClick={() => toggleDay(i)}
                      className={`w-8 h-8 rounded-full text-[9px] font-black flex items-center justify-center transition-all ${alarmDays.includes(i) ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-400'}`}
                    >
                      {d[0]}
                    </button>
                  ))}
                </div>
                <div className="flex gap-2 pt-2">
                  <button type="button" onClick={() => setShowAddAlarm(false)} className="flex-1 py-3 text-[10px] font-black text-gray-400 uppercase">Cancel</button>
                  <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase shadow-lg shadow-indigo-100">Set</button>
                </div>
              </form>
            )}

            <div className="space-y-4">
              {alarms.length === 0 ? (
                <div className="p-10 text-center border-2 border-dashed border-gray-100 rounded-[2.5rem]">
                  <p className="text-xs text-gray-300 font-bold uppercase tracking-widest">No Alarms</p>
                </div>
              ) : (
                alarms.map(alarm => (
                  <div key={alarm.id} className={`p-6 rounded-[2rem] border transition-all ${alarm.isEnabled ? 'bg-white border-gray-100 shadow-sm' : 'bg-gray-50/50 border-transparent opacity-60'}`}>
                    <div className="flex items-center justify-between mb-4">
                      <div>
                        <p className="text-3xl font-black text-gray-900 leading-none">{alarm.time}</p>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">{alarm.label}</p>
                      </div>
                      <button 
                        onClick={() => onToggleAlarm(alarm.id)}
                        className={`w-12 h-6 rounded-full relative transition-colors ${alarm.isEnabled ? 'bg-indigo-600' : 'bg-gray-300'}`}
                      >
                        <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${alarm.isEnabled ? 'right-1' : 'left-1'}`}></div>
                      </button>
                    </div>
                    <div className="flex gap-1.5 items-center">
                      <div className="flex-1 flex gap-1">
                        {days.map((d, i) => (
                          <span key={d} className={`text-[8px] font-black ${alarm.days.includes(i) ? 'text-indigo-600' : 'text-gray-300'}`}>{d[0]}</span>
                        ))}
                      </div>
                      <button onClick={() => onDeleteAlarm(alarm.id)} className="p-1 text-gray-300 hover:text-red-500">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round"/></svg>
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </section>

          {/* Schedule Column */}
          <section className="lg:col-span-2 space-y-6">
            <div className="flex items-center justify-between px-2">
              <div className="flex items-center gap-3">
                <div className="w-2 h-2 bg-green-500 rounded-full"></div>
                <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Weekly Study Grid</h3>
              </div>
              <Logo className="w-6 h-6 opacity-20" />
            </div>

            {showAddTask && (
              <form onSubmit={handleAddTask} className="bg-white p-8 rounded-[2.5rem] shadow-xl border border-gray-100 animate-in slide-in-from-top-4 space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Focus Activity</label>
                    <input 
                      required 
                      value={taskTitle} 
                      onChange={e => setTaskTitle(e.target.value)} 
                      placeholder="e.g. Physics Synthesis" 
                      className="w-full bg-gray-50 rounded-xl px-5 py-3 text-sm focus:bg-white outline-none border border-transparent focus:border-indigo-100 transition-all"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Day of Week</label>
                    <select 
                      value={taskDay} 
                      onChange={e => setTaskDay(parseInt(e.target.value))}
                      className="w-full bg-gray-50 rounded-xl px-5 py-3 text-sm focus:bg-white outline-none border border-transparent focus:border-indigo-100 transition-all"
                    >
                      {days.map((d, i) => <option key={d} value={i}>{d}</option>)}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Time</label>
                    <input 
                      type="time" 
                      value={taskTime} 
                      onChange={e => setTaskTime(e.target.value)}
                      className="w-full bg-gray-50 rounded-xl px-5 py-3 text-sm focus:bg-white outline-none border border-transparent focus:border-indigo-100 transition-all"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Category</label>
                    <div className="flex gap-2">
                      {(['study', 'break', 'review'] as const).map(cat => (
                        <button 
                          key={cat}
                          type="button"
                          onClick={() => setTaskCategory(cat)}
                          className={`flex-1 py-2 text-[9px] font-black uppercase rounded-lg border transition-all ${taskCategory === cat ? 'bg-indigo-600 text-white border-indigo-600 shadow-md' : 'bg-white text-gray-400 border-gray-100 hover:border-indigo-100'}`}
                        >
                          {cat}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
                <div className="flex justify-end gap-3">
                  <button type="button" onClick={() => setShowAddTask(false)} className="px-6 py-2 text-xs font-black uppercase text-gray-400">Cancel</button>
                  <button type="submit" className="bg-indigo-600 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase shadow-xl shadow-indigo-100">Schedule Task</button>
                </div>
              </form>
            )}

            <div className="grid grid-cols-1 md:grid-cols-7 gap-4">
              {days.map((day, idx) => (
                <div key={day} className="space-y-3">
                  <div className="text-center py-2 bg-gray-100/50 rounded-xl">
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{day}</span>
                  </div>
                  <div className="space-y-2">
                    {tasks.filter(t => t.day === idx).sort((a,b) => a.time.localeCompare(b.time)).map(task => (
                      <div key={task.id} className="relative group/task p-3 bg-white border border-gray-100 rounded-2xl shadow-sm hover:shadow-md transition-all">
                        <button 
                          onClick={() => onDeleteTask(task.id)}
                          className="absolute -top-1 -right-1 p-1 bg-red-500 text-white rounded-full opacity-0 group-hover/task:opacity-100 transition-all scale-75"
