import React, { useState, useMemo } from 'react';
import { Group, Message } from '../types';
import Logo from './Logo';

interface GroupDetailSettingsProps {
  group: Group;
  messages: Message[];
  onUpdateGroup: (updated: Partial<Group>) => void;
  onClearChat: () => void;
  onExitGroup: () => void;
  onDeleteGroup: () => void;
  onBack: () => void;
}

const GroupDetailSettings: React.FC<GroupDetailSettingsProps> = ({
  group,
  messages,
  onUpdateGroup,
  onClearChat,
  onExitGroup,
  onDeleteGroup,
  onBack
}) => {
  const [name, setName] = useState(group.name);
  const [activeSubTab, setActiveSubTab] = useState<'info' | 'media' | 'actions'>('info');

  const mediaMessages = useMemo(() => {
    return messages.filter(m => 
      m.type === 'file' || 
      (m.metadata?.preview && (m.metadata.preview.type === 'image' || m.metadata.preview.type === 'video'))
    );
  }, [messages]);

  const handleUpdateName = () => {
    if (name.trim() && name !== group.name) {
      onUpdateGroup({ name });
      alert("Group name updated!");
    }
  };

  const handleRegenerateCode = () => {
    const newCode = Math.floor(100000 + Math.random() * 900000).toString();
    onUpdateGroup({ joinCode: newCode });
    alert(`New Join Code generated: ${newCode}`);
  };

  return (
    <div className="h-full flex flex-col bg-gray-50/20 overflow-hidden">
      {/* Header */}
      <div className="p-8 border-b border-gray-100 bg-white flex items-center justify-between z-10">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-3 bg-white hover:bg-gray-100 rounded-2xl shadow-sm border border-gray-100 transition-all text-gray-400 hover:text-indigo-600">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
          </button>
          <div>
            <div className="flex items-center gap-2 mb-1">
              <span className="w-2 h-2 bg-indigo-500 rounded-full"></span>
              <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Management</span>
            </div>
            <h2 className="text-3xl font-black text-gray-900 tracking-tight">{group.name} Settings</h2>
          </div>
        </div>
        <Logo className="w-12 h-12 opacity-80" />
      </div>

      {/* Sub Navigation */}
      <div className="px-8 pt-4 bg-white border-b border-gray-100 flex gap-8">
        {[
          { id: 'info', label: 'Group Info' },
          { id: 'media', label: `Media (${mediaMessages.length})` },
          { id: 'actions', label: 'Actions' }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`pb-4 text-xs font-black uppercase tracking-widest transition-all relative ${
              activeSubTab === tab.id ? 'text-indigo-600' : 'text-gray-400 hover:text-gray-600'
            }`}
          >
            {tab.label}
            {activeSubTab === tab.id && <div className="absolute bottom-0 left-0 right-0 h-1 bg-indigo-600 rounded-t-full"></div>}
          </button>
        ))}
      </div>

      {/* Scrollable Content */}
      <div className="flex-1 overflow-y-auto p-8 flex flex-col items-center">
        <div className="w-full max-w-2xl space-y-8">

          {activeSubTab === 'info' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-300">
              <section className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm space-y-6">
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Study Group Name</label>
                  <div className="flex gap-3">
                    <input 
                      type="text" 
                      value={name}
                      onChange={e => setName(e.target.value)}
                      className="flex-1 bg-gray-50 border-transparent rounded-2xl px-6 py-4 text-sm font-medium focus:bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-100 outline-none transition-all"
                    />
                    <button 
                      onClick={handleUpdateName}
                      className="bg-indigo-600 text-white px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-indigo-100"
                    >
                      Save
                    </button>
                  </div>
                </div>

                <div className="p-6 bg-gray-50 rounded-[2rem] border border-gray-100">
                  <div className="flex justify-between items-center">
                    <div>
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Access Code</p>
                      <p className="text-3xl font-black text-indigo-600 tracking-[0.2em]">{group.joinCode}</p>
                    </div>
                    <button 
                      onClick={handleRegenerateCode}
                      className="p-3 bg-white text-gray-400 hover:text-indigo-600 rounded-xl shadow-sm border border-transparent hover:border-indigo-100 transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                    </button>
                  </div>
                </div>

                <div>
                   <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Member Count</p>
                   <div className="flex items-center gap-2">
                     <span className="text-lg font-black text-gray-900">{group.memberIds.length}</span>
                     <span className="text-xs font-bold text-gray-400">Collaborators in this space</span>
                   </div>
                </div>
              </section>
            </div>
          )}

          {activeSubTab === 'media' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
              {mediaMessages.length === 0 ? (
                <div className="bg-white p-12 rounded-[2.5rem] border border-dashed border-gray-200 text-center flex flex-col items-center">
                   <div className="w-16 h-16 bg-gray-50 rounded-2xl flex items-center justify-center text-gray-300 mb-4">
                     <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                   </div>
                   <p className="font-bold text-gray-400">No media shared yet.</p>
                </div>
              ) : (
                <div className="grid grid-cols-2 md:grid-cols-3 gap-4 pb-20">
                  {mediaMessages.map(m => {
                    const url = m.metadata?.fileUrl || m.metadata?.preview?.url;
                    const type = m.metadata?.preview?.type || 'file';

                    return (
                      <div key={m.id} className="aspect-square bg-gray-100 rounded-[1.5rem] overflow-hidden group relative border border-gray-100">
                        {type === 'image' ? (
                          <img src={url} className="w-full h-full object-cover group-hover:scale-110 transition-transform" />
                        ) : type === 'video' ? (
                          <div className="w-full h-full flex items-center justify-center bg-black">
                            <svg className="w-8 h-8 text-white opacity-40" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" /></svg>
                          </div>
                        ) : (
                          <div className="w-full h-full flex items-center justify-center">
                            <svg className="w-8 h-8 text-indigo-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
                          </div>
                        )}
                        <div className="absolute inset-0 bg-indigo-900/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center p-4">
                          <p className="text-[9px] font-black text-white uppercase tracking-widest text-center truncate">{m.metadata?.fileName || 'Media'}</p>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {activeSubTab === 'actions' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
               <section className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm space-y-6">
                 <div className="flex items-center justify-between p-4 bg-orange-50/50 rounded-2xl border border-orange-100">
                    <div>
                      <p className="font-black text-orange-900 text-sm">Clear Conversation</p>
                      <p className="text-[10px] text-orange-600 font-medium">Remove all messages in this group for yourself.</p>
                    </div>
                    <button 
                      onClick={() => { if(confirm("Are you sure? This cannot be undone.")) onClearChat(); }}
                      className="px-4 py-2 bg-orange-600 text-white rounded-xl text-[10px] font-black uppercase shadow-lg shadow-orange-200"
                    >
                      Clear
                    </button>
                 </div>

                 <div className="flex items-center justify-between p-4 bg-red-50/50 rounded-2xl border border-red-100">
                    <div>
                      <p className="font-black text-red-900 text-sm">Leave Study Squad</p>
                      <p className="text-[10px] text-red-600 font-medium">You will no longer receive updates from this group.</p>
                    </div>
                    <button 
                      onClick={() => { if(confirm("Leave this group?")) onExitGroup(); }}
                      className="px-4 py-2 bg-red-600 text-white rounded-xl text-[10px] font-black uppercase shadow-lg shadow-red-200"
                    >
                      Exit
                    </button>
                 </div>

                 <div className="flex items-center justify-between p-4 bg-gray-900 rounded-2xl shadow-xl">
                    <div>
                      <p className="font-black text-white text-sm">Permanently Delete</p>
                      <p className="text-[10px] text-gray-400 font-medium">Delete group and all its data for everyone.</p>
                    </div>
                    <button 
                      onClick={() => { if(confirm("FINAL WARNING: Delete this group permanently?")) onDeleteGroup(); }}
                      className="px-4 py-2 bg-white text-gray-900 rounded-xl text-[10px] font-black uppercase"
                    >
                      Purge
                    </button>
                 </div>
               </section>
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default GroupDetailSettings;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Group, Message, AppTab, SmartNote, VideoSession, ScheduledSession, StudyRoutine, Post, Alarm, PlannerTask } from './types';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VideoView from './components/VideoView';
import NotebookView from './components/NotebookView';
import ScheduleView from './components/ScheduleView';
import SARAPanel from './components/SARAPanel';
import Auth from './components/Auth';
import VideoCall from './components/VideoCall';
import Logo from './components/Logo';
import SettingsModal, { SettingsTab } from './components/SettingsModal';
import HomeView from './components/HomeView';
import SearchView from './components/SearchView';
import GroupsHubView from './components/GroupsHubView';
import ProfileHubView from './components/ProfileHubView';
import PlannerView from './components/PlannerView';
import GroupDetailSettings from './components/GroupDetailSettings';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.HOME);
  const [groups, setGroups] = useState<Group[]>([]);
  const [activeGroupId, setActiveGroupId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [notes, setNotes] = useState<SmartNote[]>([]);
  const [videos, setVideos] = useState<VideoSession[]>([]);
  const [scheduledSessions, setScheduledSessions] = useState<ScheduledSession[]>([]);
  const [studyRoutines, setStudyRoutines] = useState<StudyRoutine[]>([]);
  const [posts, setPosts] = useState<Post[]>([]);
  const [alarms, setAlarms] = useState<Alarm[]>([]);
  const [plannerTasks, setPlannerTasks] = useState<PlannerTask[]>([]);
  const [isSARAOpen, setIsSARAOpen] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCalling, setIsCalling] = useState(false);

  // Modals state
  const [isGroupModalOpen, setIsGroupModalOpen] = useState<'create' | 'join' | null>(null);
  const [settingsModal, setSettingsModal] = useState<{ isOpen: boolean; tab: SettingsTab }>({ isOpen: false, tab: SettingsTab.PROFILE });
  const [groupInput, setGroupInput] = useState('');

  // Load Initial Data
  useEffect(() => {
    const savedUser = localStorage.getItem('kivia_current_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));

    setGroups(JSON.parse(localStorage.getItem('kivia_groups') || '[]'));
    setMessages(JSON.parse(localStorage.getItem('kivia_messages') || '[]'));
    setNotes(JSON.parse(localStorage.getItem('kivia_notes') || '[]'));
    setVideos(JSON.parse(localStorage.getItem('kivia_videos') || '[]'));
    setScheduledSessions(JSON.parse(localStorage.getItem('kivia_schedules') || '[]'));
    setStudyRoutines(JSON.parse(localStorage.getItem('kivia_routines') || '[]'));
    setAllUsers(JSON.parse(localStorage.getItem('kivia_users') || '[]'));
    setPosts(JSON.parse(localStorage.getItem('kivia_posts') || '[]'));
    setAlarms(JSON.parse(localStorage.getItem('kivia_alarms') || '[]'));
    setPlannerTasks(JSON.parse(localStorage.getItem('kivia_planner_tasks') || '[]'));

    handleHashRouting();
    window.addEventListener('hashchange', handleHashRouting);
    return () => window.removeEventListener('hashchange', handleHashRouting);
  }, []);

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('kivia_groups', JSON.stringify(groups));
    localStorage.setItem('kivia_messages', JSON.stringify(messages));
    localStorage.setItem('kivia_notes', JSON.stringify(notes));
    localStorage.setItem('kivia_videos', JSON.stringify(videos));
    localStorage.setItem('kivia_schedules', JSON.stringify(scheduledSessions));
    localStorage.setItem('kivia_routines', JSON.stringify(studyRoutines));
    localStorage.setItem('kivia_users', JSON.stringify(allUsers));
    localStorage.setItem('kivia_posts', JSON.stringify(posts));
    localStorage.setItem('kivia_alarms', JSON.stringify(alarms));
    localStorage.setItem('kivia_planner_tasks', JSON.stringify(plannerTasks));
    if (currentUser) localStorage.setItem('kivia_current_user', JSON.stringify(currentUser));
  }, [groups, messages, notes, videos, scheduledSessions, studyRoutines, allUsers, posts, alarms, plannerTasks, currentUser]);

  const handleHashRouting = () => {
    const hash = window.location.hash;
    if (hash.startsWith('#join-')) {
      const code = hash.replace('#join-', '');
      handleJoinByCode(code);
    } else if (hash.startsWith('#call-')) {
      if (!activeGroupId && groups.length > 0) {
        setActiveGroupId(groups[0].id);
      }
      setIsCalling(true);
      window.location.hash = ''; 
    }
  };

  const handleJoinByCode = (code: string) => {
    const cleanCode = code.trim();
    if (!cleanCode) return;
    const existing = groups.find(g => g.joinCode === cleanCode);
    if (existing) {
      setActiveGroupId(existing.id);
      setActiveTab(AppTab.CHAT);
      setIsGroupModalOpen(null);
      setGroupInput('');
      return;
    }
    const newGroup: Group = {
      id: Date.now().toString(),
      name: `Peer Session #${cleanCode.slice(-4)}`,
      joinCode: cleanCode,
      memberIds: [currentUser?.id || 'anon'],
      createdAt: new Date().toISOString(),
      lastMessage: 'You joined via a peer link'
    };
    setGroups(prev => [...prev, newGroup]);
    setActiveGroupId(newGroup.id);
    setActiveTab(AppTab.CHAT);
    setIsGroupModalOpen(null);
    setGroupInput('');
    window.location.hash = '';
  };

  const handleCreateGroup = () => {
    if (!groupInput.trim()) return;
    const joinCode = Math.floor(100000 + Math.random() * 900000).toString();
    const newGroup: Group = {
      id: Date.now().toString(),
      name: groupInput,
      joinCode,
      memberIds: [currentUser!.id],
      createdAt: new Date().toISOString(),
      lastMessage: 'Group created'
    };
    setGroups([...groups, newGroup]);
    setActiveGroupId(newGroup.id);
    setActiveTab(AppTab.CHAT);
    setIsGroupModalOpen(null);
    setGroupInput('');
  };

  const handleUpdateUser = (updatedUser: Partial<User>) => {
    if (!currentUser) return;
    const newUser = { ...currentUser, ...updatedUser };
    setCurrentUser(newUser);
    setAllUsers(allUsers.map(u => u.id === newUser.id ? newUser : u));
  };

  const handleUpdateGroup = (groupId: string, updatedGroup: Partial<Group>) => {
    setGroups(groups.map(g => g.id === groupId ? { ...g, ...updatedGroup } : g));
  };

  const handleDeleteGroup = (groupId: string) => {
    setGroups(groups.filter(g => g.id !== groupId));
    setMessages(messages.filter(m => m.metadata?.groupId !== groupId));
    if (activeGroupId === groupId) {
      setActiveGroupId(null);
      setActiveTab(AppTab.HOME);
    }
  };

  const handleClearChat = (groupId: string) => {
    setMessages(messages.filter(m => m.metadata?.groupId !== groupId));
    setGroups(groups.map(g => g.id === groupId ? { ...g, lastMessage: 'Chat cleared' } : g));
  };

  const handleExitGroup = (groupId: string) => {
    setGroups(groups.filter(g => g.id !== groupId));
    if (activeGroupId === groupId) {
      setActiveGroupId(null);
      setActiveTab(AppTab.HOME);
    }
  };

  const handleSendMessage = (text: string, type: Message['type'] = 'text', metadata: any = {}) => {
    const gid = metadata.groupId || activeGroupId;
    if (!gid) return;
    const newMessage: Message = {
      id: Date.now().toString(),
      senderId: currentUser!.id,
      senderName: currentUser!.name,
      text,
      timestamp: new Date().toISOString(),
      type,
      metadata: { ...metadata, groupId: gid }
    };
    setMessages(prev => [...prev, newMessage]);
    setGroups(prev => prev.map(g => g.id === gid ? { ...g, lastMessage: type === 'text' ? text : `[${type}]` } : g));
  };

  const handleSharePostToGroup = (post: Post, groupId: string) => {
    const group = groups.find(g => g.id === groupId);
    if (!group) return;

    let shareText = `Check out this breakthrough from @${post.authorName}: ${post.content}`;
    let preview = undefined;

    if (post.type !== 'text' && post.mediaUrl) {
      preview = {
        type: post.type as 'image' | 'video',
        url: post.mediaUrl,
        title: `Post by ${post.authorName}`
      };
    }

    handleSendMessage(shareText, 'text', { groupId, preview });
    alert(`Post shared to ${group.name}!`);
  };

  const handleAddPost = (content: string, type: 'text' | 'image' | 'video', mediaUrl?: string) => {
    const newPost: Post = {
      id: Date.now().toString(),
      authorId: currentUser!.id,
      authorName: currentUser!.name,
      authorAvatar: currentUser!.avatar,
      content,
      type,
      mediaUrl,
      timestamp: new Date().toISOString(),
      likes: []
    };
    setPosts([newPost, ...posts]);
  };

  const handleLikePost = (postId: string) => {
    setPosts(posts.map(p => {
      if (p.id === postId) {
        const hasLiked = p.likes.includes(currentUser!.id);
        return {
          ...p,
          likes: hasLiked ? p.likes.filter(id => id !== currentUser!.id) : [...p.likes, currentUser!.id]
        };
      }
      return p;
    }));
  };

  const handleBack = () => {
    if (activeTab === AppTab.HOME) {
      setActiveGroupId(null);
    } else {
      setActiveTab(AppTab.HOME);
    }
  };

  const activeGroup = groups.find(g => g.id === activeGroupId) || null;
  const filteredMessages = messages.filter(m => m.metadata?.groupId === activeGroupId);

  if (!currentUser) {
    return <Auth onLogin={(user) => {
      setCurrentUser(user);
      localStorage.setItem('kivia_current_user', JSON.stringify(user));
    }} />;
  }

  return (
    <div className="flex h-screen bg-white font-['Inter'] selection:bg-indigo-100 selection:text-indigo-900 overflow-hidden">
      {/* Sidebar Overlay for Mobile/Toggled */}
      <div className={`fixed inset-0 z-[100] md:relative md:flex md:w-72 md:z-0 transition-all duration-500 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <div className="absolute inset-0 bg-black/40 backdrop-blur-sm md:hidden" onClick={() => setIsSidebarOpen(false)}></div>
        <div className="relative w-72 h-full border-r border-gray-100 bg-white">
          <Sidebar 
            groups={groups} 
            activeGroupId={activeGroupId} 
            onGroupSelect={(id) => {
              setActiveGroupId(id);
              setActiveTab(AppTab.CHAT);
              setIsSidebarOpen(false);
            }} 
            onGroupSettingsSelect={(id) => {
              setActiveGroupId(id);
              setActiveTab(AppTab.GROUP_SETTINGS);
              setIsSidebarOpen(false);
            }}
            currentUser={currentUser}
            onLogout={() => { setCurrentUser(null); localStorage.removeItem('kivia_current_user'); }}
            onCreateGroup={() => { setIsGroupModalOpen('create'); setIsSidebarOpen(false); }}
            activeTab={activeTab}
            setActiveTab={(tab) => { setActiveTab(tab); setIsSidebarOpen(false); }}
            onShareGroupLink={(g) => {
              const link = `${window.location.origin}${window.location.pathname}#join-${g.joinCode}`;
              navigator.clipboard.writeText(link);
              alert(`Join Link Copied: ${g.name}`);
            }}
            onClose={() => setIsSidebarOpen(false)}
          />
        </div>
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-white relative h-full">
        <header className="flex items-center justify-between px-8 py-5 border-b border-gray-100 glass sticky top-0 z-30 gap-6">
          <div className="flex items-center gap-5 flex-shrink-0">
            <Logo 
              className="w-10 h-10 shadow-lg shadow-green-100 rounded-full cursor-pointer hover:scale-110 transition-transform md:hidden" 
              onClick={() => {
                setActiveGroupId(null);
                setActiveTab(AppTab.HOME);
              }} 
            />
            <div className="flex flex-col">
              <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none mb-1">
                {activeTab === AppTab.HOME ? 'Feed' : 
                 activeTab === AppTab.CHAT ? 'Chat' : 
                 activeTab === AppTab.VIDEO ? 'Video Hub' : 
                 activeTab === AppTab.NOTEBOOK ? 'Notebook' : 
                 activeTab === AppTab.SCHEDULE ? 'Session Plan' : 
                 activeTab === AppTab.PLANNER ? 'Planner & Alarms' : 
                 activeTab === AppTab.GROUP_SETTINGS ? 'Squad Settings' :
                 activeTab === AppTab.GROUPS_HUB ? 'Squads' : 'Profile'}
              </h1>
              <div className="flex items-center gap-2">
                {activeTab === AppTab.GROUPS_HUB ? (
                  <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Groups Management</span>
                ) : activeTab === AppTab.PROFILE_HUB ? (
                  <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Personal Hub</span>
                ) : activeTab === AppTab.PLANNER ? (
                   <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Time Management</span>
                ) : activeTab === AppTab.GROUP_SETTINGS ? (
                   <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Settings & Media</span>
                ) : activeGroup && (activeTab === AppTab.CHAT || activeTab === AppTab.VIDEO || activeTab === AppTab.NOTEBOOK || activeTab === AppTab.SCHEDULE) ? (
                  <div className="flex items-center gap-2 group cursor-pointer" onClick={() => { setActiveTab(AppTab.CHAT); }}>
                    <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest truncate max-w-[120px]">{activeGroup.name}</span>
                    <span className="text-[9px] font-bold text-gray-300 bg-gray-50 px-1.5 py-0.5 rounded border border-gray-100">ID: {activeGroup.joinCode}</span>
                  </div>
                ) : (
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">KIVIA Community</span>
                )}
              </div>
            </div>
          </div>

          <div className="flex-1 max-w-sm relative mx-4 hidden lg:block">
            <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none text-gray-400">
              <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
            <input 
              type="text" 
              placeholder="Search peers, messages, notes..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-gray-50 border border-transparent rounded-[1.5rem] pl-14 pr-6 py-2.5 text-sm focus:bg-white focus:border-indigo-100 outline-none transition-all font-medium"
            />
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsSidebarOpen(true)}
              className={`p-3 rounded-full transition-all duration-300 flex items-center gap-2 border bg-white text-indigo-600 hover:bg-gray-50 border-indigo-100 shadow-sm`}
            >
              <div className="relative flex h-3 w-3">
                <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 bg-indigo-400`}></span>
                <span className={`relative inline-flex rounded-full h-3 w-3 bg-indigo-600`}></span>
              </div>
              <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">Navigate</span>
            </button>

            <button 
              onClick={() => setIsSARAOpen(!isSARAOpen)}
              className={`p-3 rounded-xl transition-all duration-300 border flex items-center justify-center ${isSARAOpen ? 'bg-indigo-600 text-white border-indigo-500 shadow-lg' : 'bg-gray-50 text-gray-400 hover:text-indigo-600 border-transparent hover:border-indigo-100'}`}
              title="SARA AI"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-hidden relative">
          {searchQuery ? (
            <SearchView 
              query={searchQuery}
              users={allUsers}
              messages={messages}
              notes={notes}
              videos={videos}
              groups={groups}
              onNavigate={(gid, tab) => {
                setActiveGroupId(gid);
                setActiveTab(tab);
                setSearchQuery('');
              }}
              onClose={() => setSearchQuery('')}
            />
          ) : activeTab === AppTab.HOME ? (
            <HomeView 
              currentUser={currentUser} 
              posts={posts} 
              groups={groups}
              onAddPost={handleAddPost} 
              onLikePost={handleLikePost} 
              onSharePostToGroup={handleSharePostToGroup}
            />
          ) : activeTab === AppTab.GROUPS_HUB ? (
            <GroupsHubView 
              groups={groups}
              currentUserId={currentUser.id}
              onEditGroup={(id, name) => handleUpdateGroup(id, { name })}
              onClearChat={handleClearChat}
              onExitGroup={handleExitGroup}
              onDeleteGroup={handleDeleteGroup}
              onJoinGroup={() => setSettingsModal({ isOpen: true, tab: SettingsTab.JOIN })}
              onCreateGroup={() => setIsGroupModalOpen('create')}
              onBack={handleBack}
            />
          ) : activeTab === AppTab.PROFILE_HUB ? (
            <ProfileHubView 
              user={currentUser}
              onUpdateUser={handleUpdateUser}
              onLogout={() => { setCurrentUser(null); localStorage.removeItem('kivia_current_user'); }}
              onBack={handleBack}
            />
          ) : activeTab === AppTab.PLANNER ? (
            <PlannerView 
              alarms={alarms}
              tasks={plannerTasks}
              onAddAlarm={(a) => setAlarms([...alarms, { ...a, id: Date.now().toString() }])}
              onToggleAlarm={(id) => setAlarms(alarms.map(a => a.id === id ? { ...a, isEnabled: !a.isEnabled } : a))}
              onDeleteAlarm={(id) => setAlarms(alarms.filter(a => a.id !== id))}
              onAddTask={(t) => setPlannerTasks([...plannerTasks, { ...t, id: Date.now().toString() }])}
              onDeleteTask={(id) => setPlannerTasks(plannerTasks.filter(t => t.id !== id))}
              onBack={handleBack}
            />
          ) : activeTab === AppTab.GROUP_SETTINGS && activeGroup ? (
            <GroupDetailSettings 
              group={activeGroup}
              messages={messages.filter(m => m.metadata?.groupId === activeGroup.id)}
              onUpdateGroup={(updated) => handleUpdateGroup(activeGroup.id, updated)}
              onClearChat={() => handleClearChat(activeGroup.id)}
              onExitGroup={() => handleExitGroup(activeGroup.id)}
              onDeleteGroup={() => handleDeleteGroup(activeGroup.id)}
              onBack={() => setActiveTab(AppTab.CHAT)}
            />
          ) : !activeGroupId ? (
            <div className="h-full flex flex-col items-center justify-center p-8 text-center bg-[#F9FBEC]/10 animate-in zoom-in-95 duration-1000">
              <Logo className="w-32 h-32 mb-10 shadow-[0_40px_80px_-15px_rgba(162,209,73,0.3)] rounded-full bg-white p-4" />
              <h2 className="text-4xl font-black text-gray-900 mb-4 tracking-tight leading-tight">Your Academic Hub,<br/>Amplified by AI.</h2>
              <p className="text-gray-500 max-w-md font-medium text-lg mb-12">Connect with peers, organize your schedule, and let SARA synthesize your learning journey.</p>
              <div className="flex flex-wrap justify-center gap-4">
                <button 
                  onClick={() => setIsGroupModalOpen('create')} 
                  className="bg-indigo-600 text-white px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-100 hover:bg-indigo-700 hover:scale-105 transition-all"
                >
                  Create Study Group
                </button>
                <button 
                  onClick={() => setSettingsModal({ isOpen: true, tab: SettingsTab.JOIN })} 
                  className="bg-white border-2 border-gray-100 text-gray-600 px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:border-indigo-100 hover:text-indigo-600 transition-all"
                >
                  Join Session
                </button>
              </div>
            </div>
          ) : (
            <div className="h-full">
              {activeTab === AppTab.CHAT && <ChatView currentUser={currentUser} messages={filteredMessages} onSendMessage={handleSendMessage} allUsers={allUsers} activeGroup={activeGroup} />}
              {activeTab === AppTab.VIDEO && <VideoView videos={videos.filter(v => v.groupId === activeGroupId)} onAddVideo={(t, u) => setVideos([...videos, { id: Date.now().toString(), groupId: activeGroupId, title: t, url: u, thumbnail: `https://picsum.photos/seed/${Date.now()}/400/225`, duration: '0:00', recordedAt: new Date().toISOString() }])} onBack={handleBack} />}
              {activeTab === AppTab.NOTEBOOK && <NotebookView notes={notes.filter(n => n.groupId === activeGroupId)} onBack={handleBack} />}
              {activeTab === AppTab.SCHEDULE && (
                <ScheduleView 
                  groupId={activeGroupId} 
                  sessions={scheduledSessions.filter(s => s.groupId === activeGroupId)} 
                  routines={studyRoutines.filter(r => r.groupId === activeGroupId)}
                  onAddSession={(s) => setScheduledSessions([...scheduledSessions, { ...s, id: Date.now().toString(), groupId: activeGroupId }])}
                  onAddRoutine={(r) => setStudyRoutines([...studyRoutines, { ...r, id: Date.now().toString(), groupId: activeGroupId }])}
                  onRemoveSession={(id) => setScheduledSessions(scheduledSessions.filter(s => s.id !== id))}
                  onRemoveRoutine={(id) => setStudyRoutines(studyRoutines.filter(r => r.id !== id))}
                  onBack={handleBack}
                />
              )}
            </div>
          )}

          {isSARAOpen && activeGroupId && (
            <div className="absolute right-0 top-0 bottom-0 w-full sm:w-[400px] bg-white border-l border-gray-100 transform transition-all duration-500 shadow-2xl z-50 animate-in slide-in-from-right-full">
              <SARAPanel 
                onClose={() => setIsSARAOpen(false)} 
                messages={filteredMessages} 
                notes={notes.filter(n => n.groupId === activeGroupId)} 
                videos={videos.filter(v => v.groupId === activeGroupId)}
                onAiResponse={(msg) => handleSendMessage(msg.text, 'ai')}
                onNewNote={(note) => setNotes([...notes, { ...note, groupId: activeGroupId || '' }])}
                activeGroupId={activeGroupId || ''}
              />
            </div>
          )}
        </div>
      </main>

      {/* Unified Settings Modal */}
      {settingsModal.isOpen && (
        <SettingsModal 
          user={currentUser}
          activeGroup={activeGroup}
          initialTab={settingsModal.tab}
          onClose={() => setSettingsModal({ ...settingsModal, isOpen: false })}
          onUpdateUser={handleUpdateUser}
          onUpdateGroup={(updated) => activeGroup && handleUpdateGroup(activeGroup.id, updated)}
          onDeleteGroup={() => activeGroup && handleDeleteGroup(activeGroup.id)}
          onJoinGroup={handleJoinByCode}
        />
      )}

      {/* Group Create Modal */}
      {isGroupModalOpen === 'create' && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-start mb-8">
              <div className="flex items-center gap-4">
                <Logo className="w-12 h-12" />
                <div>
                  <h2 className="text-2xl font-black text-gray-900 tracking-tight">Build a Squad</h2>
                  <p className="text-sm text-gray-500 font-medium">Start a fresh collaborative space.</p>
                </div>
              </div>
              <button onClick={() => setIsGroupModalOpen(null)} className="p-2 text-gray-400 hover:text-gray-900 transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 ml-1">Study Group Name</label>
                <input 
                  autoFocus
                  type="text"
                  value={groupInput}
                  onChange={(e) => setGroupInput(e.target.value)}
                  placeholder="e.g. Bio 101 Finals Prep"
                  onKeyPress={(e) => e.key === 'Enter' && handleCreateGroup()}
                  className="w-full bg-gray-50 border-transparent rounded-2xl px-6 py-4 text-sm focus:bg-white focus:ring-0 outline-none transition-all font-medium"
                />
              </div>
              <button onClick={handleCreateGroup} disabled={!groupInput.trim()} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">Create Space</button>
            </div>
          </div>
        </div>
      )}

      {isCalling && activeGroup && (
        <VideoCall 
          onClose={() => setIsCalling(false)} 
          currentUser={currentUser} 
          activeGroup={activeGroup}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Alarm, PlannerTask } from '../types';
import Logo from './Logo';

interface PlannerViewProps {
  alarms: Alarm[];
  tasks: PlannerTask[];
  onAddAlarm: (alarm: Omit<Alarm, 'id'>) => void;
  onToggleAlarm: (id: string) => void;
  onDeleteAlarm: (id: string) => void;
  onAddTask: (task: Omit<PlannerTask, 'id'>) => void;
  onDeleteTask: (id: string) => void;
  onBack: () => void;
}

const PlannerView: React.FC<PlannerViewProps> = ({
  alarms,
  tasks,
  onAddAlarm,
  onToggleAlarm,
  onDeleteAlarm,
  onAddTask,
  onDeleteTask,
  onBack
}) => {
  const [showAddAlarm, setShowAddAlarm] = useState(false);
  const [showAddTask, setShowAddTask] = useState(false);
  const [viewMode, setViewMode] = useState<'list' | 'calendar'>('calendar');

  // Alarm Form
  const [alarmTime, setAlarmTime] = useState('08:00');
  const [alarmLabel, setAlarmLabel] = useState('');
  const [alarmDays, setAlarmDays] = useState<number[]>([]);

  // Task Form
  const [taskTitle, setTaskTitle] = useState('');
  const [taskDay, setTaskDay] = useState(1);
  const [taskTime, setTaskTime] = useState('09:00');
  const [taskCategory, setTaskCategory] = useState<'study' | 'break' | 'review'>('study');

  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const hours = Array.from({ length: 24 }, (_, i) => i);

  const toggleDay = (dayIndex: number) => {
    setAlarmDays(prev => 
      prev.includes(dayIndex) ? prev.filter(d => d !== dayIndex) : [...prev, dayIndex]
    );
  };

  const handleAddAlarm = (e: React.FormEvent) => {
    e.preventDefault();
    onAddAlarm({ time: alarmTime, label: alarmLabel || 'Alarm', isEnabled: true, days: alarmDays });
    setAlarmLabel('');
    setAlarmDays([]);
    setShowAddAlarm(false);
  };

  const handleAddTask = (e: React.FormEvent) => {
    e.preventDefault();
    onAddTask({ title: taskTitle, day: taskDay, time: taskTime, category: taskCategory });
    setTaskTitle('');
    setShowAddTask(false);
  };

  const getTimeInMinutes = (timeStr: string) => {
    const [h, m] = timeStr.split(':').map(Number);
    return h * 60 + m;
  };

  return (
    <div className="h-full overflow-y-auto bg-gray-50/20 p-8 flex flex-col items-center">
      <div className="w-full max-w-6xl space-y-12 pb-20">

        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-3 bg-white hover:bg-gray-100 rounded-2xl shadow-sm border border-gray-100 transition-all text-gray-400 hover:text-indigo-600">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
            </button>
            <div>
              <h2 className="text-3xl font-black text-gray-900 tracking-tight">Study Planner</h2>
              <p className="text-gray-500 font-medium">Coordinate your schedule and sync your study sprints.</p>
            </div>
          </div>
          <div className="flex items-center gap-3 bg-white p-1.5 rounded-2xl shadow-sm border border-gray-100">
            <button 
              onClick={() => setViewMode('list')}
              className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${viewMode === 'list' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:bg-gray-50'}`}
            >
              List
            </button>
            <button 
              onClick={() => setViewMode('calendar')}
              className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${viewMode === 'calendar' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:bg-gray-50'}`}
            >
              Calendar
            </button>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">

          {/* Controls Column */}
          <section className="lg:col-span-1 space-y-6">
            <div className="space-y-3">
              <button 
                onClick={() => setShowAddTask(true)}
                className="w-full px-6 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg>
                Plan Activity
              </button>
              <button 
                onClick={() => setShowAddAlarm(true)}
                className="w-full px-6 py-4 bg-white border-2 border-gray-100 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:border-indigo-100 hover:text-indigo-600 transition-all shadow-sm flex items-center justify-center gap-2"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                Set Alarm
              </button>
            </div>

            {showAddAlarm && (
              <form onSubmit={handleAddAlarm} className="bg-white p-6 rounded-[2rem] shadow-xl border border-gray-100 animate-in slide-in-from-top-4 space-y-4">
                <div className="flex items-center gap-2 mb-2">
                  <span className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">New Alarm</span>
                </div>
                <input 
                  type="time" 
                  value={alarmTime}
                  onChange={e => setAlarmTime(e.target.value)}
                  className="w-full text-4xl font-black text-center bg-gray-50 rounded-2xl p-4 focus:bg-white outline-none border border-transparent focus:border-indigo-100 transition-all"
                />
                <input 
                  type="text" 
                  placeholder="Alarm label..."
                  value={alarmLabel}
                  onChange={e => setAlarmLabel(e.target.value)}
                  className="w-full bg-gray-50 rounded-xl px-4 py-3 text-sm font-medium focus:bg-white outline-none border border-transparent focus:border-indigo-100 transition-all"
                />
                <div className="flex justify-between">
                  {days.map((d, i) => (
                    <button 
                      key={d} 
                      type="button"
                      onClick={() => toggleDay(i)}
                      className={`w-8 h-8 rounded-full text-[9px] font-black flex items-center justify-center transition-all ${alarmDays.includes(i) ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-400'}`}
                    >
                      {d[0]}
                    </button>
                  ))}
                </div>
                <div className="flex gap-2 pt-2">
                  <button type="button" onClick={() => setShowAddAlarm(false)} className="flex-1 py-3 text-[10px] font-black text-gray-400 uppercase">Cancel</button>
                  <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase shadow-lg shadow-indigo-100">Set</button>
                </div>
              </form>
            )}

            {showAddTask && (
              <form onSubmit={handleAddTask} className="bg-white p-6 rounded-[2rem] shadow-xl border border-gray-100 animate-in slide-in-from-top-4 space-y-4">
                <div className="flex items-center gap-2 mb-2">
                  <span className="w-2 h-2 bg-indigo-500 rounded-full"></span>
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">New Activity</span>
                </div>
                <input 
                  required 
                  value={taskTitle} 
                  onChange={e => setTaskTitle(e.target.value)} 
                  placeholder="Activity title..." 
                  className="w-full bg-gray-50 rounded-xl px-4 py-3 text-sm focus:bg-white outline-none border border-transparent focus:border-indigo-100 transition-all"
                />
                <div className="grid grid-cols-2 gap-2">
                   <select 
                      value={taskDay} 
                      onChange={e => setTaskDay(parseInt(e.target.value))}
                      className="w-full bg-gray-50 rounded-xl px-4 py-3 text-sm focus:bg-white outline-none border border-transparent focus:border-indigo-100 transition-all"
                    >
                      {days.map((d, i) => <option key={d} value={i}>{d}</option>)}
                    </select>
                    <input 
                      type="time" 
                      value={taskTime} 
                      onChange={e => setTaskTime(e.target.value)}
                      className="w-full bg-gray-50 rounded-xl px-4 py-3 text-sm focus:bg-white outline-none border border-transparent focus:border-indigo-100 transition-all"
                    />
                </div>
                <div className="flex gap-1.5">
                  {(['study', 'break', 'review'] as const).map(cat => (
                    <button 
                      key={cat}
                      type="button"
                      onClick={() => setTaskCategory(cat)}
                      className={`flex-1 py-2 text-[8px] font-black uppercase rounded-lg border transition-all ${taskCategory === cat ? 'bg-indigo-600 text-white border-indigo-600 shadow-md' : 'bg-white text-gray-400 border-gray-100'}`}
                    >
                      {cat}
                    </button>
                  ))}
                </div>
                <div className="flex gap-2 pt-2">
                  <button type="button" onClick={() => setShowAddTask(false)} className="flex-1 py-3 text-[10px] font-black text-gray-400 uppercase">Cancel</button>
                  <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase shadow-lg shadow-indigo-100">Schedule</button>
                </div>
              </form>
            )}

            {/* List Alarms Mini */}
