import React from 'react';
import { Group, User, AppTab } from '../types';
import Logo from './Logo';

interface SidebarProps {
  groups: Group[];
  activeGroupId: string | null;
  onGroupSelect: (id: string) => void;
  onGroupSettingsSelect: (id: string) => void;
  currentUser: User;
  onLogout: () => void;
  onCreateGroup: () => void;
