import { GoogleGenAI, Type } from "@google/genai";

// Service for interacting with SARA (Study Assistant for Real-time Analysis)
export const getSaraResponse = async (prompt: string, context: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Context (Discussion & Notes): ${context}\n\nUser Question: ${prompt}`,
      config: {
        systemInstruction: "You are SARA (Study Assistant for Real-time Analysis), KIVIA's expert academic AI. You help peer study groups by synthesizing their discussions, explaining concepts from shared materials, and providing encouragement. Keep answers concise, helpful, and academically rigorous but accessible. Always refer to the group's specific context when available.",
        temperature: 1.0,
        // Pro models require a non-zero thinking budget when using the thinking feature
        thinkingConfig: { thinkingBudget: 16384 }
      },
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I hit a snag in my processing. Could you try rephrasing or focusing on a specific part of your discussion?";
  }
};

export const generateSmartNotes = async (conversation: string) => {
  if (!conversation.trim()) return [];

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Study Group Discussion Transcript:\n${conversation}`,
      config: {
        systemInstruction: "Extract meaningful study notes from this transcript. Focus on definitions, formulas, theories, and key dates. Ignore small talk.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING, description: "Short descriptive concept name" },
              content: { type: Type.STRING, description: "Detailed explanation or formula" },
              tags: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Academic subjects" }
            },
            required: ["title", "content", "tags"],
            propertyOrdering: ["title", "content", "tags"],
          }
        },
        thinkingConfig: { thinkingBudget: 8192 }
      }
    });

    const parsed = JSON.parse(response.text || "[]");
    return Array.isArray(parsed) ? parsed : [];
  } catch (error) {
    console.error("Smart Note Generation Error:", error);
    return [];
  }
};

export const generateFlashcards = async (notebookContent: string) => {
  if (!notebookContent.trim()) return [];

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Existing Notebook Concepts:\n${notebookContent}`,
      config: {
        systemInstruction: "Convert these notebook entries into a series of active-recall flashcards. Each card should have a 'term' (the concept/question) and a 'definition' (the answer/explanation). Ensure they are concise and perfect for quick study sessions.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              term: { type: Type.STRING, description: "The concept or question to be tested" },
              definition: { type: Type.STRING, description: "The answer or detailed explanation" },
              tags: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Subject tags" }
            },
            required: ["term", "definition", "tags"],
            propertyOrdering: ["term", "definition", "tags"],
          }
        },
        thinkingConfig: { thinkingBudget: 8192 }
      }
    });

    const parsed = JSON.parse(response.text || "[]");
    return Array.isArray(parsed) ? parsed : [];
  } catch (error) {
    console.error("Flashcard Generation Error:", error);
    return [];
  }
};

export const optimizePlanner = async (currentTasks: any[], currentAlarms: any[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Current Weekly Tasks: ${JSON.stringify(currentTasks)}\nCurrent Alarms: ${JSON.stringify(currentAlarms)}`,
      config: {
        systemInstruction: "You are a world-class academic performance coach. Analyze the user's weekly schedule and provide an optimized plan. Focus on: 1. Deep work blocks (90-120 mins). 2. Regular breaks (Pomodoro style). 3. Spaced repetition review sessions. 4. Strategic time for difficult subjects. Return a full set of tasks for the week that replaces the old one. Keep titles motivating and clear.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              day: { type: Type.INTEGER, description: "0-6 (Sun-Sat)" },
              time: { type: Type.STRING, description: "HH:mm format" },
              category: { type: Type.STRING, enum: ["study", "break", "review"] }
            },
            required: ["title", "day", "time", "category"]
          }
        },
        thinkingConfig: { thinkingBudget: 16384 }
      }
    });

    const parsed = JSON.parse(response.text || "[]");
    return Array.isArray(parsed) ? parsed : [];
  } catch (error) {
    console.error("Optimization Error:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { Flashcard } from '../types';
import Logo from './Logo';

interface FlashcardGeneratorViewProps {
  groupId: string;
  onBack: () => void;
  onCardsGenerated: (cards: Flashcard[]) => void;
}

const FlashcardGeneratorView: React.FC<FlashcardGeneratorViewProps> = ({ groupId, onBack, onCardsGenerated }) => {
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [deckSize, setDeckSize] = useState('10');

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() || isLoading) return;

    setIsLoading(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Specific Instruction: ${prompt}\nTarget Deck Size: ${deckSize}`,
        config: {
          systemInstruction: "You are an expert academic tutor. Create a series of active-recall flashcards based on the user's specific prompt. Each card must have a 'term' and a 'definition'. Ensure high academic quality and clear definitions.",
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                term: { type: Type.STRING },
                definition: { type: Type.STRING },
                tags: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["term", "definition", "tags"]
            }
          },
          // Pro models require a non-zero thinking budget
          thinkingConfig: { thinkingBudget: 8192 }
        }
      });

      const parsed = JSON.parse(response.text || "[]");
      const formatted: Flashcard[] = parsed.map((c: any) => ({
        ...c,
        id: Date.now().toString() + Math.random(),
        groupId: groupId
      }));

      onCardsGenerated(formatted);
      alert(`SARA successfully forged ${formatted.length} new flashcards!`);
      onBack();
    } catch (err) {
      console.error(err);
      alert("Flashcard generation failed. Try rephrasing your instructions.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="h-full flex flex-col bg-gray-50/20">
      <div className="p-8 border-b border-gray-100 bg-white flex items-center justify-between">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-3 bg-white hover:bg-gray-100 rounded-2xl shadow-sm border border-gray-100 transition-all text-gray-400 hover:text-indigo-600">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
          </button>
          <div>
            <div className="flex items-center gap-2 mb-1">
              <span className="w-2 h-2 bg-yellow-500 rounded-full animate-ping"></span>
              <span className="text-[10px] font-black text-yellow-600 uppercase tracking-widest">Flashcards Generator</span>
            </div>
            <h2 className="text-3xl font-black text-gray-900 tracking-tight">Custom Generator</h2>
          </div>
        </div>
        <Logo className="w-12 h-12" />
      </div>

      <div className="flex-1 p-8 overflow-y-auto">
        <div className="max-w-3xl mx-auto bg-white rounded-[3rem] p-12 border border-gray-100 shadow-xl space-y-10 animate-in zoom-in-95 duration-500">
          <div className="space-y-4">
            <h3 className="text-2xl font-black text-gray-900 tracking-tight leading-tight">Instruct SARA to forge your deck</h3>
            <p className="text-gray-500 font-medium">Be specific about the subject, difficulty, and focus area. SARA will synthesize high-quality active recall cards based on your instructions.</p>
          </div>

          <form onSubmit={handleGenerate} className="space-y-8">
            <div className="space-y-3">
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Forge Instructions</label>
              <textarea 
                required
                value={prompt}
                onChange={e => setPrompt(e.target.value)}
                placeholder="E.g. Create 15 cards about Cellular Respiration focusing on the Krebs Cycle and Electron Transport Chain. Assume an undergraduate level."
                className="w-full bg-gray-50 border-transparent rounded-[1.5rem] px-8 py-6 text-sm focus:bg-white focus:ring-4 focus:ring-yellow-500/5 focus:border-yellow-100 outline-none transition-all font-medium min-h-[200px] resize-none"
              />
            </div>

            <div className="grid grid-cols-2 gap-6">
              <div className="space-y-3">
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Deck Size</label>
                <select 
                  value={deckSize}
                  onChange={e => setDeckSize(e.target.value)}
                  className="w-full bg-gray-50 border-transparent rounded-2xl px-6 py-4 text-sm focus:bg-white outline-none border border-transparent focus:border-yellow-100 font-medium transition-all"
                >
                  <option value="5">5 Cards (Quick Review)</option>
                  <option value="10">10 Cards (Balanced)</option>
                  <option value="20">20 Cards (Deep Dive)</option>
                  <option value="30">30 Cards (Exam Prep)</option>
                </select>
              </div>
            </div>

            <button 
              type="submit"
              disabled={isLoading || !prompt.trim()}
              className="w-full bg-yellow-500 text-white py-5 rounded-[1.5rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-yellow-100 hover:bg-yellow-600 transition-all flex items-center justify-center gap-3 active:scale-95"
            >
              {isLoading ? (
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              )}
              {isLoading ? 'Forging Cards...' : 'Begin Generation'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default FlashcardGeneratorView;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Group, Message, AppTab, SmartNote, Flashcard, VideoSession, ScheduledSession, StudyRoutine, Post, Alarm, PlannerTask } from './types';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VideoView from './components/VideoView';
import NotebookView from './components/NotebookView';
import FlashcardsView from './components/FlashcardsView';
import FlashcardGeneratorView from './components/FlashcardGeneratorView';
import AIChatView from './components/AIChatView';
import ScheduleView from './components/ScheduleView';
import SARAPanel from './components/SARAPanel';
import Auth from './components/Auth';
import VideoCall from './components/VideoCall';
import Logo from './components/Logo';
import SettingsModal, { SettingsTab } from './components/SettingsModal';
import HomeView from './components/HomeView';
import SearchView from './components/SearchView';
import GroupsHubView from './components/GroupsHubView';
import ProfileHubView from './components/ProfileHubView';
import PlannerView from './components/PlannerView';
import GroupDetailSettings from './components/GroupDetailSettings';
import { generateFlashcards } from './services/gemini';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.HOME);
  const [groups, setGroups] = useState<Group[]>([]);
  const [activeGroupId, setActiveGroupId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [notes, setNotes] = useState<SmartNote[]>([]);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [videos, setVideos] = useState<VideoSession[]>([]);
  const [scheduledSessions, setScheduledSessions] = useState<ScheduledSession[]>([]);
  const [studyRoutines, setStudyRoutines] = useState<StudyRoutine[]>([]);
  const [posts, setPosts] = useState<Post[]>([]);
  const [alarms, setAlarms] = useState<Alarm[]>([]);
  const [plannerTasks, setPlannerTasks] = useState<PlannerTask[]>([]);
  const [isSARAOpen, setIsSARAOpen] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCalling, setIsCalling] = useState(false);
  const [isGeneratingFlashcards, setIsGeneratingFlashcards] = useState(false);

  // Modals state
  const [isGroupModalOpen, setIsGroupModalOpen] = useState<'create' | 'join' | null>(null);
  const [settingsModal, setSettingsModal] = useState<{ isOpen: boolean; tab: SettingsTab }>({ isOpen: false, tab: SettingsTab.PROFILE });
  const [groupInput, setGroupInput] = useState('');

  // Load Initial Data
  useEffect(() => {
    const savedUser = localStorage.getItem('kivia_current_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));

    setGroups(JSON.parse(localStorage.getItem('kivia_groups') || '[]'));
    setMessages(JSON.parse(localStorage.getItem('kivia_messages') || '[]'));
    setNotes(JSON.parse(localStorage.getItem('kivia_notes') || '[]'));
    setFlashcards(JSON.parse(localStorage.getItem('kivia_flashcards') || '[]'));
    setVideos(JSON.parse(localStorage.getItem('kivia_videos') || '[]'));
    setScheduledSessions(JSON.parse(localStorage.getItem('kivia_schedules') || '[]'));
    setStudyRoutines(JSON.parse(localStorage.getItem('kivia_routines') || '[]'));
    setAllUsers(JSON.parse(localStorage.getItem('kivia_users') || '[]'));
    setPosts(JSON.parse(localStorage.getItem('kivia_posts') || '[]'));
    setAlarms(JSON.parse(localStorage.getItem('kivia_alarms') || '[]'));
    setPlannerTasks(JSON.parse(localStorage.getItem('kivia_planner_tasks') || '[]'));

    handleHashRouting();
    window.addEventListener('hashchange', handleHashRouting);
    return () => window.removeEventListener('hashchange', handleHashRouting);
  }, []);

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('kivia_groups', JSON.stringify(groups));
    localStorage.setItem('kivia_messages', JSON.stringify(messages));
    localStorage.setItem('kivia_notes', JSON.stringify(notes));
    localStorage.setItem('kivia_flashcards', JSON.stringify(flashcards));
    localStorage.setItem('kivia_videos', JSON.stringify(videos));
    localStorage.setItem('kivia_schedules', JSON.stringify(scheduledSessions));
    localStorage.setItem('kivia_routines', JSON.stringify(studyRoutines));
    localStorage.setItem('kivia_users', JSON.stringify(allUsers));
    localStorage.setItem('kivia_posts', JSON.stringify(posts));
    localStorage.setItem('kivia_alarms', JSON.stringify(alarms));
    localStorage.setItem('kivia_planner_tasks', JSON.stringify(plannerTasks));
    if (currentUser) localStorage.setItem('kivia_current_user', JSON.stringify(currentUser));
  }, [groups, messages, notes, flashcards, videos, scheduledSessions, studyRoutines, allUsers, posts, alarms, plannerTasks, currentUser]);

  const handleHashRouting = () => {
    const hash = window.location.hash;
    if (hash.startsWith('#join-')) {
      const code = hash.replace('#join-', '');
      handleJoinByCode(code);
    } else if (hash.startsWith('#call-')) {
      if (!activeGroupId && groups.length > 0) {
        setActiveGroupId(groups[0].id);
      }
      setIsCalling(true);
      window.location.hash = ''; 
    }
  };

  const handleJoinByCode = (code: string) => {
    const cleanCode = code.trim();
    if (!cleanCode) return;
    const existing = groups.find(g => g.joinCode === cleanCode);
    if (existing) {
      setActiveGroupId(existing.id);
      setActiveTab(AppTab.CHAT);
      setIsGroupModalOpen(null);
      setGroupInput('');
      return;
    }
    const newGroup: Group = {
      id: Date.now().toString(),
      name: `Peer Session #${cleanCode.slice(-4)}`,
      joinCode: cleanCode,
      memberIds: [currentUser?.id || 'anon'],
      createdAt: new Date().toISOString(),
      lastMessage: 'You joined via a peer link'
    };
    setGroups(prev => [...prev, newGroup]);
    setActiveGroupId(newGroup.id);
    setActiveTab(AppTab.CHAT);
    setIsGroupModalOpen(null);
    setGroupInput('');
    window.location.hash = '';
  };

  const handleCreateGroup = () => {
    if (!groupInput.trim()) return;
    const joinCode = Math.floor(100000 + Math.random() * 900000).toString();
    const newGroup: Group = {
      id: Date.now().toString(),
      name: groupInput,
      joinCode,
      memberIds: [currentUser!.id],
      createdAt: new Date().toISOString(),
      lastMessage: 'Group created'
    };
    setGroups([...groups, newGroup]);
    setActiveGroupId(newGroup.id);
    setActiveTab(AppTab.CHAT);
    setIsGroupModalOpen(null);
    setGroupInput('');
  };

  const handleUpdateUser = (updatedUser: Partial<User>) => {
    if (!currentUser) return;
    const newUser = { ...currentUser, ...updatedUser };
    setCurrentUser(newUser);
    setAllUsers(allUsers.map(u => u.id === newUser.id ? newUser : u));
  };

  const handleUpdateGroup = (groupId: string, updatedGroup: Partial<Group>) => {
    setGroups(groups.map(g => g.id === groupId ? { ...g, ...updatedGroup } : g));
  };

  const handleDeleteGroup = (groupId: string) => {
    setGroups(groups.filter(g => g.id !== groupId));
    setMessages(messages.filter(m => m.metadata?.groupId !== groupId));
    if (activeGroupId === groupId) {
      setActiveGroupId(null);
      setActiveTab(AppTab.HOME);
    }
  };

  const handleClearChat = (groupId: string) => {
    setMessages(messages.filter(m => m.metadata?.groupId !== groupId));
    setGroups(prev => prev.map(g => g.id === groupId ? { ...g, lastMessage: 'Chat cleared' } : g));
  };

  const handleExitGroup = (groupId: string) => {
    setGroups(groups.filter(g => g.id !== groupId));
    if (activeGroupId === groupId) {
      setActiveGroupId(null);
      setActiveTab(AppTab.HOME);
    }
  };

  const handleSendMessage = (text: string, type: Message['type'] = 'text', metadata: any = {}) => {
    const gid = metadata.groupId || activeGroupId;
    if (!gid) return;

    const messageId = Date.now().toString();
    const newMessage: Message = {
      id: messageId,
      senderId: currentUser!.id,
      senderName: currentUser!.name,
      text,
      timestamp: new Date().toISOString(),
      type,
      status: 'sent', // Initially sent
      metadata: { ...metadata, groupId: gid }
    };

    setMessages(prev => [...prev, newMessage]);
    setGroups(prev => prev.map(g => g.id === gid ? { ...g, lastMessage: type === 'text' ? text : `[${type}]` } : g));

    // Simulate "Read" status after a brief delay for local visual feedback
    setTimeout(() => {
      setMessages(prev => prev.map(m => m.id === messageId ? { ...m, status: 'read' as const } : m));
    }, 1500);
  };

  const handleSharePostToGroup = (post: Post, groupId: string) => {
    const group = groups.find(g => g.id === groupId);
    if (!group) return;
    let shareText = `Check out this breakthrough from @${post.authorName}: ${post.content}`;
    let preview = undefined;
    if (post.type !== 'text' && post.mediaUrl) {
      preview = { type: post.type as 'image' | 'video', url: post.mediaUrl, title: `Post by ${post.authorName}` };
    }
    handleSendMessage(shareText, 'text', { groupId, preview });
    alert(`Post shared to ${group.name}!`);
  };

  const handleAddPost = (content: string, type: 'text' | 'image' | 'video', mediaUrl?: string) => {
    const newPost: Post = {
      id: Date.now().toString(),
      authorId: currentUser!.id,
      authorName: currentUser!.name,
      authorAvatar: currentUser!.avatar,
      content, type, mediaUrl, timestamp: new Date().toISOString(), likes: []
    };
    setPosts([newPost, ...posts]);
  };

  const handleLikePost = (postId: string) => {
    setPosts(posts.map(p => {
      if (p.id === postId) {
        const hasLiked = p.likes.includes(currentUser!.id);
        return { ...p, likes: hasLiked ? p.likes.filter(id => id !== currentUser!.id) : [...p.likes, currentUser!.id] };
      }
      return p;
    }));
  };

  const handleGenerateFlashcards = async () => {
    if (!activeGroupId) return;
    const groupNotes = notes.filter(n => n.groupId === activeGroupId);
    if (groupNotes.length === 0) {
      alert("No notes found for this group. SARA needs some content to generate cards!");
      return;
    }

    setIsGeneratingFlashcards(true);
    const notebookStr = groupNotes.map(n => `Title: ${n.title}\nContent: ${n.content}`).join('\n\n');

    try {
      const newCards = await generateFlashcards(notebookStr);
      const formattedCards: Flashcard[] = newCards.map((c: any) => ({
        ...c,
        id: Date.now().toString() + Math.random(),
        groupId: activeGroupId
      }));

      setFlashcards(prev => [
        ...prev.filter(fc => fc.groupId !== activeGroupId),
        ...formattedCards
      ]);

      alert(`SARA successfully generated ${formattedCards.length} flashcards!`);
    } catch (err: any) {
      console.error(err);
      alert("Flashcard generation failed. Please check your connection or try again later.");
    } finally {
      setIsGeneratingFlashcards(false);
    }
  };

  const handleBack = () => {
    if (activeTab === AppTab.HOME) {
      setActiveGroupId(null);
    } else {
      setActiveTab(AppTab.HOME);
    }
  };

  const activeGroup = groups.find(g => g.id === activeGroupId) || null;
  const filteredMessages = messages.filter(m => m.metadata?.groupId === activeGroupId);
  const activeGroupFlashcards = flashcards.filter(fc => fc.groupId === activeGroupId);

  if (!currentUser) {
    return <Auth onLogin={(user) => {
      setCurrentUser(user);
      localStorage.setItem('kivia_current_user', JSON.stringify(user));
    }} />;
  }

  return (
    <div className="flex h-screen bg-white font-['Inter'] selection:bg-indigo-100 selection:text-indigo-900 overflow-hidden">
      <div className={`fixed inset-0 z-[100] md:relative md:flex md:w-72 md:z-0 transition-all duration-500 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <div className="absolute inset-0 bg-black/40 backdrop-blur-sm md:hidden" onClick={() => setIsSidebarOpen(false)}></div>
        <div className="relative w-72 h-full border-r border-gray-100 bg-white">
          <Sidebar 
            groups={groups} 
            activeGroupId={activeGroupId} 
            onGroupSelect={(id) => { setActiveGroupId(id); setActiveTab(AppTab.CHAT); setIsSidebarOpen(false); }} 
            onGroupSettingsSelect={(id) => { setActiveGroupId(id); setActiveTab(AppTab.GROUP_SETTINGS); setIsSidebarOpen(false); }}
            currentUser={currentUser}
            onLogout={() => { setCurrentUser(null); localStorage.removeItem('kivia_current_user'); }}
            onCreateGroup={() => { setIsGroupModalOpen('create'); setIsSidebarOpen(false); }}
            activeTab={activeTab}
            setActiveTab={(tab) => { setActiveTab(tab); setIsSidebarOpen(false); }}
            onShareGroupLink={(g) => {
              const link = `${window.location.origin}${window.location.pathname}#join-${g.joinCode}`;
              navigator.clipboard.writeText(link);
              alert(`Join Link Copied: ${g.name}`);
            }}
            onClose={() => setIsSidebarOpen(false)}
          />
        </div>
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-white relative h-full">
        <header className="flex items-center justify-between px-8 py-5 border-b border-gray-100 glass sticky top-0 z-30 gap-6">
          <div className="flex items-center gap-5 flex-shrink-0">
            <Logo className="w-10 h-10 shadow-lg shadow-green-100 rounded-full cursor-pointer hover:scale-110 transition-transform md:hidden" onClick={() => { setActiveGroupId(null); setActiveTab(AppTab.HOME); }} />
            <div className="flex flex-col">
              <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none mb-1">
                {activeTab === AppTab.HOME ? 'Feed' : 
                 activeTab === AppTab.CHAT ? 'Chat' : 
                 activeTab === AppTab.VIDEO ? 'Video Hub' : 
                 activeTab === AppTab.NOTEBOOK ? 'Notebook' : 
                 activeTab === AppTab.FLASHCARDS ? 'Flashcards' :
                 activeTab === AppTab.FLASHCARD_GEN ? 'Forge Deck' :
                 activeTab === AppTab.AI_CHAT ? 'Deep Reason' :
                 activeTab === AppTab.SCHEDULE ? 'Session Plan' : 
                 activeTab === AppTab.PLANNER ? 'Planner & Alarms' : 
                 activeTab === AppTab.GROUP_SETTINGS ? 'Squad Settings' :
                 activeTab === AppTab.GROUPS_HUB ? 'Squads' : 'Profile'}
              </h1>
              <div className="flex items-center gap-2">
                {activeTab === AppTab.GROUP_SETTINGS ? (
                   <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Settings & Media</span>
                ) : activeGroup && (activeTab === AppTab.CHAT || activeTab === AppTab.VIDEO || activeTab === AppTab.NOTEBOOK || activeTab === AppTab.FLASHCARDS || activeTab === AppTab.SCHEDULE) ? (
                  <div className="flex items-center gap-2 group cursor-pointer">
                    <span onClick={() => setActiveTab(AppTab.CHAT)} className="text-[10px] font-black text-indigo-600 uppercase tracking-widest truncate max-w-[120px]">{activeGroup.name}</span>
                    <span className="text-[9px] font-bold text-gray-300 bg-gray-50 px-1.5 py-0.5 rounded border border-gray-100">ID: {activeGroup.joinCode}</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setActiveTab(AppTab.GROUP_SETTINGS); }}
                      className="ml-1.5 p-1.5 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 border border-transparent hover:border-indigo-100 rounded-lg transition-all"
                      title="Group Settings"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                    </button>
                  </div>
                ) : (
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">KIVIA Community</span>
                )}
              </div>
            </div>
          </div>

          <div className="flex-1 max-w-sm relative mx-4 hidden lg:block">
            <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none text-gray-400">
              <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
            <input type="text" placeholder="Search peers, messages, notes..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-gray-50 border border-transparent rounded-[1.5rem] pl-14 pr-6 py-2.5 text-sm focus:bg-white focus:border-indigo-100 outline-none transition-all font-medium" />
          </div>

          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className={`p-3 rounded-full transition-all duration-300 flex items-center gap-2 border bg-white text-indigo-600 hover:bg-gray-50 border-indigo-100 shadow-sm md:hidden`}>
              <div className="relative flex h-3 w-3"><span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 bg-indigo-400`}></span><span className={`relative inline-flex rounded-full h-3 w-3 bg-indigo-600`}></span></div>
            </button>
            <button onClick={() => setIsSARAOpen(!isSARAOpen)} className={`p-3 rounded-xl transition-all duration-300 border flex items-center justify-center ${isSARAOpen ? 'bg-indigo-600 text-white border-indigo-500 shadow-lg' : 'bg-gray-50 text-gray-400 hover:text-indigo-600 border-transparent hover:border-indigo-100'}`} title="SARA AI">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
            </button>
          </div>
        </header>

        <div className={`flex-1 overflow-hidden relative ${activeGroupId ? 'study-grid' : ''}`}>
          {searchQuery ? (
            <SearchView query={searchQuery} users={allUsers} messages={messages} notes={notes} videos={videos} groups={groups} onNavigate={(gid, tab) => { setActiveGroupId(gid); setActiveTab(tab); setSearchQuery(''); }} onClose={() => setSearchQuery('')} />
          ) : activeTab === AppTab.HOME ? (
            <HomeView currentUser={currentUser} posts={posts} groups={groups} onAddPost={handleAddPost} onLikePost={handleLikePost} onSharePostToGroup={handleSharePostToGroup} />
          ) : activeTab === AppTab.AI_CHAT ? (
            <AIChatView onBack={handleBack} context={notes.slice(-5).map(n => n.content).join(' ')} />
          ) : activeTab === AppTab.GROUPS_HUB ? (
            <GroupsHubView groups={groups} currentUserId={currentUser.id} onEditGroup={handleUpdateGroup} onClearChat={handleClearChat} onExitGroup={handleExitGroup} onDeleteGroup={handleDeleteGroup} onJoinGroup={() => setSettingsModal({ isOpen: true, tab: SettingsTab.JOIN })} onCreateGroup={() => setIsGroupModalOpen('create')} onBack={handleBack} />
          ) : activeTab === AppTab.PROFILE_HUB ? (
            <ProfileHubView user={currentUser} onUpdateUser={handleUpdateUser} onLogout={() => { setCurrentUser(null); localStorage.removeItem('kivia_current_user'); }} onBack={handleBack} />
          ) : activeTab === AppTab.PLANNER ? (
            <PlannerView alarms={alarms} tasks={plannerTasks} onAddAlarm={(a) => setAlarms([...alarms, { ...a, id: Date.now().toString() }])} onToggleAlarm={(id) => setAlarms(alarms.map(a => a.id === id ? { ...a, isEnabled: !a.isEnabled } : a))} onDeleteAlarm={(id) => setAlarms(alarms.filter(a => a.id !== id))} onAddTask={(t) => setPlannerTasks([...plannerTasks, { ...t, id: Date.now().toString() }])} onUpdateTasks={(t) => setPlannerTasks(t)} onDeleteTask={(id) => setPlannerTasks(plannerTasks.filter(t => t.id !== id))} onBack={handleBack} />
          ) : activeTab === AppTab.GROUP_SETTINGS && activeGroup ? (
            <GroupDetailSettings group={activeGroup} messages={messages.filter(m => m.metadata?.groupId === activeGroup.id)} onUpdateGroup={(updated) => handleUpdateGroup(activeGroup.id, updated)} onClearChat={() => handleClearChat(activeGroup.id)} onExitGroup={() => handleExitGroup(activeGroup.id)} onDeleteGroup={() => handleDeleteGroup(activeGroup.id)} onBack={() => setActiveTab(AppTab.CHAT)} />
          ) : !activeGroupId ? (
            <div className="h-full flex flex-col items-center justify-center p-8 text-center bg-[#F9FBEC]/10 animate-in zoom-in-95 duration-1000">
              <Logo className="w-32 h-32 mb-10 shadow-[0_40px_80px_-15px_rgba(162,209,73,0.3)] rounded-full bg-white p-4" />
              <h2 className="text-4xl font-black text-gray-900 mb-4 tracking-tight leading-tight">Your Academic Hub,<br/>Amplified by AI.</h2>
              <p className="text-gray-500 max-w-md font-medium text-lg mb-12">Connect with peers, organize your schedule, and let SARA synthesize your learning journey.</p>
              <div className="flex flex-wrap justify-center gap-4">
                <button onClick={() => setIsGroupModalOpen('create')} className="bg-indigo-600 text-white px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-100 hover:bg-indigo-700 hover:scale-105 transition-all">Create Study Group</button>
                <button onClick={() => setSettingsModal({ isOpen: true, tab: SettingsTab.JOIN })} className="bg-white border-2 border-gray-100 text-gray-600 px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:border-indigo-100 hover:text-indigo-600 transition-all">Join Session</button>
              </div>
            </div>
          ) : (
            <div className="h-full">
              {activeTab === AppTab.CHAT && <ChatView currentUser={currentUser} messages={filteredMessages} onSendMessage={handleSendMessage} allUsers={allUsers} activeGroup={activeGroup} />}
              {activeTab === AppTab.VIDEO && <VideoView videos={videos.filter(v => v.groupId === activeGroupId)} onAddVideo={(t, u) => setVideos([...videos, { id: Date.now().toString(), groupId: activeGroupId, title: t, url: u, thumbnail: `https://picsum.photos/seed/${Date.now()}/400/225`, duration: '0:00', recordedAt: new Date().toISOString() }])} onBack={handleBack} />}
              {activeTab === AppTab.NOTEBOOK && <NotebookView notes={notes.filter(n => n.groupId === activeGroupId)} onBack={handleBack} />}
              {activeTab === AppTab.FLASHCARDS && <FlashcardsView flashcards={activeGroupFlashcards} onGenerate={() => setActiveTab(AppTab.FLASHCARD_GEN)} isGenerating={isGeneratingFlashcards} onBack={handleBack} />}
              {activeTab === AppTab.FLASHCARD_GEN && <FlashcardGeneratorView groupId={activeGroupId || ''} onBack={() => setActiveTab(AppTab.FLASHCARDS)} onCardsGenerated={(newCards) => setFlashcards(prev => [...prev, ...newCards])} />}
              {activeTab === AppTab.SCHEDULE && <ScheduleView groupId={activeGroupId} sessions={scheduledSessions.filter(s => s.groupId === activeGroupId)} routines={studyRoutines.filter(r => r.groupId === activeGroupId)} onAddSession={(s) => setScheduledSessions([...scheduledSessions, { ...s, id: Date.now().toString(), groupId: activeGroupId }])} onAddRoutine={(r) => setStudyRoutines([...studyRoutines, { ...r, id: Date.now().toString(), groupId: activeGroupId }])} onRemoveSession={(id) => setScheduledSessions(scheduledSessions.filter(s => s.id !== id))} onRemoveRoutine={(id) => setStudyRoutines(studyRoutines.filter(r => r.id !== id))} onBack={handleBack} />}
            </div>
          )}
          {isSARAOpen && activeGroupId && (
            <div className="absolute right-0 top-0 bottom-0 w-full sm:w-[400px] bg-white border-l border-gray-100 transform transition-all duration-500 shadow-2xl z-50 animate-in slide-in-from-right-full">
              <SARAPanel onClose={() => setIsSARAOpen(false)} messages={filteredMessages} notes={notes.filter(n => n.groupId === activeGroupId)} videos={videos.filter(v => v.groupId === activeGroupId)} onAiResponse={(msg) => handleSendMessage(msg.text, 'ai')} onNewNote={(note) => setNotes([...notes, { ...note, groupId: activeGroupId || '' }])} activeGroupId={activeGroupId || ''} />
            </div>
          )}
        </div>
      </main>

      {settingsModal.isOpen && (
        <SettingsModal user={currentUser} activeGroup={activeGroup} initialTab={settingsModal.tab} onClose={() => setSettingsModal({ ...settingsModal, isOpen: false })} onUpdateUser={handleUpdateUser} onUpdateGroup={(updated) => activeGroup && handleUpdateGroup(activeGroup.id, updated)} onDeleteGroup={() => activeGroup && handleDeleteGroup(activeGroup.id)} onJoinGroup={handleJoinByCode} />
      )}

      {isGroupModalOpen === 'create' && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-start mb-8">
              <div className="flex items-center gap-4"><Logo className="w-12 h-12" /><div><h2 className="text-2xl font-black text-gray-900 tracking-tight">Build a Squad</h2><p className="text-sm text-gray-500 font-medium">Start a fresh collaborative space.</p></div></div>
              <button onClick={() => setIsGroupModalOpen(null)} className="p-2 text-gray-400 hover:text-gray-900 transition-colors"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg></button>
            </div>
            <div className="space-y-6">
              <div><label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 ml-1">Study Group Name</label><input autoFocus type="text" value={groupInput} onChange={(e) => setGroupInput(e.target.value)} placeholder="e.g. Bio 101 Finals Prep" onKeyPress={(e) => e.key === 'Enter' && handleCreateGroup()} className="w-full bg-gray-50 border-transparent rounded-2xl px-6 py-4 text-sm focus:bg-white focus:ring-0 outline-none transition-all font-medium" /></div>
              <button onClick={handleCreateGroup} disabled={!groupInput.trim()} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">Create Space</button>
            </div>
          </div>
        </div>
      )}

      {isCalling && activeGroup && (
        <VideoCall onClose={() => setIsCalling(false)} currentUser={currentUser} activeGroup={activeGroup} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Message, User, Group } from '../types';
import PreviewCard from './PreviewCard';
import Logo from './Logo';

interface ChatViewProps {
  currentUser: User;
  messages: Message[];
  onSendMessage: (text: string, type?: Message['type'], metadata?: any) => void;
  allUsers: User[];
  activeGroup: Group | null;
}

const ChatView: React.FC<ChatViewProps> = ({ currentUser, messages, onSendMessage, allUsers, activeGroup }) => {
  const [inputText, setInputText] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [recordingDuration, setRecordingDuration] = useState(0);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [showScrollDown, setShowScrollDown] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  };

  const handleScroll = () => {
    if (scrollRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
      const isAtBottom = scrollHeight - scrollTop - clientHeight < 100;
      setShowScrollDown(!isAtBottom);
    }
  };

  const detectMessageType = (text: string) => {
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const match = text.match(urlRegex);
    if (!match) return null;

    const url = match[0];
    if (url.match(/\.(jpeg|jpg|gif|png|webp)$/i)) return { type: 'image' as const, url };
    if (url.includes('youtube.com') || url.includes('youtu.be')) return { type: 'video' as const, url };
    return { type: 'website' as const, url };
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const preview = detectMessageType(inputText);
    if (preview) {
      onSendMessage(inputText, 'text', { preview });
    } else {
      onSendMessage(inputText);
    }
    setInputText('');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const isImage = file.type.startsWith('image/');
      const url = URL.createObjectURL(file);
      if (isImage) {
        onSendMessage(`Shared an image`, 'file', { fileName: file.name, fileUrl: url, preview: { type: 'image', url } });
      } else {
        onSendMessage(`Shared a file: ${file.name}`, 'file', { fileName: file.name, fileUrl: url });
      }
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const audioUrl = URL.createObjectURL(audioBlob);
        onSendMessage('Voice note sent', 'voice', { 
          fileUrl: audioUrl, 
          duration: recordingDuration,
          fileName: 'Voice Note.webm'
        });
        stream.getTracks().forEach(track => track.stop());
        setRecordingDuration(0);
      };

      mediaRecorder.start();
      setIsRecording(true);

      let seconds = 0;
      timerRef.current = window.setInterval(() => {
        seconds++;
        setRecordingDuration(seconds);
      }, 1000);

    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Microphone access is required to record voice notes.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }
  };

  const toggleRecording = () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
  };

  const toggleAudio = (id: string) => {
    const audio = document.getElementById(`audio-${id}`) as HTMLAudioElement;
    if (audio) {
      if (audio.paused) {
        if (playingId && playingId !== id) {
          const other = document.getElementById(`audio-${playingId}`) as HTMLAudioElement;
          other?.pause();
        }
        audio.play();
        setPlayingId(id);
      } else {
        audio.pause();
        setPlayingId(null);
      }
    }
  };

  const MessageStatus: React.FC<{ status?: 'sent' | 'delivered' | 'read', isMe: boolean }> = ({ status = 'read', isMe }) => {
    if (!isMe) return null;
    return (
      <span className="inline-flex ml-1.5 align-middle">
        {status === 'sent' && (
          <svg className="w-3 h-3 text-indigo-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
        )}
        {(status === 'delivered' || status === 'read') && (
          <div className="flex -space-x-1.5">
            <svg className={`w-3 h-3 ${status === 'read' ? 'text-green-300' : 'text-indigo-200'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
            <svg className={`w-3 h-3 ${status === 'read' ? 'text-green-300' : 'text-indigo-200'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
          </div>
        )}
      </span>
    );
  };

  return (
    <div className="flex flex-col h-full bg-transparent relative">
      <div 
        ref={scrollRef} 
        onScroll={handleScroll}
        className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth"
      >
        {messages.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-4">
            <Logo className="w-20 h-20 opacity-20 grayscale" />
            <div className="space-y-1">
              <h3 className="text-xl font-black text-gray-300 tracking-tight uppercase">Welcome to {activeGroup?.name}</h3>
              <p className="text-xs text-gray-400 font-medium max-w-[250px] mx-auto leading-relaxed">
                Invite peers using code <span className="font-black text-indigo-400">{activeGroup?.joinCode}</span> or just start the conversation!
              </p>
            </div>
          </div>
        ) : (
          messages.map((msg) => {
            const isMe = msg.senderId === currentUser.id;
            const sender = allUsers.find(u => u.id === msg.senderId);
            const isAI = msg.type === 'ai';

            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
                <div className={`flex max-w-[85%] gap-3 ${isMe ? 'flex-row-reverse' : 'flex-row'}`}>
                  {!isMe && !isAI && (
                    <img src={sender?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${msg.senderName}`} className="w-10 h-10 rounded-full border border-gray-100 mt-1 shadow-sm bg-white object-cover" alt={msg.senderName} />
                  )}
                  {isAI && (
                    <div className="w-10 h-10 rounded-full bg-indigo-50 border border-indigo-100 flex items-center justify-center mt-1">
                      <Logo className="w-6 h-6" />
                    </div>
                  )}
                  <div className="min-w-0">
                    {!isMe && <div className="text-[10px] font-black text-gray-400 mb-1 ml-1 uppercase tracking-tighter">{msg.senderName}</div>}
                    <div className={`
                      p-4 rounded-3xl shadow-sm text-sm relative break-words leading-relaxed
                      ${isMe ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-gray-800 rounded-tl-none border border-gray-50'}
                      ${isAI ? 'border-2 border-indigo-200 bg-indigo-50/50 shadow-indigo-100' : ''}
                    `}>
                      {isAI && (
                        <div className="flex items-center gap-1.5 text-[10px] font-black text-indigo-600 mb-2 uppercase tracking-widest">
                          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                          SARA Analysis
                        </div>
                      )}

                      {msg.type === 'file' && !msg.metadata?.preview ? (
                        <PreviewCard type="file" url={msg.metadata?.fileUrl || '#'} title={msg.metadata?.fileName} />
                      ) : msg.type === 'voice' ? (
                        <div className="flex items-center gap-4 py-1 px-2 min-w-[220px]">
                          <audio className="hidden" id={`audio-${msg.id}`} src={msg.metadata?.fileUrl} onEnded={() => setPlayingId(null)} />
                          <button 
                            onClick={() => toggleAudio(msg.id)}
                            className={`${isMe ? 'text-white' : 'text-indigo-600'} hover:scale-110 transition-transform active:scale-90`}
                          >
                            {playingId === msg.id ? (
                               <svg className="w-10 h-10" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1 1v4a1 1 0 001 1h4a1 1 0 001-1V8a1 1 0 00-1-1H8z" clipRule="evenodd" /></svg>
                            ) : (
                               <svg className="w-10 h-10" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                            )}
                          </button>
                          <div className="flex-1 space-y-1.5">
                            <div className={`h-1.5 rounded-full w-full relative overflow-hidden ${isMe ? 'bg-white/20' : 'bg-gray-100'}`}>
                                <div className={`absolute inset-y-0 left-0 rounded-full transition-all duration-300 ${isMe ? 'bg-white' : 'bg-indigo-600'} ${playingId === msg.id ? 'w-full animate-[shimmer_2s_infinite]' : 'w-0'}`}></div>
                            </div>
                            <div className={`flex justify-between items-center text-[9px] font-black uppercase tracking-tighter ${isMe ? 'text-indigo-100' : 'text-gray-400'}`}>
                                <span>{msg.metadata?.duration ? `0:${msg.metadata.duration.toString().padStart(2, '0')}` : 'Voice'}</span>
                                <span className="flex items-center gap-1">
                                  {playingId === msg.id && <span className="flex gap-0.5"><span className="w-0.5 h-1.5 bg-current animate-bounce [animation-delay:0s]"></span><span className="w-0.5 h-1.5 bg-current animate-bounce [animation-delay:0.2s]"></span><span className="w-0.5 h-1.5 bg-current animate-bounce [animation-delay:0.4s]"></span></span>}
                                  Voice Note
                                </span>
                            </div>
                          </div>
                        </div>
                      ) : (
                        <div>
                          <p className="whitespace-pre-wrap">{msg.text}</p>
                          {msg.metadata?.preview && (
                            <PreviewCard 
                              type={msg.metadata.preview.type} 
                              url={msg.metadata.preview.url} 
                              title={msg.metadata.preview.title}
                            />
                          )}
                        </div>
                      )}

                      <div className={`text-[9px] mt-2 font-bold uppercase tracking-tight opacity-60 text-right flex items-center justify-end ${isMe ? 'text-indigo-100' : 'text-gray-400'}`}>
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        <MessageStatus status={msg.status} isMe={isMe} />
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* Floating Scroll Down Button */}
      {showScrollDown && (
        <button 
          onClick={scrollToBottom}
          className="absolute bottom-24 right-8 p-3 bg-white text-indigo-600 rounded-full shadow-2xl border border-indigo-50 hover:bg-indigo-50 transition-all animate-bounce z-10"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 14l-7 7-7-7M12 21V3" /></svg>
        </button>
      )}

      <form onSubmit={handleSubmit} className="p-5 bg-white/80 backdrop-blur-md border-t border-gray-100 flex items-center gap-4">
        <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
        <button 
          type="button" 
          onClick={() => fileInputRef.current?.click()}
          className="p-2.5 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
          title="Share File"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
        </button>
        <div className="flex-1 relative">
          {isRecording ? (
            <div className="w-full bg-red-50 text-red-600 rounded-[1.5rem] px-6 py-4 text-sm font-black flex items-center justify-between">
               <div className="flex items-center gap-3">
                 <span className="w-2 h-2 bg-red-600 rounded-full animate-pulse"></span>
                 <span className="uppercase tracking-widest">Recording...</span>
               </div>
               <span className="font-mono">00:{recordingDuration.toString().padStart(2, '0')}</span>
            </div>
          ) : (
            <input
              type="text"
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="Discuss concepts or share resources..."
              className="w-full bg-gray-50 border-transparent rounded-[1.5rem] px-6 py-4 text-sm focus:bg-white focus:ring-0 outline-none transition-all placeholder:text-gray-400 font-medium"
            />
          )}
        </div>
        <button 
          type="button" 
          onClick={toggleRecording}
          className={`p-3 rounded-2xl transition-all ${isRecording ? 'bg-red-500 text-white animate-pulse shadow-lg shadow-red-100' : 'text-gray-400 hover:text-indigo-600 hover:bg-gray-100'}`}
          title={isRecording ? "Stop Recording" : "Voice Note"}
        >
          {isRecording ? (
             <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1 1v4a1 1 0 001 1h4a1 1 0 001-1V8a1 1 0 00-1-1H8z" clipRule="evenodd" /></svg>
          ) : (
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
          )}
        </button>
        {!isRecording && (
          <button 
            type="submit" 
            disabled={!inputText.trim()}
            className="bg-indigo-600 text-white p-4 rounded-2xl hover:bg-indigo-700 disabled:opacity-50 disabled:grayscale shadow-lg shadow-indigo-100 transition-all active:scale-95"
          >
            <svg className="w-5 h-5 transform rotate-45" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
          </button>
        )}
      </form>
    </div>
  );
};

