          <div className="text-center mb-10">
            <div className="flex justify-center mb-6">
              <Logo className="w-16 h-16 shadow-2xl shadow-green-100 rounded-full" />
            </div>
            <h1 className="text-4xl font-black text-gray-900 tracking-tight">KIVIA</h1>
            <p className="text-gray-500 text-sm mt-2 font-medium italic">Elevate your peer study experience.</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            {!isLogin && (
              <div className="flex flex-col items-center gap-4 mb-6">
                <div className="relative group">
                  <img src={avatar} alt="Avatar" className="w-28 h-28 rounded-full border-4 border-indigo-50 bg-gray-50 shadow-inner group-hover:scale-105 transition-transform duration-300 object-cover" />
                  <div className="absolute -bottom-2 right-0 flex gap-1">
                    <button 
                      type="button" 
                      onClick={randomizeAvatar}
                      className="bg-indigo-600 text-white p-2.5 rounded-full shadow-lg hover:bg-indigo-700 transition-colors border-2 border-white"
                      title="Randomize Avatar"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                    </button>
                    <button 
                      type="button" 
                      onClick={() => fileInputRef.current?.click()}
                      className="bg-green-600 text-white p-2.5 rounded-full shadow-lg hover:bg-green-700 transition-colors border-2 border-white"
                      title="Upload Custom Pic"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg>
                    </button>
                  </div>
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="image/*" 
                    onChange={handleCustomAvatar} 
                  />
                </div>
                <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Select Peer Identity</span>
              </div>
            )}

            <div className="space-y-4">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Username</label>
                <input 
                  type="text" 
                  required
                  value={username}
