                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Class / Year</label>
                      <input 
                        type="text" 
                        value={classLevel}
                        onChange={e => setClassLevel(e.target.value)}
                        className="w-full px-6 py-4 rounded-2xl bg-gray-50 border border-transparent focus:bg-white focus:border-indigo-100 focus:ring-4 focus:ring-indigo-500/5 outline-none text-sm font-medium transition-all"
                        placeholder="e.g. 2nd Year"
                      />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Division</label>
                      <input 
                        type="text" 
                        value={division}
