import React, { useState, useRef, useEffect } from 'react';
import { Message, User, Group } from '../types';
import PreviewCard from './PreviewCard';
import Logo from './Logo';

interface ChatViewProps {
  currentUser: User;
  messages: Message[];
  onSendMessage: (text: string, type?: Message['type'], metadata?: any) => void;
  allUsers: User[];
  activeGroup: Group | null;
}

const ChatView: React.FC<ChatViewProps> = ({ currentUser, messages, onSendMessage, allUsers, activeGroup }) => {
  const [inputText, setInputText] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [recordingDuration, setRecordingDuration] = useState(0);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [showScrollDown, setShowScrollDown] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  };

  const handleScroll = () => {
    if (scrollRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
      const isAtBottom = scrollHeight - scrollTop - clientHeight < 100;
      setShowScrollDown(!isAtBottom);
    }
  };

  const detectMessageType = (text: string) => {
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const match = text.match(urlRegex);
    if (!match) return null;

    const url = match[0];
    if (url.match(/\.(jpeg|jpg|gif|png|webp)$/i)) return { type: 'image' as const, url };
    if (url.includes('youtube.com') || url.includes('youtu.be')) return { type: 'video' as const, url };
    return { type: 'website' as const, url };
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const preview = detectMessageType(inputText);
    if (preview) {
      onSendMessage(inputText, 'text', { preview });
    } else {
      onSendMessage(inputText);
    }
    setInputText('');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const isImage = file.type.startsWith('image/');
      const url = URL.createObjectURL(file);
      if (isImage) {
        onSendMessage(`Shared an image`, 'file', { fileName: file.name, fileUrl: url, preview: { type: 'image', url } });
      } else {
        onSendMessage(`Shared a file: ${file.name}`, 'file', { fileName: file.name, fileUrl: url });
      }
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const audioUrl = URL.createObjectURL(audioBlob);
        onSendMessage('Voice note sent', 'voice', { 
          fileUrl: audioUrl, 
          duration: recordingDuration,
          fileName: 'Voice Note.webm'
        });
        stream.getTracks().forEach(track => track.stop());
        setRecordingDuration(0);
      };

      mediaRecorder.start();
      setIsRecording(true);

      let seconds = 0;
      timerRef.current = window.setInterval(() => {
        seconds++;
        setRecordingDuration(seconds);
      }, 1000);

    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Microphone access is required to record voice notes.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }
  };

  const toggleRecording = () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
  };

  const toggleAudio = (id: string) => {
    const audio = document.getElementById(`audio-${id}`) as HTMLAudioElement;
    if (audio) {
      if (audio.paused) {
        if (playingId && playingId !== id) {
          const other = document.getElementById(`audio-${playingId}`) as HTMLAudioElement;
          other?.pause();
        }
        audio.play();
        setPlayingId(id);
      } else {
        audio.pause();
        setPlayingId(null);
      }
    }
  };

  const MessageStatus: React.FC<{ status?: 'sent' | 'delivered' | 'read', isMe: boolean }> = ({ status = 'read', isMe }) => {
    if (!isMe) return null;
    return (
      <span className="inline-flex ml-1.5 align-middle">
        {status === 'sent' && (
          <svg className="w-3 h-3 text-indigo-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
        )}
        {(status === 'delivered' || status === 'read') && (
          <div className="flex -space-x-1.5">
            <svg className={`w-3 h-3 ${status === 'read' ? 'text-green-400' : 'text-indigo-300'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
            <svg className={`w-3 h-3 ${status === 'read' ? 'text-green-400' : 'text-indigo-300'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
          </div>
        )}
      </span>
    );
  };

  return (
    <div className="flex flex-col h-full bg-white relative">
      <div 
        ref={scrollRef} 
        onScroll={handleScroll}
        className="flex-1 overflow-y-auto px-4 md:px-8 py-6 space-y-6 scroll-smooth"
      >
        {messages.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-4">
            <Logo className="w-16 h-16 opacity-10" />
            <div className="space-y-1">
              <h3 className="text-lg font-bold text-gray-400 uppercase tracking-widest">Connect and Conquer</h3>
              <p className="text-xs text-gray-300 font-medium max-w-[200px] mx-auto leading-relaxed">
                Invite peers using code <span className="font-bold text-indigo-400">{activeGroup?.joinCode}</span>
              </p>
            </div>
          </div>
        ) : (
          messages.map((msg) => {
            const isMe = msg.senderId === currentUser.id;
            const sender = allUsers.find(u => u.id === msg.senderId);
            const isAI = msg.type === 'ai';

            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-1 duration-300`}>
                <div className={`flex max-w-[90%] md:max-w-[80%] gap-2 ${isMe ? 'flex-row-reverse' : 'flex-row'}`}>
                  {!isMe && !isAI && (
                    <img src={sender?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${msg.senderName}`} className="w-8 h-8 rounded-full border border-gray-100 mt-1 flex-shrink-0" alt={msg.senderName} />
                  )}
                  {isAI && (
                    <div className="w-8 h-8 rounded-full bg-indigo-50 border border-indigo-100 flex items-center justify-center mt-1 flex-shrink-0">
                      <Logo className="w-5 h-5" />
                    </div>
                  )}
                  <div className="min-w-0">
                    {!isMe && <div className="text-[9px] font-black text-gray-400 mb-0.5 ml-1 uppercase tracking-widest">{msg.senderName}</div>}
                    <div className={`
                      p-3.5 rounded-2xl text-sm relative break-words leading-relaxed border
                      ${isMe ? 'bg-indigo-600 text-white border-indigo-700 rounded-tr-none' : 'bg-gray-50 text-gray-800 border-gray-200 rounded-tl-none'}
                      ${isAI ? 'border-indigo-200 bg-indigo-50/30' : ''}
                    `}>
                      {isAI && (
                        <div className="flex items-center gap-1.5 text-[9px] font-black text-indigo-600 mb-2 uppercase tracking-widest border-b border-indigo-100 pb-1.5">
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                          SARA ANALYTICS
                        </div>
                      )}

                      {msg.type === 'file' && !msg.metadata?.preview ? (
                        <PreviewCard type="file" url={msg.metadata?.fileUrl || '#'} title={msg.metadata?.fileName} />
                      ) : msg.type === 'voice' ? (
                        <div className="flex items-center gap-3 py-0.5 px-1 min-w-[200px]">
                          <audio className="hidden" id={`audio-${msg.id}`} src={msg.metadata?.fileUrl} onEnded={() => setPlayingId(null)} />
                          <button 
                            onClick={() => toggleAudio(msg.id)}
                            className={`${isMe ? 'text-white' : 'text-indigo-600'} hover:scale-105 transition-transform`}
                          >
                            {playingId === msg.id ? (
                               <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1 1v4a1 1 0 001 1h4a1 1 0 001-1V8a1 1 0 00-1-1H8z" clipRule="evenodd" /></svg>
                            ) : (
                               <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                            )}
                          </button>
                          <div className="flex-1 space-y-1">
                            <div className={`h-1 rounded-full w-full relative overflow-hidden ${isMe ? 'bg-white/20' : 'bg-gray-200'}`}>
                                <div className={`absolute inset-y-0 left-0 transition-all duration-300 ${isMe ? 'bg-white' : 'bg-indigo-600'} ${playingId === msg.id ? 'w-full animate-pulse' : 'w-0'}`}></div>
                            </div>
                            <div className={`flex justify-between items-center text-[8px] font-bold uppercase ${isMe ? 'text-indigo-100' : 'text-gray-400'}`}>
                                <span>{msg.metadata?.duration ? `0:${msg.metadata.duration.toString().padStart(2, '0')}` : 'Voice'}</span>
                                <span>VOICE NOTE</span>
                            </div>
                          </div>
                        </div>
                      ) : (
                        <div>
                          <p className="whitespace-pre-wrap">{msg.text}</p>
                          {msg.metadata?.preview && (
                            <div className="mt-2 border border-black/5 rounded-xl overflow-hidden">
                              <PreviewCard 
                                type={msg.metadata.preview.type} 
                                url={msg.metadata.preview.url} 
                                title={msg.metadata.preview.title}
                              />
                            </div>
                          )}
                        </div>
                      )}

                      <div className={`text-[8px] mt-1.5 font-bold uppercase tracking-widest opacity-60 text-right flex items-center justify-end ${isMe ? 'text-indigo-100' : 'text-gray-400'}`}>
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        <MessageStatus status={msg.status} isMe={isMe} />
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      {showScrollDown && (
        <button 
          onClick={scrollToBottom}
          className="absolute bottom-24 right-4 md:right-8 p-2.5 bg-white text-indigo-600 rounded-full shadow-lg border border-gray-200 hover:bg-gray-50 transition-all z-10"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 14l-7 7-7-7" /></svg>
        </button>
      )}

      <form onSubmit={handleSubmit} className="p-4 md:p-6 bg-white border-t border-gray-100 flex items-center gap-3">
        <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
        <button 
          type="button" 
          onClick={() => fileInputRef.current?.click()}
          className="p-2 text-gray-400 hover:text-indigo-600 transition-all"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
        </button>
        <div className="flex-1 relative">
          {isRecording ? (
            <div className="w-full bg-red-50 text-red-600 rounded-xl px-4 py-3 text-sm font-bold flex items-center justify-between border border-red-100">
               <div className="flex items-center gap-2">
                 <span className="w-1.5 h-1.5 bg-red-600 rounded-full animate-pulse"></span>
                 <span className="uppercase tracking-widest text-[10px]">Recording</span>
               </div>
               <span className="font-mono text-xs">00:{recordingDuration.toString().padStart(2, '0')}</span>
            </div>
          ) : (
            <input
              type="text"
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="Share a concept..."
              className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3 text-sm focus:bg-white focus:border-indigo-300 outline-none transition-all font-medium"
            />
          )}
        </div>
        {!isRecording && (
          <button 
            type="submit" 
            disabled={!inputText.trim()}
            className="bg-indigo-600 text-white p-3 rounded-xl hover:bg-indigo-700 disabled:opacity-30 transition-all shadow-md active:scale-95"
          >
            <svg className="w-5 h-5 transform rotate-45" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
          </button>
        )}
        <button 
          type="button" 
          onClick={toggleRecording}
          className={`p-3 rounded-xl transition-all ${isRecording ? 'bg-red-500 text-white' : 'text-gray-400 hover:text-indigo-600'}`}
        >
          {isRecording ? (
             <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1 1v4a1 1 0 001 1h4a1 1 0 001-1V8a1 1 0 00-1-1H8z" clipRule="evenodd" /></svg>
          ) : (
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
          )}
        </button>
      </form>
    </div>
  );
};

export default ChatView;

import React, { useState, useRef, useEffect } from 'react';
import { Post, User, Group } from '../types';
import Logo from './Logo';

interface HomeViewProps {
  currentUser: User;
  posts: Post[];
  groups: Group[];
  onAddPost: (content: string, type: 'text' | 'image' | 'video', mediaUrl?: string) => void;
  onLikePost: (postId: string) => void;
  onSharePostToGroup: (post: Post, groupId: string) => void;
}

const HomeView: React.FC<HomeViewProps> = ({ currentUser, posts, groups, onAddPost, onLikePost, onSharePostToGroup }) => {
  const [newPostContent, setNewPostContent] = useState('');
  const [mediaPreview, setMediaPreview] = useState<string | null>(null);
  const [postType, setPostType] = useState<'text' | 'image' | 'video'>('text');
  const [showPublisher, setShowPublisher] = useState(false);
  const [sharingPost, setSharingPost] = useState<Post | null>(null);
  const [showScrollTop, setShowScrollTop] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleScroll = () => {
    if (scrollRef.current) {
      setShowScrollTop(scrollRef.current.scrollTop > 300);
    }
  };

  const scrollToTop = () => {
    scrollRef.current?.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'image' | 'video') => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setMediaPreview(url);
      setPostType(type);
    }
  };

  const handlePublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPostContent.trim() && !mediaPreview) return;
    onAddPost(newPostContent, postType, mediaPreview || undefined);
    setNewPostContent('');
    setMediaPreview(null);
    setPostType('text');
    setShowPublisher(false);
  };

  const clearMedia = () => {
    setMediaPreview(null);
    setPostType('text');
  };

  const handleExternalShare = async (post: Post) => {
    const shareUrl = window.location.origin + window.location.pathname;
    const shareData = {
      title: `Breakthrough from @${post.authorName} | KIVIA`,
      text: post.content,
      url: shareUrl,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
        return;
      } catch (err) {
        if ((err as Error).name !== 'AbortError') console.error(err);
      }
    }

    try {
      await navigator.clipboard.writeText(`${post.content}\n\nShared via KIVIA: ${shareUrl}`);
      alert('Breakthrough copied to clipboard!');
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div 
      ref={scrollRef}
      onScroll={handleScroll}
      className="h-full overflow-y-auto bg-gray-50/20 px-4 md:px-8 py-8 flex flex-col items-center relative scroll-smooth"
    >
      <div className="w-full max-w-2xl space-y-8">
        <div className="space-y-1">
          <h2 className="text-2xl font-black text-gray-900 tracking-tight">Study Community</h2>
          <p className="text-sm text-gray-500 font-medium">What's your breakthrough today, <span className="text-indigo-600 font-bold">@{currentUser.name}</span>?</p>
        </div>

        <div className="bg-white rounded-2xl p-5 border border-gray-200 shadow-sm transition-all">
          {!showPublisher ? (
            <div className="flex items-center gap-3 cursor-pointer" onClick={() => setShowPublisher(true)}>
              <img src={currentUser.avatar} className="w-9 h-9 rounded-full bg-gray-100 border border-gray-200" />
              <div className="flex-1 bg-gray-50 hover:bg-gray-100 rounded-xl px-4 py-2.5 text-gray-400 text-sm font-medium transition-colors border border-gray-200">
                Share a tip or discovery...
              </div>
            </div>
          ) : (
            <form onSubmit={handlePublish} className="space-y-4 animate-in fade-in duration-300">
              <textarea 
                autoFocus
                value={newPostContent}
                onChange={e => setNewPostContent(e.target.value)}
                placeholder="Break down a concept..."
                className="w-full bg-transparent border-none focus:ring-0 text-gray-800 placeholder:text-gray-300 font-medium resize-none text-base min-h-[100px] outline-none"
              />

              {mediaPreview && (
                <div className="relative rounded-xl overflow-hidden border border-gray-200">
                  {postType === 'image' ? (
                    <img src={mediaPreview} className="w-full h-auto max-h-[300px] object-cover" />
                  ) : (
                    <video src={mediaPreview} className="w-full h-auto max-h-[300px] object-cover" controls />
                  )}
                  <button 
                    type="button" 
                    onClick={clearMedia}
                    className="absolute top-3 right-3 bg-black/50 text-white p-1.5 rounded-full hover:bg-red-500 transition-colors"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
              )}

              <div className="pt-3 border-t border-gray-100 flex items-center justify-between">
                <div className="flex items-center gap-1">
                   <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={(e) => handleFileChange(e, 'image')} />
                   <button type="button" onClick={() => fileInputRef.current?.click()} className="p-2.5 text-gray-400 hover:text-indigo-600 hover:bg-gray-50 rounded-lg transition-all">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                   </button>

                   <input type="file" accept="video/*" className="hidden" id="video-upload-home" onChange={(e) => handleFileChange(e, 'video')} />
                   <label htmlFor="video-upload-home" className="p-2.5 text-gray-400 hover:text-indigo-600 hover:bg-gray-50 rounded-lg transition-all cursor-pointer">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                   </label>
                </div>

                <div className="flex gap-2 items-center">
                  <button type="button" onClick={() => setShowPublisher(false)} className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-3 hover:text-gray-600">Cancel</button>
                  <button 
                    type="submit" 
                    disabled={!newPostContent.trim() && !mediaPreview}
                    className="bg-indigo-600 text-white px-5 py-2 rounded-xl font-bold text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all disabled:opacity-40"
                  >
                    Publish
                  </button>
                </div>
              </div>
            </form>
          )}
        </div>

        <div className="space-y-6 pb-20">
          {posts.length === 0 ? (
            <div className="text-center py-20 opacity-20 flex flex-col items-center">
              <Logo className="w-12 h-12 mb-3 grayscale" />
              <p className="font-bold text-sm">Nothing shared yet.</p>
            </div>
          ) : (
            posts.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()).map(post => (
              <div key={post.id} className="bg-white rounded-2xl p-6 border border-gray-200 shadow-sm space-y-5 animate-in slide-in-from-bottom-2 duration-300">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <img src={post.authorAvatar} className="w-10 h-10 rounded-full border border-gray-100 bg-gray-50" />
                    <div>
                      <h4 className="font-bold text-gray-900 leading-none mb-0.5">@{post.authorName}</h4>
                      <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">
                        {new Date(post.timestamp).toLocaleDateString()}
                      </p>
                    </div>
                  </div>
                  <Logo className="w-5 h-5 opacity-5" />
                </div>

                {post.content && <p className="text-gray-800 text-sm leading-relaxed">{post.content}</p>}

                {post.type === 'image' && post.mediaUrl && (
                  <div className="rounded-xl overflow-hidden border border-gray-100 bg-gray-50">
                    <img src={post.mediaUrl} className="w-full h-auto max-h-[400px] object-cover" />
                  </div>
                )}

                {post.type === 'video' && post.mediaUrl && (
                  <div className="rounded-xl overflow-hidden border border-gray-100 bg-black aspect-video flex items-center justify-center">
                    <video src={post.mediaUrl} className="w-full h-full" controls />
                  </div>
                )}

                <div className="flex items-center gap-5 pt-3 border-t border-gray-100">
                  <button 
                    onClick={() => onLikePost(post.id)}
                    className={`flex items-center gap-1.5 transition-colors ${post.likes.includes(currentUser.id) ? 'text-red-500' : 'text-gray-400 hover:text-red-500'}`}
                  >
                    <svg className={`w-5 h-5 ${post.likes.includes(currentUser.id) ? 'fill-current' : 'fill-none'}`} stroke="currentColor" strokeWidth={2.5} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
                    <span className="text-[10px] font-black uppercase">{post.likes.length}</span>
                  </button>
                  <button 
                    onClick={() => setSharingPost(post)}
                    className="flex items-center gap-1.5 text-gray-400 hover:text-indigo-600 transition-colors"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
                    <span className="text-[10px] font-black uppercase">Share</span>
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {showScrollTop && (
        <button 
          onClick={scrollToTop}
          className="fixed bottom-6 right-6 p-3 bg-indigo-600 text-white rounded-xl shadow-xl hover:bg-indigo-700 transition-all z-50"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 10l7-7 7 7M12 3v18" /></svg>
        </button>
      )}

      {sharingPost && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col border border-gray-200">
            <div className="flex justify-between items-center mb-5 pb-3 border-b border-gray-100">
              <h2 className="text-sm font-black uppercase tracking-widest text-gray-900">Forward Breakthrough</h2>
              <button onClick={() => setSharingPost(null)} className="p-1 text-gray-400 hover:text-gray-900">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-4 overflow-y-auto max-h-[300px] no-scrollbar">
              <h3 className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] mb-2">My Groups</h3>
              <div className="space-y-1.5">
                {groups.map(group => (
                  <button 
                    key={group.id} 
                    onClick={() => { onSharePostToGroup(sharingPost, group.id); setSharingPost(null); }}
                    className="w-full flex items-center justify-between p-3 bg-gray-50 hover:bg-indigo-50 rounded-xl border border-gray-200 hover:border-indigo-200 transition-all text-left group/btn"
                  >
                    <span className="text-xs font-bold text-gray-700 group-hover/btn:text-indigo-600">{group.name}</span>
                    <svg className="w-4 h-4 text-indigo-400 opacity-0 group-hover/btn:opacity-100 transition-opacity" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
                  </button>
                ))}
              </div>
            </div>

            <button 
              onClick={() => { handleExternalShare(sharingPost); setSharingPost(null); }}
              className="mt-6 w-full bg-gray-900 text-white py-3.5 rounded-xl font-bold text-[10px] uppercase tracking-widest hover:bg-black transition-all flex items-center justify-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
              Copy External Link
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

