import React, { useState, useRef } from 'react';
import { SmartNote } from '../types';
import Logo from './Logo';

interface NotebookViewProps {
  notes: SmartNote[];
  onBack: () => void;
}

const NotebookView: React.FC<NotebookViewProps> = ({ notes, onBack }) => {
  const [filter, setFilter] = useState('');
  const [showScrollTop, setShowScrollTop] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const filteredNotes = notes.filter(n => 
    n.title.toLowerCase().includes(filter.toLowerCase()) || 
    n.content.toLowerCase().includes(filter.toLowerCase()) ||
    n.tags.some(t => t.toLowerCase().includes(filter.toLowerCase()))
  );

  const handleScroll = () => {
    if (scrollRef.current) {
      setShowScrollTop(scrollRef.current.scrollTop > 300);
    }
  };

  const scrollToTop = () => {
    scrollRef.current?.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="h-full flex flex-col bg-gray-50/10 relative">
      <div className="p-6 md:p-8 border-b border-gray-200 bg-white/80 backdrop-blur-md flex flex-col md:flex-row md:items-center justify-between gap-4 z-10">
        <div className="flex items-center gap-3">
          <button onClick={onBack} className="p-2.5 bg-white hover:bg-gray-100 rounded-xl border border-gray-200 transition-all text-gray-400 hover:text-indigo-600 shadow-sm">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
          </button>
          <div>
            <h2 className="text-xl font-black text-gray-900 tracking-tight leading-tight">Smart Notebook</h2>
            <p className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest">SARA's Knowledge Synthesis</p>
          </div>
        </div>
        <div className="relative w-full md:w-72">
          <svg className="w-4 h-4 absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          <input 
            type="text" 
            placeholder="Filter topics..." 
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-10 pr-4 py-2.5 text-sm focus:bg-white focus:border-indigo-300 outline-none transition-all font-medium"
          />
        </div>
      </div>

      <div 
        ref={scrollRef} 
        onScroll={handleScroll}
        className="flex-1 overflow-y-auto px-4 md:px-8 py-8 scroll-smooth no-scrollbar"
      >
        {filteredNotes.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-24 text-center bg-white border border-dashed border-gray-300 rounded-2xl">
            <Logo className="w-10 h-10 mb-4 opacity-10" />
            <h3 className="text-base font-bold text-gray-400 tracking-tight uppercase">Notebook Empty</h3>
            <p className="text-xs text-gray-300 mt-2 font-medium max-w-xs mx-auto italic">Ask SARA to "Create Notes" in the sidebar.</p>
          </div>
