          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-20">
            {filteredNotes.map(note => (
              <div key={note.id} className="p-6 bg-white border border-gray-200 rounded-2xl shadow-sm hover:shadow-md hover:border-indigo-200 transition-all flex flex-col group">
                <div className="flex items-center justify-between mb-4">
                  <span className="text-[8px] font-black text-indigo-600 bg-indigo-50 border border-indigo-100 px-2.5 py-1 rounded-lg uppercase tracking-widest">
                    {note.source.type}
                  </span>
                  <span className="text-[8px] font-bold text-gray-400 uppercase">{new Date(note.createdAt).toLocaleDateString()}</span>
                </div>
                <h3 className="text-base font-black text-gray-900 mb-3 group-hover:text-indigo-600 transition-colors leading-snug tracking-tight">{note.title}</h3>
                <div className="text-xs text-gray-600 leading-relaxed font-medium line-clamp-5 mb-6 flex-1">
                  {note.content}
