                <div className="flex flex-wrap gap-1.5 mt-auto border-t border-gray-50 pt-4">
                  {note.tags.map(tag => (
                    <span key={tag} className="text-[8px] font-black text-gray-400 border border-gray-100 bg-gray-50/50 px-2 py-1 rounded-md uppercase tracking-tighter">
                      #{tag}
                    </span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {showScrollTop && (
        <button 
          onClick={scrollToTop}
          className="fixed bottom-6 right-6 p-3 bg-indigo-600 text-white rounded-xl shadow-lg hover:bg-indigo-700 transition-all z-50"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 10l7-7 7 7M12 3v18" /></svg>
        </button>
      )}
    </div>
  );
};

